    @staticmethod
    def _emit_material_sync_progress(progress_callback: Any | None, **payload: Any) -> None:
        if not callable(progress_callback):
            return
        try:
            progress_callback(dict(payload))
        except Exception:  # noqa: BLE001
            return

    def _emit_material_sync_observation(self, event: str, **payload: Any) -> None:
        observe_enabled = self._material_sync_observe_enabled()
        observe_path = self._material_sync_observe_path()
        if not observe_enabled and not observe_path:
            return
        record = {"event": str(event or "").strip(), "time": now_text(), **payload}
        text = json.dumps(record, ensure_ascii=False)
        if observe_enabled:
            print(text, file=sys.stderr, flush=True)
        if not observe_path:
            return
        try:
            with open(observe_path, "a", encoding="utf-8") as handle:
                handle.write(text)
                handle.write("\n")
        except Exception as exc:  # noqa: BLE001
            if observe_enabled:
                print(
                    json.dumps(
                        {
                            "event": "material_sync_observation_write_error",
                            "time": now_text(),
                            "path": observe_path,
                            "error": str(exc),
                        },
                        ensure_ascii=False,
                    ),
                    file=sys.stderr,
                    flush=True,
                )

    @staticmethod
    def _runtime_lock_key(lock_name: str) -> str:
        return f"dashboard:runtime-lock:{str(lock_name or '').strip()}"

    def runtime_lock_active(self, lock_name: str) -> bool:
        client = self._redis()
        if client is None:
            return False
        try:
            return bool(client.exists(self._runtime_lock_key(lock_name)))
        except Exception:  # noqa: BLE001
            return False

    def _touch_runtime_lock(self, lock_name: str, *, timeout_seconds: int) -> None:
        client = self._redis()
        if client is None:
            return
        try:
            client.expire(self._runtime_lock_key(lock_name), max(int(timeout_seconds or 0), 1))
        except Exception:  # noqa: BLE001
            return

    def _clear_runtime_lock(self, lock_name: str) -> None:
        client = self._redis()
        if client is None:
            return
        try:
            client.delete(self._runtime_lock_key(lock_name))
        except Exception:  # noqa: BLE001
            return

    @staticmethod
    def _startup_dispatch_marker_key(marker_name: str) -> str:
        return f"dashboard:startup-dispatch:{str(marker_name or '').strip()}"

    @staticmethod
    def _dispatch_marker_key(marker_name: str) -> str:
        return f"dashboard:dispatch-marker:{str(marker_name or '').strip()}"

    def _acquire_dispatch_marker(self, marker_name: str, *, ttl_seconds: int = 600) -> bool:
        client = self._redis()
        if client is None:
            return True
        key = self._dispatch_marker_key(marker_name)
        try:
            return bool(
                client.set(
                    key,
                    now_text(),
                    ex=max(int(ttl_seconds or 0), 60),
                    nx=True,
                )
            )
        except Exception:  # noqa: BLE001
            return True

    def _acquire_startup_dispatch_marker(self, marker_name: str, *, ttl_seconds: int = 600) -> bool:
        return self._acquire_dispatch_marker(
            self._startup_dispatch_marker_key(marker_name),
            ttl_seconds=ttl_seconds,
        )

    @staticmethod
    def _runtime_lock_heartbeat_interval_seconds(timeout_seconds: int) -> float:
        raw_value = str(os.environ.get("RUNTIME_LOCK_HEARTBEAT_INTERVAL_SECONDS") or "").strip()
        max_interval = max(min(float(timeout_seconds or 0) / 3.0, 60.0), 5.0)
        if not raw_value:
            return max_interval
        try:
            return max(min(float(raw_value), max(float(timeout_seconds or 0) - 1.0, 1.0)), 1.0)
        except Exception:  # noqa: BLE001
            return max_interval

    @staticmethod
    def _api_error_payload(exc: Exception, **payload: Any) -> dict[str, Any]:
        normalized = dict(payload)
        if isinstance(exc, ApiError):
            normalized["message"] = str(exc)
            normalized["code"] = int(exc.code or 0)
            normalized["request_id"] = str(exc.request_id or "").strip()
            normalized["retryable"] = bool(exc.retryable)
            if int(exc.status_code or 0) > 0:
                normalized["status_code"] = int(exc.status_code or 0)
            if str(exc.help_message or "").strip():
                normalized["help_message"] = str(exc.help_message or "").strip()
        else:
            normalized["message"] = str(exc)
        normalized["error"] = str(exc)
        return normalized

    @staticmethod
    def _full_refresh_lock_ttl_seconds() -> int:
        return max(int(settings.full_refresh_lock_ttl_seconds or 3600), 300)

    @classmethod
    def _full_refresh_stale_seconds(cls) -> int:
        configured = max(int(settings.full_refresh_stale_seconds or 0), 0)
        if configured > 0:
            return max(configured, 300)
        return max(cls._full_refresh_lock_ttl_seconds() // 2, 900)

    @staticmethod
    def _default_full_refresh_status() -> dict[str, Any]:
        return {
            "task_id": "",
            "trigger": "",
            "status": "idle",
            "stage": "",
            "stage_label": "",
            "message": "",
            "queued_at": "",
            "started_at": "",
            "updated_at": "",
            "finished_at": "",
            "progress": {
                "completed_steps": 0,
                "total_steps": len(FULL_REFRESH_STAGE_SEQUENCE),
                "stage_completed_steps": 0,
                "stage_total_steps": 0,
            },
            "stages": {},
            "result": {},
        }

    def _normalize_full_refresh_status(self, payload: dict[str, Any] | None) -> dict[str, Any]:
        baseline = self._default_full_refresh_status()
        if not isinstance(payload, dict):
            return baseline
        normalized = dict(baseline)
        normalized.update(
            {
                "task_id": str(payload.get("task_id") or "").strip(),
                "trigger": str(payload.get("trigger") or "").strip().lower(),
                "status": str(payload.get("status") or "idle").strip().lower() or "idle",
                "stage": str(payload.get("stage") or "").strip(),
                "stage_label": str(payload.get("stage_label") or "").strip(),
                "message": str(payload.get("message") or "").strip(),
                "queued_at": str(payload.get("queued_at") or "").strip(),
                "started_at": str(payload.get("started_at") or "").strip(),
                "updated_at": str(payload.get("updated_at") or "").strip(),
                "finished_at": str(payload.get("finished_at") or "").strip(),
                "stages": copy.deepcopy(payload.get("stages") or {}),
                "result": copy.deepcopy(payload.get("result") or {}),
            }
        )
        if normalized["stage"] and not normalized["stage_label"]:
            normalized["stage_label"] = FULL_REFRESH_STAGE_LABELS.get(normalized["stage"], normalized["stage"])
        progress_payload = payload.get("progress") if isinstance(payload.get("progress"), dict) else {}
        total_steps = max(
            int(progress_payload.get("total_steps", len(FULL_REFRESH_STAGE_SEQUENCE)) or len(FULL_REFRESH_STAGE_SEQUENCE)),
            1,
        )
        completed_steps = max(min(int(progress_payload.get("completed_steps", 0) or 0), total_steps), 0)
        stage_total_steps = max(int(progress_payload.get("stage_total_steps", 0) or 0), 0)
        stage_completed_steps = max(min(int(progress_payload.get("stage_completed_steps", 0) or 0), stage_total_steps), 0)
        normalized["progress"] = {
            "completed_steps": completed_steps,
            "total_steps": total_steps,
            "stage_completed_steps": stage_completed_steps,
            "stage_total_steps": stage_total_steps,
        }
        return normalized

    def full_refresh_status(self) -> dict[str, Any]:
        client = self._redis()
        payload: dict[str, Any] | None = None
        if client is None:
            payload = copy.deepcopy(self._full_refresh_status_local) if self._full_refresh_status_local else None
        else:
            cached = self._shared_json_cache_get(FULL_REFRESH_STATUS_CACHE_KEY)
            payload = cached if isinstance(cached, dict) else None
        normalized = self._normalize_full_refresh_status(payload)
        full_refresh_running = self.runtime_lock_active("full-refresh")
        stale_threshold_seconds = self._full_refresh_stale_seconds()
        normalized_updated_at = self._parse_normalized_datetime_text(normalized.get("updated_at"))
        status_heartbeat_stale = (
            normalized["status"] in {"queued", "running"}
            and normalized_updated_at is not None
            and (datetime.now(ZoneInfo(TIMEZONE)).replace(tzinfo=None) - normalized_updated_at).total_seconds()
            >= stale_threshold_seconds
        )
        if status_heartbeat_stale:
            now_value = now_text()
            if full_refresh_running:
                self._clear_runtime_lock("full-refresh")
                full_refresh_running = False
            normalized["status"] = "unknown"
            normalized["finished_at"] = normalized["finished_at"] or now_value
            normalized["updated_at"] = now_value
            heartbeat_age_minutes = max(int(stale_threshold_seconds // 60), 1)
            normalized["message"] = (
                f"历史刷新状态心跳已超过 {heartbeat_age_minutes} 分钟，已判定为失活。"
            )
            return self._set_full_refresh_status(normalized)
        if full_refresh_running and normalized["status"] not in {"queued", "running"}:
            normalized["status"] = "running"
            normalized["finished_at"] = ""
            normalized["updated_at"] = normalized["updated_at"] or now_text()
            normalized["started_at"] = normalized["started_at"] or normalized["updated_at"]
            if not normalized["message"]:
                normalized["message"] = "历史刷新执行中。"
            return self._set_full_refresh_status(normalized)
        if normalized["status"] in {"queued", "running"} and not full_refresh_running:
            previous_status = str(normalized["status"] or "").strip().lower()
            if not normalized["finished_at"]:
                normalized["finished_at"] = now_text()
            normalized["status"] = "unknown"
            if not normalized["message"]:
                normalized["message"] = (
                    "任务已不在执行中，但未写入完成状态。"
                    if previous_status == "queued"
                    else "任务锁已释放，但未写入完成状态。"
                )
            return self._set_full_refresh_status(normalized)
        return normalized

    def _set_full_refresh_status(self, payload: dict[str, Any]) -> dict[str, Any]:
        normalized = self._normalize_full_refresh_status(payload)
        client = self._redis()
        if client is None:
            self._full_refresh_status_local = copy.deepcopy(normalized)
            if normalized["status"] == "running":
                self._touch_runtime_lock("full-refresh", timeout_seconds=self._full_refresh_lock_ttl_seconds())
            elif normalized["status"] in {"idle", "completed", "failed", "unknown"}:
                self._clear_runtime_lock("full-refresh")
            return normalized
        self._shared_json_cache_set(FULL_REFRESH_STATUS_CACHE_KEY, normalized, FULL_REFRESH_STATUS_TTL_SECONDS)
        if normalized["status"] == "running":
            self._touch_runtime_lock("full-refresh", timeout_seconds=self._full_refresh_lock_ttl_seconds())
        elif normalized["status"] in {"idle", "completed", "failed", "unknown"}:
            self._clear_runtime_lock("full-refresh")
        return normalized

    def update_full_refresh_status(self, **fields: Any) -> dict[str, Any]:
        current = self.full_refresh_status()
        merged = dict(current)
        for key, value in fields.items():
            if key == "stages" and isinstance(value, dict):
                next_stages = dict(merged.get("stages") or {})
                for stage_key, stage_payload in value.items():
                    next_stages[str(stage_key)] = copy.deepcopy(stage_payload)
                merged["stages"] = next_stages
                continue
            if key in {"progress", "result"} and isinstance(value, dict):
                merged[key] = copy.deepcopy(value)
                continue
            merged[key] = value
        return self._set_full_refresh_status(merged)

    def mark_full_refresh_queued(self, task_id: str, *, trigger: str = "manual") -> dict[str, Any]:
        queued_at = now_text()
        return self._set_full_refresh_status(
            {
                "task_id": str(task_id or "").strip(),
                "trigger": str(trigger or "manual").strip().lower() or "manual",
                "status": "queued",
                "stage": "",
                "stage_label": "",
                "message": "近30天历史覆盖刷新任务已进入队列，等待开始执行。",
                "queued_at": queued_at,
                "started_at": "",
                "updated_at": queued_at,
                "finished_at": "",
                "progress": {
                    "completed_steps": 0,
                    "total_steps": len(FULL_REFRESH_STAGE_SEQUENCE),
                    "stage_completed_steps": 0,
                    "stage_total_steps": 0,
                },
                "stages": {},
                "result": {},
            }
        )

    @staticmethod
    def _versioned_cache_key(version: str, raw_key: str) -> str:
        return f"v{str(version or '1').strip()}:{str(raw_key or '').strip()}"

    @staticmethod
    def _shared_payload_cache_storage_key(namespace: str, raw_key: str, version: str) -> str:
        digest = hashlib.sha1(str(raw_key or "").encode("utf-8")).hexdigest()[:20]
        return f"dashboard:payload:{str(namespace or 'default').strip()}:v{str(version or '1').strip()}:{digest}"

    @staticmethod
    def _cache_entry(payload: dict[str, Any], *, cached_at: float | None = None) -> dict[str, Any]:
        return {
            "_cached_at": float(cached_at if cached_at is not None else time.time()),
            "payload": copy.deepcopy(payload),
        }

    @staticmethod
    def _cache_entry_payload(cache_entry: dict[str, Any] | None) -> dict[str, Any] | None:
        if not isinstance(cache_entry, dict):
            return None
        payload = cache_entry.get("payload")
        return copy.deepcopy(payload) if isinstance(payload, dict) else None

    @staticmethod
    def _cache_entry_age_seconds(cache_entry: dict[str, Any] | None) -> float:
        if not isinstance(cache_entry, dict):
            return float("inf")
        cached_at = float(cache_entry.get("_cached_at", 0.0) or 0.0)
        if cached_at <= 0:
            return float("inf")
        return max(time.time() - cached_at, 0.0)

    @staticmethod
    def _local_dict_cache_entry_get(
        cache_store: dict[str, dict[str, Any]],
        cache_key: str,
    ) -> dict[str, Any] | None:
        cached = cache_store.get(cache_key)
        if not isinstance(cached, dict):
            cache_store.pop(cache_key, None)
            return None
        payload = cached.get("payload")
        if not isinstance(payload, dict):
            cache_store.pop(cache_key, None)
            return None
        return {
            "_cached_at": float(cached.get("_cached_at", 0.0) or 0.0),
            "payload": copy.deepcopy(payload),
        }

    @staticmethod
    def _local_dict_cache_get(
        cache_store: dict[str, dict[str, Any]],
        cache_key: str,
        ttl_seconds: int,
    ) -> dict[str, Any] | None:
        cached = DashboardService._local_dict_cache_entry_get(cache_store, cache_key)
        if cached is None:
            return None
        if DashboardService._cache_entry_age_seconds(cached) >= max(int(ttl_seconds or 0), 1):
            cache_store.pop(cache_key, None)
            return None
        return DashboardService._cache_entry_payload(cached)

    @staticmethod
    def _trim_local_dict_cache(cache_store: dict[str, dict[str, Any]]) -> None:
        if len(cache_store) <= LOCAL_DICT_CACHE_SOFT_LIMIT:
            return
        expired_keys = [
            key
            for key, value in list(cache_store.items())
            if time.time() - float((value or {}).get("_cached_at", 0.0) or 0.0) >= max(RANGE_CACHE_SECONDS, 1)
        ]
        for key in expired_keys:
            cache_store.pop(key, None)
        if len(cache_store) <= LOCAL_DICT_CACHE_SOFT_LIMIT:
            return
        oldest_keys = sorted(
            cache_store.items(),
            key=lambda item: float((item[1] or {}).get("_cached_at", 0.0) or 0.0),
        )[: max(len(cache_store) - LOCAL_DICT_CACHE_TRIM_TO, 0)]
        for key, _value in oldest_keys:
            cache_store.pop(key, None)

    @staticmethod
    def _local_dict_cache_set_entry(
        cache_store: dict[str, dict[str, Any]],
        cache_key: str,
        payload: dict[str, Any],
        *,
        cached_at: float | None = None,
    ) -> None:
        cache_store[cache_key] = DashboardService._cache_entry(payload, cached_at=cached_at)
        DashboardService._trim_local_dict_cache(cache_store)

    @staticmethod
    def _local_dict_cache_set(
        cache_store: dict[str, dict[str, Any]],
        cache_key: str,
        payload: dict[str, Any],
    ) -> None:
        DashboardService._local_dict_cache_set_entry(cache_store, cache_key, payload)

    def _shared_dict_cache_get(self, namespace: str, raw_key: str, version: str) -> dict[str, Any] | None:
        payload = self._shared_json_cache_get(self._shared_payload_cache_storage_key(namespace, raw_key, version))
        return copy.deepcopy(payload) if isinstance(payload, dict) else None

    def _shared_dict_cache_set(self, namespace: str, raw_key: str, version: str, payload: dict[str, Any], ttl_seconds: int) -> None:
        self._shared_json_cache_set(
            self._shared_payload_cache_storage_key(namespace, raw_key, version),
            payload,
            ttl_seconds,
        )

    def _shared_payload_cache_entry_get(
        self,
        namespace: str,
        raw_key: str,
        version: str,
    ) -> dict[str, Any] | None:
        cached = self._shared_json_cache_get(self._shared_payload_cache_storage_key(namespace, raw_key, version))
        if not isinstance(cached, dict):
            return None
        payload = cached.get("payload")
        if not isinstance(payload, dict):
            return None
        return {
            "_cached_at": float(cached.get("_cached_at", 0.0) or 0.0),
            "payload": copy.deepcopy(payload),
        }

    def _shared_payload_cache_entry_set(
        self,
        namespace: str,
        raw_key: str,
        version: str,
        payload: dict[str, Any],
        ttl_seconds: int,
        *,
        cached_at: float | None = None,
    ) -> None:
        self._shared_json_cache_set(
            self._shared_payload_cache_storage_key(namespace, raw_key, version),
            self._cache_entry(payload, cached_at=cached_at),
            ttl_seconds,
        )

    @staticmethod
    def _payload_refresh_marker_key(namespace: str, cache_key: str) -> str:
        return f"{str(namespace or 'default').strip()}:{str(cache_key or '').strip()}"

    def _refresh_payload_cache(
        self,
        *,
        refresh_key: str,
        cache_store: dict[str, dict[str, Any]],
        cache_key: str,
        namespace: str,
        raw_cache_key: str,
        cache_version: str,
        stale_ttl_seconds: int,
        builder: Any,
    ) -> None:
        try:
            payload = builder()
            if isinstance(payload, dict):
                self._local_dict_cache_set_entry(cache_store, cache_key, payload)
                self._shared_payload_cache_entry_set(
                    namespace,
                    raw_cache_key,
                    cache_version,
                    payload,
                    stale_ttl_seconds,
                )
        except Exception:
            pass
        finally:
            with self._payload_refresh_lock:
                self._payload_refreshing.discard(refresh_key)

    def _schedule_payload_cache_refresh(
        self,
        *,
        namespace: str,
        cache_store: dict[str, dict[str, Any]],
        cache_key: str,
        raw_cache_key: str,
        cache_version: str,
        stale_ttl_seconds: int,
        builder: Any,
    ) -> None:
        refresh_key = self._payload_refresh_marker_key(namespace, cache_key)
        with self._payload_refresh_lock:
            if refresh_key in self._payload_refreshing:
                return
            self._payload_refreshing.add(refresh_key)
        threading.Thread(
            target=self._refresh_payload_cache,
            kwargs={
                "refresh_key": refresh_key,
                "cache_store": cache_store,
                "cache_key": cache_key,
                "namespace": namespace,
                "raw_cache_key": raw_cache_key,
                "cache_version": cache_version,
                "stale_ttl_seconds": stale_ttl_seconds,
                "builder": builder,
            },
            daemon=True,
            name=f"{namespace}-cache-refresh",
        ).start()

    def _read_payload_cache_swr(
        self,
        *,
        namespace: str,
        cache_store: dict[str, dict[str, Any]],
        cache_key: str,
        raw_cache_key: str,
        cache_version: str,
        force_refresh: bool,
        builder: Any,
        fresh_ttl_seconds: int = PAYLOAD_CACHE_FRESH_SECONDS,
        stale_ttl_seconds: int = PAYLOAD_CACHE_STALE_SECONDS,
    ) -> dict[str, Any]:
        fresh_ttl = max(int(fresh_ttl_seconds or 0), 1)
        stale_ttl = max(int(stale_ttl_seconds or 0), fresh_ttl)
        stale_payload: dict[str, Any] | None = None
        if not force_refresh:
            local_entry = self._local_dict_cache_entry_get(cache_store, cache_key)
            if local_entry is not None:
                payload = self._cache_entry_payload(local_entry)
                age = self._cache_entry_age_seconds(local_entry)
                if payload is not None:
                    stale_payload = payload
                    if age < fresh_ttl:
                        return payload
                    if age < stale_ttl:
                        self._schedule_payload_cache_refresh(
                            namespace=namespace,
                            cache_store=cache_store,
                            cache_key=cache_key,
                            raw_cache_key=raw_cache_key,
                            cache_version=cache_version,
                            stale_ttl_seconds=stale_ttl,
                            builder=builder,
                        )
                        return payload
                cache_store.pop(cache_key, None)
            shared_entry = self._shared_payload_cache_entry_get(namespace, raw_cache_key, cache_version)
            if shared_entry is not None:
                payload = self._cache_entry_payload(shared_entry)
                age = self._cache_entry_age_seconds(shared_entry)
                if payload is not None:
                    if age < stale_ttl:
                        self._local_dict_cache_set_entry(
                            cache_store,
                            cache_key,
                            payload,
                            cached_at=float(shared_entry.get("_cached_at", 0.0) or 0.0) or None,
                        )
                        stale_payload = payload
                        if age >= fresh_ttl:
                            self._schedule_payload_cache_refresh(
                                namespace=namespace,
                                cache_store=cache_store,
                                cache_key=cache_key,
                                raw_cache_key=raw_cache_key,
                                cache_version=cache_version,
                                stale_ttl_seconds=stale_ttl,
                                builder=builder,
                            )
                        return payload
        try:
            payload = builder()
        except Exception:
            if stale_payload is not None:
                return stale_payload
            raise
        self._local_dict_cache_set_entry(cache_store, cache_key, payload)
        self._shared_payload_cache_entry_set(namespace, raw_cache_key, cache_version, payload, stale_ttl)
        return copy.deepcopy(payload)

    def _invalidate_cache_namespaces(self, *namespaces: str) -> None:
        for namespace in namespaces:
            self._bump_shared_cache_version(namespace)

    @contextmanager
    def _distributed_runtime_lock(
        self,
        lock_name: str,
        *,
        timeout_seconds: int,
        blocking_timeout_seconds: int = 0,
    ) -> Any:
        client = self._redis()
        if client is None:
            yield True
            return
        lock = client.lock(
            self._runtime_lock_key(lock_name),
            timeout=max(int(timeout_seconds or 0), 1),
            blocking_timeout=max(int(blocking_timeout_seconds or 0), 0),
        )
        try:
            acquired = bool(lock.acquire(blocking=blocking_timeout_seconds > 0))
        except Exception:  # noqa: BLE001
            acquired = False
        if not acquired:
            yield False
            return
        heartbeat_stop = threading.Event()
        heartbeat_thread: threading.Thread | None = None
        heartbeat_interval = self._runtime_lock_heartbeat_interval_seconds(timeout_seconds)
        if client is not None and timeout_seconds > 0:
            self._touch_runtime_lock(lock_name, timeout_seconds=timeout_seconds)

            def heartbeat() -> None:
                while not heartbeat_stop.wait(heartbeat_interval):
                    self._touch_runtime_lock(lock_name, timeout_seconds=timeout_seconds)

            heartbeat_thread = threading.Thread(
                target=heartbeat,
                daemon=True,
                name=f"runtime-lock-heartbeat:{lock_name}",
            )
            heartbeat_thread.start()
        try:
            yield True
        finally:
            heartbeat_stop.set()
            if heartbeat_thread is not None:
                heartbeat_thread.join(timeout=1.0)
            try:
                lock.release()
            except Exception:  # noqa: BLE001
                pass

    @staticmethod
    def _history_catchup_probe_interval_minutes() -> int:
        return max(int(settings.history_catchup_probe_interval_minutes or 0), 0)

    @staticmethod
    def _startup_history_catchup_delay_seconds() -> int:
        return max(int(settings.startup_history_catchup_delay_seconds or 0), 0)

    @staticmethod
    def _history_refresh_stage_tables(stage: str) -> list[str]:
        normalized_stage = str(stage or "").strip().lower()
        if normalized_stage == "performance":
            return ["summary_daily", "account_daily", "plan_daily"]
        if normalized_stage == "extended":
            return [
                "extended_sync_runs",
                "material_daily",
                "material_relation_daily",
                "plan_detail_snapshots",
                "product_snapshots",
                "material_snapshots",
                "material_rollups",
                "material_report_snapshots",
                "video_origin_flags",
            ]
        if normalized_stage == "material_metadata":
            return ["material_profile"]
        if normalized_stage == "material_finalize":
            return [
                "extended_sync_runs",
                "material_daily",
                "material_relation_daily",
                "material_snapshots",
                "material_relation_edges",
                "material_profile",
            ]
        if normalized_stage == "material_reconcile":
            return [
                "extended_sync_runs",
                "material_daily",
                "material_relation_daily",
                "material_snapshots",
                "material_relation_edges",
                "material_profile",
            ]
        return []

    @staticmethod
    def _history_refresh_window_dates(days: int, timezone_name: str) -> tuple[datetime, datetime] | None:
        normalized_days = max(int(days or 0), 0)
        if normalized_days <= 0:
            return None
        tz = ZoneInfo(str(timezone_name or TIMEZONE).strip() or TIMEZONE)
        today = datetime.now(tz).date()
        end_day = today - timedelta(days=1)
        if end_day < today - timedelta(days=3650):
            return None
        start_day = today - timedelta(days=normalized_days)
        start_dt = datetime(start_day.year, start_day.month, start_day.day, 0, 0, 0, tzinfo=tz)
        end_dt = datetime(end_day.year, end_day.month, end_day.day, 23, 59, 59, tzinfo=tz)
        return start_dt, end_dt

    def _range_span_days(self, start_dt: datetime, end_dt: datetime) -> int:
        return max((end_dt.date() - start_dt.date()).days + 1, 1)

    @staticmethod
    def _db_optional_timestamp_value(value: Any) -> Any:
        if value is None:
            return None
        if isinstance(value, str):
            text = value.strip()
            return text or None
        return value

    def _record_history_backfill_job_locked(
        self,
        conn: Any,
        *,
        job_key: str,
        kind: str,
        task_name: str,
        range_start: str,
        range_end: str,
        days: int,
        requested_missing_days: int,
        status: str,
        task_id: str = "",
        message: str = "",
        result_json: Any = "{}",
        queued_at: Any = "",
        started_at: Any = "",
        finished_at: Any = "",
    ) -> None:
        updated_at = now_text()
        conn.execute(
            """
            INSERT INTO history_backfill_jobs (
                job_key, kind, task_name, range_start, range_end, days, requested_missing_days,
                status, task_id, message, result_json, queued_at, started_at, finished_at, updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT (job_key) DO UPDATE SET
                kind = excluded.kind,
                task_name = excluded.task_name,
                range_start = excluded.range_start,
                range_end = excluded.range_end,
                days = excluded.days,
                requested_missing_days = excluded.requested_missing_days,
                status = excluded.status,
                task_id = excluded.task_id,
                message = excluded.message,
                result_json = excluded.result_json,
                queued_at = excluded.queued_at,
                started_at = excluded.started_at,
                finished_at = excluded.finished_at,
                updated_at = excluded.updated_at
            """,
            (
                job_key,
                kind,
                task_name,
                range_start,
                range_end,
                max(int(days or 0), 0),
                max(int(requested_missing_days or 0), 0),
                status,
                task_id,
                message,
                result_json,
                self._db_optional_timestamp_value(queued_at),
                self._db_optional_timestamp_value(started_at),
                self._db_optional_timestamp_value(finished_at),
                updated_at,
            ),
        )

    def mark_history_backfill_job_started(self, job_key: str, task_id: str = "") -> None:
        normalized_job_key = str(job_key or "").strip()
        if not normalized_job_key:
            return
        with self.db() as conn:
            row = conn.execute(
                "SELECT kind, task_name, range_start, range_end, days, requested_missing_days FROM history_backfill_jobs WHERE job_key = ? LIMIT 1",
                (normalized_job_key,),
            ).fetchone()
            if not row:
                return
            started_at = now_text()
            self._record_history_backfill_job_locked(
                conn,
                job_key=normalized_job_key,
                kind=str(row["kind"] or "").strip(),
                task_name=str(row["task_name"] or "").strip(),
                range_start=str(row["range_start"] or "").strip(),
                range_end=str(row["range_end"] or "").strip(),
                days=int(row["days"] or 0),
                requested_missing_days=int(row["requested_missing_days"] or 0),
                status="running",
                task_id=str(task_id or row["task_id"] or "").strip(),
                message="",
                result_json="{}",
                queued_at="",
                started_at=started_at,
                finished_at="",
            )

    def mark_history_backfill_job_finished(
        self,
        job_key: str,
        status: str,
        *,
        message: str = "",
        result: dict[str, Any] | None = None,
    ) -> None:
        normalized_job_key = str(job_key or "").strip()
        if not normalized_job_key:
            return
        with self.db() as conn:
            row = conn.execute(
                """
                SELECT kind, task_name, range_start, range_end, days, requested_missing_days, task_id, queued_at, started_at
                FROM history_backfill_jobs
                WHERE job_key = ?
                LIMIT 1
                """,
                (normalized_job_key,),
            ).fetchone()
            if not row:
                return
            self._record_history_backfill_job_locked(
                conn,
                job_key=normalized_job_key,
                kind=str(row["kind"] or "").strip(),
                task_name=str(row["task_name"] or "").strip(),
                range_start=str(row["range_start"] or "").strip(),
                range_end=str(row["range_end"] or "").strip(),
                days=int(row["days"] or 0),
                requested_missing_days=int(row["requested_missing_days"] or 0),
                status=str(status or "success").strip() or "success",
                task_id=str(row["task_id"] or "").strip(),
                message=str(message or "").strip(),
                result_json=self._json_text(result or {}),
                queued_at=str(row["queued_at"] or "").strip(),
                started_at=str(row["started_at"] or "").strip(),
                finished_at=now_text(),
            )

    def _queue_history_backfill_if_needed(
        self,
        kind: str,
        start_dt: datetime,
        end_dt: datetime,
        missing_days: int,
    ) -> bool:
        _ = (kind, start_dt, end_dt, missing_days)
        return False

    @staticmethod
    def _normalize_allowed_advertiser_ids(
        allowed_advertiser_ids: set[int] | list[int] | tuple[int, ...] | None,
    ) -> set[int] | None:
        if allowed_advertiser_ids is None:
            return None
        return {int(item) for item in allowed_advertiser_ids if int(item or 0)}

    def _comment_sync_dedupe_key(
        self,
        start_date: str,
        end_date: str,
        advertiser_id: int = 0,
        allowed_advertiser_ids: set[int] | list[int] | tuple[int, ...] | None = None,
    ) -> str:
        normalized_allowed = self._normalize_allowed_advertiser_ids(allowed_advertiser_ids)
        scope_digest = hashlib.sha1(build_scope_cache_key(normalized_allowed).encode("utf-8")).hexdigest()[:16]
        return (
            f"comment-sync:{self._current_customer_center_id()}:{str(start_date or '').strip()}:"
            f"{str(end_date or '').strip()}:{int(advertiser_id or 0)}:{scope_digest}"
        )

    def _material_hot_sync_dedupe_key(self, customer_center_id: str = "") -> str:
        normalized_customer_center_id = str(customer_center_id or self._current_customer_center_id() or "").strip()
        return f"material-hot-sync:{normalized_customer_center_id}"

    @staticmethod
    def _material_hot_sync_queue_debounce_seconds() -> int:
        return max(60, min(int(BACKFILL_QUEUE_DEBOUNCE_SECONDS or 0), 300))

    @classmethod
    def _history_catchup_followup_queue_debounce_seconds(cls) -> int:
        interval_seconds = cls._history_catchup_probe_interval_minutes() * 60
        if interval_seconds <= 0:
            return 120
        return max(min(interval_seconds // 4, 300), 60)

    @staticmethod
    def _history_catchup_followup_delay_seconds() -> int:
        return 5

    @staticmethod
    def _history_catchup_followup_marker_name(
        trigger: str,
        performance_days: int | None = None,
        extended_days: int | None = None,
    ) -> str:
        return (
            "history-catchup-followup:"
            f"{str(trigger or '').strip().lower() or 'probe'}:"
            f"{max(int(performance_days or 0), 0)}:"
            f"{max(int(extended_days or 0), 0)}"
        )

    def _queue_history_catchup_followup_if_needed(
        self,
        *,
        remaining_total: int,
        trigger: str,
        performance_days: int | None = None,
        extended_days: int | None = None,
        ok: bool = True,
    ) -> bool:
        if max(int(remaining_total or 0), 0) <= 0:
            return False
        if not ok:
            return False
        marker_name = self._history_catchup_followup_marker_name(
            trigger,
            performance_days=performance_days,
            extended_days=extended_days,
        )
        if not self._acquire_dispatch_marker(
            marker_name,
            ttl_seconds=self._history_catchup_followup_queue_debounce_seconds(),
        ):
            self._emit_material_sync_observation(
                "history_catchup_followup_dispatch_skipped",
                trigger=str(trigger or "").strip(),
                remaining_total=max(int(remaining_total or 0), 0),
                reason="followup already queued recently",
            )
            return False
        followup_trigger = str(trigger or "probe").strip().lower() or "probe"
        if not followup_trigger.endswith("-continuation"):
            followup_trigger = f"{followup_trigger}-continuation"
        from dashboard.celery_app import celery_app

        try:
            celery_app.send_task(
                "dashboard.history_catchup_probe",
                kwargs={
                    "trigger": followup_trigger,
                    "performance_days": max(int(performance_days or 0), 0),
                    "extended_days": max(int(extended_days or 0), 0),
                },
                queue="history",
                countdown=self._history_catchup_followup_delay_seconds(),
            )
        except Exception as exc:  # noqa: BLE001
            self._emit_material_sync_observation(
                "history_catchup_followup_dispatch_error",
                trigger=str(trigger or "").strip(),
                remaining_total=max(int(remaining_total or 0), 0),
                error=str(exc),
            )
            return False
        self._emit_material_sync_observation(
            "history_catchup_followup_dispatch",
            trigger=str(trigger or "").strip(),
            followup_trigger=followup_trigger,
            remaining_total=max(int(remaining_total or 0), 0),
            performance_days=max(int(performance_days or 0), 0),
            extended_days=max(int(extended_days or 0), 0),
        )
        return True

    @staticmethod
    def _snapshot_time_epoch(snapshot_time: str, tz_name: str = TIMEZONE) -> int:
        text = str(snapshot_time or "").strip()
        if not text:
            return 0
        try:
            return int(datetime.strptime(text, "%Y-%m-%d %H:%M:%S").replace(tzinfo=ZoneInfo(tz_name)).timestamp())
        except Exception:  # noqa: BLE001
            return 0

    @classmethod
    def _material_hot_sync_stale_threshold_seconds(cls) -> int:
        return max(int(MATERIAL_SYNC_INTERVAL_MINUTES or 10) * 90, 600)

    def _latest_material_current_meta(self, conn: Any, customer_center_id: str | None = None) -> dict[str, Any] | None:
        target_customer_center_id = str(customer_center_id or self._current_customer_center_id() or "").strip()
        row = conn.execute(
            """
            SELECT snapshot_time, COUNT(*) AS material_row_count
            FROM material_current
            WHERE customer_center_id = ?
            GROUP BY snapshot_time
            ORDER BY snapshot_time DESC
            LIMIT 1
            """,
            (target_customer_center_id,),
        ).fetchone()
        return dict(row) if row else None

    def _latest_material_current_meta_all_customer_centers(self, conn: Any) -> list[dict[str, Any]]:
        rows = [
            dict(row)
            for row in conn.execute(
                """
                SELECT customer_center_id, snapshot_time, COUNT(*) AS material_row_count
                FROM material_current
                WHERE COALESCE(customer_center_id, '') <> ''
                GROUP BY customer_center_id, snapshot_time
                ORDER BY snapshot_time DESC, customer_center_id ASC
                """
            ).fetchall()
        ]
        return self._latest_rows_by_customer_center(rows)

    def _material_today_hot_status(self, *, all_customer_centers: bool = False) -> dict[str, Any]:
        running = self.runtime_lock_active("detail-sync")
        threshold_seconds = self._material_hot_sync_stale_threshold_seconds()
        summary_target_snapshot_time = ""
        material_snapshot_time = ""
        material_row_count = 0
        missing_count = 0
        stale_count = 0
        lag_seconds = 0
        customer_center_count = 0

        with self.db() as conn:
            if all_customer_centers:
                summary_rows = self._latest_rows_by_customer_center(
                    [
                        dict(row)
                        for row in conn.execute(
                            """
                            SELECT customer_center_id, snapshot_time
                            FROM summary_current
                            WHERE COALESCE(customer_center_id, '') <> ''
                            ORDER BY snapshot_time DESC, customer_center_id ASC
                            """
                        ).fetchall()
                    ]
                )
                material_rows = self._latest_material_current_meta_all_customer_centers(conn)
                summary_by_customer_center = {
                    str(row.get("customer_center_id") or "").strip(): dict(row)
                    for row in summary_rows
                    if str(row.get("customer_center_id") or "").strip()
                }
                material_by_customer_center = {
                    str(row.get("customer_center_id") or "").strip(): dict(row)
                    for row in material_rows
                    if str(row.get("customer_center_id") or "").strip()
                }
                customer_center_count = len(summary_by_customer_center)
                summary_target_snapshot_time = max(
                    (str(row.get("snapshot_time") or "") for row in summary_by_customer_center.values()),
                    default="",
                )
                material_snapshot_time = max(
                    (str(row.get("snapshot_time") or "") for row in material_by_customer_center.values()),
                    default="",
                )
                material_row_count = sum(int(row.get("material_row_count", 0) or 0) for row in material_by_customer_center.values())
                for customer_center_id, summary_row in summary_by_customer_center.items():
                    material_row = material_by_customer_center.get(customer_center_id)
                    target_snapshot = str(summary_row.get("snapshot_time") or "").strip()
                    current_snapshot = str((material_row or {}).get("snapshot_time") or "").strip()
                    if not current_snapshot:
                        missing_count += 1
                        continue
                    target_epoch = self._snapshot_time_epoch(target_snapshot)
                    current_epoch = self._snapshot_time_epoch(current_snapshot)
                    if target_epoch > 0 and current_epoch > 0:
                        lag_seconds = max(lag_seconds, max(target_epoch - current_epoch, 0))
                    if target_epoch > current_epoch + threshold_seconds:
                        stale_count += 1
            else:
                summary_meta = self._latest_summary_current_meta(conn)
                material_meta = self._latest_material_current_meta(conn)
                customer_center_count = 1 if summary_meta else 0
                summary_target_snapshot_time = str((summary_meta or {}).get("snapshot_time") or "").strip()
                material_snapshot_time = str((material_meta or {}).get("snapshot_time") or "").strip()
                material_row_count = int((material_meta or {}).get("material_row_count", 0) or 0)
                if summary_target_snapshot_time and not material_snapshot_time:
                    missing_count = 1
                elif summary_target_snapshot_time and material_snapshot_time:
                    target_epoch = self._snapshot_time_epoch(summary_target_snapshot_time)
                    current_epoch = self._snapshot_time_epoch(material_snapshot_time)
                    if target_epoch > 0 and current_epoch > 0:
                        lag_seconds = max(target_epoch - current_epoch, 0)
                    if target_epoch > current_epoch + threshold_seconds:
                        stale_count = 1

        pending = running or missing_count > 0 or stale_count > 0
        reason = ""
        if running and missing_count > 0:
            reason = "running_missing_today_material_current"
        elif running and stale_count > 0:
            reason = "running_refreshing_stale_today_material_current"
        elif running:
            reason = "running"
        elif missing_count > 0:
            reason = "missing_today_material_current"
        elif stale_count > 0:
            reason = "stale_today_material_current"

        return {
            "today_hot_pending": pending,
            "today_hot_running": running,
            "today_hot_missing": missing_count > 0,
            "today_hot_stale": stale_count > 0,
            "today_hot_reason": reason,
            "today_hot_last_snapshot_time": material_snapshot_time,
            "today_hot_target_snapshot_time": summary_target_snapshot_time,
            "today_hot_material_row_count": material_row_count,
            "today_hot_missing_customer_center_count": missing_count,
            "today_hot_stale_customer_center_count": stale_count,
            "today_hot_customer_center_count": customer_center_count,
            "today_hot_lag_seconds": int(max(lag_seconds, 0)),
            "today_hot_stale_threshold_seconds": int(threshold_seconds),
        }

    def _queue_material_hot_sync_if_needed(
        self,
        *,
        customer_center_id: str = "",
        reason: str = "",
        force_refresh: bool = False,
    ) -> bool:
        normalized_customer_center_id = str(customer_center_id or self._current_customer_center_id() or "").strip()
        if not normalized_customer_center_id:
            return False
        if self.runtime_lock_active("detail-sync"):
            return False
        with self.db() as conn:
            summary_meta = self._latest_summary_current_meta(conn, normalized_customer_center_id)
            material_meta = self._latest_material_current_meta(conn, normalized_customer_center_id)
        summary_snapshot_time = str((summary_meta or {}).get("snapshot_time") or "").strip()
        material_snapshot_time = str((material_meta or {}).get("snapshot_time") or "").strip()
        if not summary_snapshot_time:
            return False
        target_epoch = self._snapshot_time_epoch(summary_snapshot_time)
        current_epoch = self._snapshot_time_epoch(material_snapshot_time)
        stale = (
            bool(material_snapshot_time)
            and target_epoch > current_epoch + self._material_hot_sync_stale_threshold_seconds()
        )
        missing = not material_snapshot_time
        if not missing and not stale:
            return False
        dedupe_key = self._material_hot_sync_dedupe_key(normalized_customer_center_id)
        now_ts = time.time()
        last_ts = float(self._backfill_queue_marks.get(dedupe_key, 0.0) or 0.0)
        if now_ts - last_ts < self._material_hot_sync_queue_debounce_seconds():
            return False
        from dashboard.celery_app import celery_app

        try:
            celery_app.send_task(
                "dashboard.material_hot_sync",
                kwargs={"force_refresh": bool(force_refresh)},
            )
        except Exception as exc:  # noqa: BLE001
            self._emit_material_sync_observation(
                "material_hot_sync_dispatch_error",
                customer_center_id=normalized_customer_center_id,
                reason=str(reason or ""),
                error=str(exc),
            )
            return False
        self._backfill_queue_marks[dedupe_key] = now_ts
        self._emit_material_sync_observation(
            "material_hot_sync_dispatch",
            customer_center_id=normalized_customer_center_id,
            reason=str(reason or ""),
            summary_snapshot_time=summary_snapshot_time,
            material_snapshot_time=material_snapshot_time,
            stale=stale,
            missing=missing,
        )
        return True

    def _queue_comment_sync_if_needed(
        self,
        start_date: str,
        end_date: str,
        advertiser_id: int = 0,
        allowed_advertiser_ids: set[int] | list[int] | tuple[int, ...] | None = None,
        force_refresh: bool = False,
    ) -> bool:
        normalized_allowed = self._normalize_allowed_advertiser_ids(allowed_advertiser_ids)
        dedupe_key = self._comment_sync_dedupe_key(
            start_date,
            end_date,
            advertiser_id=advertiser_id,
            allowed_advertiser_ids=normalized_allowed,
        )
        now_ts = time.time()
        last_ts = float(self._backfill_queue_marks.get(dedupe_key, 0.0) or 0.0)
        if now_ts - last_ts < COMMENT_SYNC_QUEUE_DEBOUNCE_SECONDS:
            return False
        from dashboard.celery_app import celery_app

        try:
            celery_app.send_task(
                "dashboard.comment_sync_recent",
                kwargs={
                    "start_date": str(start_date or "").strip(),
                    "end_date": str(end_date or "").strip(),
                    "advertiser_id": int(advertiser_id or 0),
                    "allowed_advertiser_ids": (
                        sorted(int(item) for item in normalized_allowed)
                        if normalized_allowed is not None
                        else None
                    ),
                    "force_refresh": bool(force_refresh),
                },
            )
        except Exception:  # noqa: BLE001
            return False
        self._backfill_queue_marks[dedupe_key] = now_ts
        return True

    def init_db(self) -> None:
        with self.db() as conn:
            self._acquire_init_db_lock(conn)
            apply_migrations(
                conn,
                context={
                    "base_customer_center_id": str(
                        self._base_runtime_config().get("customer_center_id") or ""
                    ).strip(),
                    "timezone": TIMEZONE,
                },
            )
            self.alert_access.ensure_notification_settings(conn)

    def init_db_once(self) -> None:
        current_pid = os.getpid()
        if self._db_init_pid == current_pid:
            return
        with self._db_init_thread_lock:
            if self._db_init_pid == current_pid:
                return
            self.init_db()
            self._db_init_pid = current_pid

    @staticmethod
    def _acquire_init_db_lock(conn: Any) -> None:
        if getattr(conn, "backend", "") != "postgres":
            return
        conn.execute(
            "SELECT pg_advisory_xact_lock(?, ?)",
            (INIT_DB_LOCK_NAMESPACE, INIT_DB_LOCK_KEY),
        )

    def _runtime_config_override_row_locked(self, conn: Any) -> dict[str, Any] | None:
        row = conn.execute(
            """
            SELECT id, customer_center_id, refresh_token, updated_at
            FROM runtime_config_overrides
            WHERE id = 1
            LIMIT 1
            """
        ).fetchone()
        return dict(row) if row else None

    @contextmanager
    def db(self) -> Any:
        conn = connect_database(DATABASE_URL, DATABASE_PATH)
        try:
            yield conn
            conn.commit()
        except Exception:
            conn.rollback()
            raise
        finally:
            conn.close()

    def _default_notification_target(self) -> str:
        try:
            payload = load_runtime_config(CONFIG_PATH)
        except Exception:
            return ""
        return str(payload.get("feishu_target") or "").strip()

    @staticmethod
    def _merge_runtime_config_override(
        base_config: dict[str, Any],
        override_row: dict[str, Any] | None,
    ) -> dict[str, Any]:
        merged = dict(base_config)
        if not override_row:
            return merged
        customer_center_id = str(override_row.get("customer_center_id") or "").strip()
        refresh_token = str(override_row.get("refresh_token") or "").strip()
        if customer_center_id:
            merged["customer_center_id"] = customer_center_id
        if refresh_token:
            merged["refresh_token"] = refresh_token
        return merged

    def _base_runtime_config(self) -> dict[str, Any]:
        config = load_runtime_config(CONFIG_PATH)
        config.setdefault("material_sync_interval_minutes", settings.material_sync_interval_minutes)
        config.setdefault("material_sync_workers", settings.material_sync_workers)
        config.setdefault("material_sync_warm_interval_minutes", settings.material_sync_warm_interval_minutes)
        config.setdefault("material_sync_warm_window_hours", settings.material_sync_warm_window_hours)
        config.setdefault("material_sync_warm_plan_batch_size", settings.material_sync_warm_plan_batch_size)
        config.setdefault("material_sync_cold_plan_batch_size", settings.material_sync_cold_plan_batch_size)
        config.setdefault("material_sync_cold_coverage_hours", settings.material_sync_cold_coverage_hours)
        return config

    def _runtime_config_override_row(self) -> dict[str, Any] | None:
        try:
            with self.db() as conn:
                row = self._runtime_config_override_row_locked(conn)
        except Exception:
            return None
        return row

    def _current_customer_center_id(self) -> str:
        return str(self.read_config().get("customer_center_id") or "").strip()

    @staticmethod
    def _normalize_display_scope(display_scope: str) -> str:
        return DISPLAY_SCOPE_ALL if str(display_scope or "").strip().lower() == DISPLAY_SCOPE_ALL else DISPLAY_SCOPE_CURRENT

    def _display_scope_uses_all_customer_centers(self, display_scope: str) -> bool:
        return self._normalize_display_scope(display_scope) == DISPLAY_SCOPE_ALL

    @staticmethod
    def _snapshot_pairs_from_rows(rows: list[dict[str, Any]]) -> set[tuple[str, str]]:
        return {
            (
                str(row.get("customer_center_id") or "").strip(),
                str(row.get("snapshot_time") or "").strip(),
            )
            for row in rows
            if str(row.get("customer_center_id") or "").strip() and str(row.get("snapshot_time") or "").strip()
        }

    @staticmethod
    def _latest_snapshot_pairs_by_customer_center(selected_pairs: set[tuple[str, str]]) -> set[tuple[str, str]]:
        latest_by_customer_center: dict[str, str] = {}
        for customer_center_id, snapshot_time in selected_pairs:
            current_snapshot = latest_by_customer_center.get(customer_center_id, "")
            if snapshot_time > current_snapshot:
                latest_by_customer_center[customer_center_id] = snapshot_time
        return {
            (customer_center_id, snapshot_time)
            for customer_center_id, snapshot_time in latest_by_customer_center.items()
            if customer_center_id and snapshot_time
        }

    @staticmethod
    def _filter_rows_for_snapshot_pairs(
        rows: list[dict[str, Any]],
        selected_pairs: set[tuple[str, str]],
    ) -> list[dict[str, Any]]:
        if not rows or not selected_pairs:
            return []
        return [
            row
            for row in rows
            if (
                str(row.get("customer_center_id") or "").strip(),
                str(row.get("snapshot_time") or "").strip(),
            )
            in selected_pairs
        ]

    def _latest_extended_sync_all_customer_centers(self) -> dict[str, Any] | None:
        with self.db() as conn:
            rows = [
                dict(row)
                for row in conn.execute(
                    """
                    SELECT
                        customer_center_id,
                        MAX(snapshot_time) AS snapshot_time,
                        COUNT(*) AS material_row_count,
                        SUM(CASE WHEN is_original <> 0 THEN 1 ELSE 0 END) AS original_video_row_count
                    FROM material_current
                    WHERE COALESCE(customer_center_id, '') <> ''
                    GROUP BY customer_center_id
                    ORDER BY snapshot_time DESC, customer_center_id ASC
                    """
                ).fetchall()
            ]
            latest_run_rows = [
                dict(row)
                for row in conn.execute(
                    """
                    SELECT customer_center_id, snapshot_time, status, plan_count, error_count
                    FROM extended_sync_runs
                    WHERE COALESCE(customer_center_id, '') <> ''
                    """
                ).fetchall()
            ]
        if not rows:
            return None
        latest_run_map = {
            (
                str(row.get("customer_center_id") or "").strip(),
                str(row.get("snapshot_time") or "").strip(),
            ): row
            for row in latest_run_rows
            if str(row.get("customer_center_id") or "").strip() and str(row.get("snapshot_time") or "").strip()
        }
        latest_snapshot_time = max(str(row.get("snapshot_time") or "") for row in rows)
        matched_run_rows = [
            latest_run_map.get(
                (
                    str(row.get("customer_center_id") or "").strip(),
                    str(row.get("snapshot_time") or "").strip(),
                )
            )
            for row in rows
        ]
        plan_count = sum(
            int((run_row or {}).get("plan_count", 0) or 0)
            for run_row in matched_run_rows
        )
        error_count = sum(
            int((run_row or {}).get("error_count", 0) or 0)
            for run_row in matched_run_rows
        )
        status = "partial" if any(str((run_row or {}).get("status") or "").strip() == "partial" for run_row in matched_run_rows) else "ok"
        return {
            "snapshot_time": latest_snapshot_time,
            "status": status,
            "plan_count": plan_count,
            "detail_count": sum(int(row.get("material_row_count") or 0) for row in rows),
            "product_row_count": 0,
            "material_row_count": sum(int(row.get("material_row_count") or 0) for row in rows),
            "original_video_row_count": sum(int(row.get("original_video_row_count") or 0) for row in rows),
            "error_count": error_count,
            "customer_center_count": len(rows),
        }

    def _summary_history_all_customer_centers(self, limit: int = 144) -> list[dict[str, Any]]:
        with self.db() as conn:
            rows = (
                [
                    dict(row)
                    for row in conn.execute(
                        """
                        SELECT snapshot_time, customer_center_id, stat_cost, pay_amount, order_count
                        FROM summary_daily
                        WHERE COALESCE(customer_center_id, '') <> ''
                        ORDER BY biz_date DESC, customer_center_id ASC
                        """
                    ).fetchall()
                ]
                if db_table_exists(conn, "summary_daily")
                else []
            )
            current_rows = (
                [
                    dict(row)
                    for row in conn.execute(
                        """
                        SELECT snapshot_time, customer_center_id, stat_cost, pay_amount, order_count
                        FROM summary_current
                        WHERE COALESCE(customer_center_id, '') <> ''
                        ORDER BY customer_center_id ASC
                        """
                    ).fetchall()
                ]
                if db_table_exists(conn, "summary_current")
                else []
            )
        grouped: dict[str, dict[str, Any]] = {}
        for row in [*rows, *current_rows]:
            day_key = str(row.get("snapshot_time") or "")[:10]
            if not day_key:
                continue
            bucket = grouped.setdefault(
                day_key,
                {
                    "snapshot_time": "",
                    "stat_cost": 0.0,
                    "pay_amount": 0.0,
                    "order_count": 0,
                },
            )
            snapshot_time = str(row.get("snapshot_time") or "")
            if snapshot_time > str(bucket.get("snapshot_time") or ""):
                bucket["snapshot_time"] = snapshot_time
            bucket["stat_cost"] = round(float(bucket.get("stat_cost", 0.0) or 0.0) + float(row.get("stat_cost", 0.0) or 0.0), 2)
            bucket["pay_amount"] = round(float(bucket.get("pay_amount", 0.0) or 0.0) + float(row.get("pay_amount", 0.0) or 0.0), 2)
            bucket["order_count"] = int(bucket.get("order_count", 0) or 0) + int(row.get("order_count") or 0)
        items = []
        for day_key in sorted(grouped):
            item = dict(grouped[day_key])
            stat_cost = round(float(item.get("stat_cost", 0.0) or 0.0), 2)
            pay_amount = round(float(item.get("pay_amount", 0.0) or 0.0), 2)
            item["roi"] = round(pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0
            items.append(item)
        return items[-max(int(limit or 0), 0) :] if limit > 0 else items

    def _persist_runtime_config_override(
        self,
        customer_center_id: str,
        refresh_token: str | None = None,
    ) -> dict[str, Any]:
        normalized_customer_center_id = str(customer_center_id or "").strip()
        if not normalized_customer_center_id:
            raise ValueError("customer_center_id 不能为空")
        existing = self._runtime_config_override_row() or {}
        next_refresh_token = str(existing.get("refresh_token") or "").strip()
        if refresh_token is not None:
            next_refresh_token = str(refresh_token).strip()
        updated_at = now_text()
        with self.db() as conn:
            conn.execute(
                """
                INSERT INTO runtime_config_overrides (
                    id, customer_center_id, refresh_token, updated_at
                ) VALUES (1, ?, ?, ?)
                ON CONFLICT (id) DO UPDATE SET
                    customer_center_id = excluded.customer_center_id,
                    refresh_token = excluded.refresh_token,
                    updated_at = excluded.updated_at
                """,
                (normalized_customer_center_id, next_refresh_token, updated_at),
            )
        return {
            "customer_center_id": normalized_customer_center_id,
            "refresh_token": next_refresh_token,
            "updated_at": updated_at,
        }

    @staticmethod
    def _token_updated_at(payload: dict[str, Any] | None) -> int:
        if not payload:
            return 0
        try:
            return int(payload.get("updated_at") or 0)
        except (TypeError, ValueError):
            return 0

    @staticmethod
    def _token_expires_at(payload: dict[str, Any] | None) -> int:
        if not payload:
            return 0
        try:
            return int(payload.get("expires_at") or 0)
        except (TypeError, ValueError):
            return 0

    @staticmethod
    def _token_payload_has_usable_access_token(payload: dict[str, Any] | None, now: int | None = None) -> bool:
        if not payload:
            return False
        current = int(now or time.time())
        access_token = str(payload.get("access_token") or "").strip()
        expires_at = DashboardService._token_expires_at(payload)
        return bool(access_token) and expires_at > current + 300

    @staticmethod
    def _prefer_candidate_token_payload(candidate: dict[str, Any] | None, current: dict[str, Any] | None) -> bool:
        if not candidate:
            return False
        if not current:
            return True
        candidate_updated_at = DashboardService._token_updated_at(candidate)
        current_updated_at = DashboardService._token_updated_at(current)
        if candidate_updated_at != current_updated_at:
            return candidate_updated_at > current_updated_at
        candidate_expires_at = DashboardService._token_expires_at(candidate)
        current_expires_at = DashboardService._token_expires_at(current)
        if candidate_expires_at != current_expires_at:
            return candidate_expires_at > current_expires_at
        candidate_refresh_token = str(candidate.get("refresh_token") or "").strip()
        current_refresh_token = str(current.get("refresh_token") or "").strip()
        return bool(candidate_refresh_token and candidate_refresh_token != current_refresh_token)

    @staticmethod
    def _join_upstream_url(base_url: str, path: str) -> str:
        normalized_base = str(base_url or "").strip().rstrip("/")
        normalized_path = str(path or "").strip()
        if not normalized_path:
            return normalized_base
        if normalized_path.startswith("http://") or normalized_path.startswith("https://"):
            return normalized_path
        if not normalized_path.startswith("/"):
            normalized_path = f"/{normalized_path}"
        return f"{normalized_base}{normalized_path}"

    def _upstream_token_sync_enabled(self) -> bool:
        return bool(
            OCEANENGINE_UPSTREAM_BASE_URL
            and OCEANENGINE_UPSTREAM_USERNAME
            and OCEANENGINE_UPSTREAM_PASSWORD
        )

    def _fetch_upstream_latest_token_payload(self, config: dict[str, Any]) -> dict[str, Any] | None:
        if not self._upstream_token_sync_enabled():
            return None
        login_url = self._join_upstream_url(OCEANENGINE_UPSTREAM_BASE_URL, OCEANENGINE_UPSTREAM_LOGIN_PATH)
        token_url = self._join_upstream_url(OCEANENGINE_UPSTREAM_BASE_URL, OCEANENGINE_UPSTREAM_TOKEN_PATH)
        session = requests.Session()
        login_response = session.post(
            login_url,
            data={
                "username": OCEANENGINE_UPSTREAM_USERNAME,
                "password": OCEANENGINE_UPSTREAM_PASSWORD,
            },
            allow_redirects=False,
            timeout=OCEANENGINE_UPSTREAM_TIMEOUT_SECONDS,
        )
        if login_response.status_code not in {200, 302, 303}:
            raise ApiError(f"upstream token login failed: {login_response.status_code}")
        response = session.get(token_url, timeout=OCEANENGINE_UPSTREAM_TIMEOUT_SECONDS)
        response.raise_for_status()
        payload = response.json()
        if isinstance(payload, dict) and isinstance(payload.get("data"), dict):
            payload = dict(payload["data"])
        if not isinstance(payload, dict):
            raise ApiError("upstream token payload must be a JSON object")
        normalized = dict(payload)
        normalized["app_id"] = str(normalized.get("app_id") or config.get("app_id") or "").strip()
        normalized["customer_center_id"] = str(
            normalized.get("customer_center_id") or config.get("customer_center_id") or ""
        ).strip()
        normalized["access_token"] = str(normalized.get("access_token") or "").strip()
        normalized["refresh_token"] = str(normalized.get("refresh_token") or "").strip()
        normalized["source"] = str(normalized.get("source") or "aa_upstream").strip() or "aa_upstream"
        try:
            normalized["expires_at"] = int(normalized.get("expires_at") or 0)
        except (TypeError, ValueError):
            normalized["expires_at"] = 0
        try:
            normalized["refresh_token_expires_in"] = int(normalized.get("refresh_token_expires_in") or 0)
        except (TypeError, ValueError):
            normalized["refresh_token_expires_in"] = 0
        try:
            normalized["updated_at"] = int(normalized.get("updated_at") or int(time.time()))
        except (TypeError, ValueError):
            normalized["updated_at"] = int(time.time())
        target_app_id = str(config.get("app_id") or "").strip()
        target_customer_center_id = str(config.get("customer_center_id") or "").strip()
        if target_app_id and normalized["app_id"] and normalized["app_id"] != target_app_id:
            raise ApiError(
                f"upstream token app_id mismatch: expected {target_app_id}, got {normalized['app_id']}"
            )
        if (
            target_customer_center_id
            and normalized["customer_center_id"]
            and normalized["customer_center_id"] != target_customer_center_id
        ):
            return None
        if not normalized["access_token"] and not normalized["refresh_token"]:
            raise ApiError("upstream token payload is empty")
        return normalized

    def _upstream_latest_token_payload_cached(
        self,
        config: dict[str, Any],
        *,
        force_refresh: bool = False,
    ) -> dict[str, Any] | None:
        if not self._upstream_token_sync_enabled():
            return None
        normalized_app_id = str(config.get("app_id") or "").strip()
        normalized_customer_center_id = str(config.get("customer_center_id") or "").strip()
        cache_key = f"{normalized_app_id}:{normalized_customer_center_id}"
        now = float(time.time())
        cached = self._upstream_token_payload_cache.get(cache_key) or {}
        checked_at = float(cached.get("checked_at") or 0.0)
        if not force_refresh and checked_at > 0 and now - checked_at < 60:
            payload = cached.get("payload")
            return dict(payload) if isinstance(payload, dict) else None
        payload = self._fetch_upstream_latest_token_payload(config)
        self._upstream_token_payload_cache[cache_key] = {
            "checked_at": now,
            "payload": dict(payload) if isinstance(payload, dict) else None,
        }
        return dict(payload) if isinstance(payload, dict) else None

    @staticmethod
    def _token_refresh_mode() -> str:
        normalized = str(OCEANENGINE_TOKEN_REFRESH_MODE or "local_refresh").strip().lower()
        return normalized if normalized in {"local_refresh", "upstream_only"} else "local_refresh"

    def _token_refresh_uses_upstream_only(self) -> bool:
        return self._token_refresh_mode() == "upstream_only"

    def _authoritative_token_payload_for_config(
        self,
        config: dict[str, Any],
        *,
        force_refresh: bool = False,
    ) -> dict[str, Any] | None:
        effective_config = dict(config or {})
        with self._upstream_token_sync_lock:
            try:
                upstream_payload = self._upstream_latest_token_payload_cached(
                    effective_config,
                    force_refresh=force_refresh,
                )
            except Exception:
                upstream_payload = None
            if upstream_payload:
                return self._persist_token_cache_for_config(effective_config, upstream_payload)
            stored_payload = self._stored_token_payload_for_config(effective_config) or {}
            if stored_payload:
                return self._persist_token_cache_for_config(effective_config, stored_payload)
        return None

    def _synchronize_authoritative_token_for_config(
        self,
        config: dict[str, Any],
    ) -> dict[str, Any] | None:
        effective_config = dict(config or {})
        target_customer_center_id = str(effective_config.get("customer_center_id") or "").strip()
        trigger_material_hot_sync = False
        with self._upstream_token_sync_lock:
            stored_payload = self._stored_token_payload_for_config(effective_config) or {}
            selected_payload: dict[str, Any] | None = stored_payload or None
            upstream_payload: dict[str, Any] | None = None

            try:
                upstream_payload = self._upstream_latest_token_payload_cached(effective_config)
            except Exception:
                upstream_payload = None
            if upstream_payload and self._prefer_candidate_token_payload(upstream_payload, stored_payload):
                selected_payload = self._persist_token_cache_for_config(effective_config, upstream_payload)
                trigger_material_hot_sync = True
            elif stored_payload:
                selected_payload = self._persist_token_cache_for_config(effective_config, stored_payload)
            elif upstream_payload:
                selected_payload = self._persist_token_cache_for_config(effective_config, upstream_payload)

            if (
                selected_payload
                and target_customer_center_id
                and target_customer_center_id == self._current_customer_center_id()
            ):
                refresh_token = str(selected_payload.get("refresh_token") or "").strip()
                if refresh_token:
                    self._persist_runtime_config_override(target_customer_center_id, refresh_token=refresh_token)
        if trigger_material_hot_sync:
            self._queue_material_hot_sync_if_needed(
                customer_center_id=target_customer_center_id,
                reason="upstream_token_updated",
            )
        return selected_payload

    def _exchange_auth_code_payload(self, config: dict[str, Any], auth_code: str) -> dict[str, Any]:
        now = int(time.time())
        response = post_json(
            ACCESS_TOKEN_URL,
            {
                "app_id": config["app_id"],
                "secret": config["app_secret"],
                "grant_type": "auth_code",
                "auth_code": str(auth_code or "").strip(),
            },
        )
        if response.get("code") != 0:
            raise ApiError(f"exchange auth_code failed: {response}")
        data = response["data"]
        return {
            "access_token": data["access_token"],
            "refresh_token": data["refresh_token"],
            "expires_at": now + int(data["expires_in"]),
            "refresh_token_expires_in": data.get("refresh_token_expires_in"),
            "updated_at": now,
            "source": "auth_code",
        }

    def _customer_center_preview(
        self,
        config: dict[str, Any],
        access_token: str,
        sample_limit: int = 5,
    ) -> dict[str, Any]:
        response = get_json_with_retries(
            CUSTOMER_CENTER_URL,
            access_token,
            {
                "cc_account_id": config["customer_center_id"],
                "account_source": config["account_source"],
                "page": 1,
                "page_size": 100,
            },
        )
        if response.get("code") != 0:
            raise ApiError(f"list accounts failed: {response}")
        data = response.get("data") or {}
        rows = list(data.get("list") or [])
        page_info = data.get("page_info") or {}
        total_count = int(page_info.get("total_number", len(rows)) or len(rows))
        sample_accounts = [
            {
                "advertiser_id": int(item.get("advertiser_id") or item.get("account_id") or 0),
                "advertiser_name": str(
                    item.get("advertiser_name")
                    or item.get("account_name")
                    or item.get("name")
                    or item.get("advertiser_id")
                    or item.get("account_id")
                    or ""
                ).strip(),
            }
            for item in rows[: max(int(sample_limit or 0), 0)]
            if int(item.get("advertiser_id") or item.get("account_id") or 0)
        ]
        return {
            "account_count": total_count,
            "sample_accounts": sample_accounts,
        }

    def _persist_token_cache_for_config(self, config: dict[str, Any], payload: dict[str, Any]) -> dict[str, Any]:
        normalized = dict(payload)
        normalized["app_id"] = str(config.get("app_id") or "")
        normalized["customer_center_id"] = str(config.get("customer_center_id") or "")
        dump_json(TOKEN_CACHE_PATH, normalized)
        try:
            os.chmod(TOKEN_CACHE_PATH, 0o600)
        except OSError:
            pass
        if LATEST_TOKEN_PATH != TOKEN_CACHE_PATH:
            dump_json(LATEST_TOKEN_PATH, normalized)
            try:
                os.chmod(LATEST_TOKEN_PATH, 0o600)
            except OSError:
                pass
        self.persist_token_record(normalized)
        return normalized

    def _stored_token_payload_for_config(self, config: dict[str, Any]) -> dict[str, Any] | None:
        return self.token_access.token_payload_for(
            str(config.get("app_id") or ""),
            str(config.get("customer_center_id") or ""),
        )

    def _access_token_from_payload(
        self,
        config: dict[str, Any],
        payload: dict[str, Any],
    ) -> tuple[str, dict[str, Any]]:
        now = int(time.time())
        normalized = dict(payload or {})
        access_token = str(normalized.get("access_token") or "").strip()
        expires_at = int(normalized.get("expires_at") or 0)
        if access_token and expires_at > now + 300:
            normalized["updated_at"] = int(normalized.get("updated_at") or now)
            normalized["source"] = str(normalized.get("source") or "stored_token")
            return access_token, normalized

        authoritative_payload = self._authoritative_token_payload_for_config(config, force_refresh=True) or {}
        authoritative_access_token = str(authoritative_payload.get("access_token") or "").strip()
        authoritative_expires_at = int(authoritative_payload.get("expires_at") or 0)
        if authoritative_access_token and authoritative_expires_at > now + 60:
            authoritative_payload["updated_at"] = int(authoritative_payload.get("updated_at") or now)
            authoritative_payload["source"] = str(authoritative_payload.get("source") or "aa_upstream")
            return authoritative_access_token, authoritative_payload
        if self._token_refresh_uses_upstream_only():
            raise ApiError("No valid upstream access_token is available for the selected customer_center_id")

        refresh_token = str(normalized.get("refresh_token") or config.get("refresh_token") or "").strip()
        if not refresh_token:
            raise ApiError("No refresh token is available for the selected customer_center_id")
        response = post_json(
            REFRESH_URL,
            {
                "app_id": config["app_id"],
                "secret": config["app_secret"],
                "grant_type": "refresh_token",
                "refresh_token": refresh_token,
            },
        )
        if response.get("code") != 0:
            raise ApiError(f"refresh token failed: {response}")
        data = response["data"]
        refreshed = {
            "access_token": data["access_token"],
            "refresh_token": data["refresh_token"],
            "expires_at": now + int(data["expires_in"]),
            "refresh_token_expires_in": data.get("refresh_token_expires_in"),
            "updated_at": now,
            "source": "refresh_token",
        }
        return str(refreshed["access_token"]), refreshed

    @staticmethod
    def _latest_rows_by_customer_center(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
        selected: list[dict[str, Any]] = []
        seen_customer_centers: set[str] = set()
        for raw_row in rows:
            row = dict(raw_row)
            customer_center_id = str(row.get("customer_center_id") or "").strip()
            if not customer_center_id or customer_center_id in seen_customer_centers:
                continue
            selected.append(row)
            seen_customer_centers.add(customer_center_id)
        return selected

    @staticmethod
    def _latest_rows_by_customer_center_day(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
        selected: list[dict[str, Any]] = []
        seen_keys: set[tuple[str, str]] = set()
        for raw_row in rows:
            row = dict(raw_row)
            customer_center_id = str(row.get("customer_center_id") or "").strip()
            snapshot_time = str(row.get("snapshot_time") or "").strip()
            day_key = snapshot_time[:10]
            if not customer_center_id or not day_key:
                continue
            dedupe_key = (customer_center_id, day_key)
            if dedupe_key in seen_keys:
                continue
            selected.append(row)
            seen_keys.add(dedupe_key)
        selected.sort(key=lambda item: str(item.get("snapshot_time") or ""))
        return selected

    def list_bound_customer_centers(self) -> list[dict[str, Any]]:
        base_config = self._base_runtime_config()
        current_customer_center_id = self._current_customer_center_id()
        base_customer_center_id = str(base_config.get("customer_center_id") or "").strip()
        override_row = self._runtime_config_override_row() or {}
        override_customer_center_id = str(override_row.get("customer_center_id") or "").strip()
        app_id = str(base_config.get("app_id") or "").strip()

        with self.db() as conn:
            token_rows = (
                [
                    dict(row)
                    for row in conn.execute(
                        """
                        SELECT customer_center_id, updated_at, source, expires_at
                        FROM oauth_tokens
                        WHERE app_id = ?
                        ORDER BY updated_at DESC, customer_center_id ASC
                        """,
                        (app_id,),
                    ).fetchall()
                ]
                if app_id
                else []
            )
            summary_rows = self._latest_rows_by_customer_center(
                [
                    dict(row)
                    for row in conn.execute(
                        """
                        SELECT
                            customer_center_id,
                            snapshot_time,
                            account_count,
                            active_account_count,
                            plan_count,
                            active_plan_count,
                            stat_cost,
                            pay_amount,
                            order_count,
                            roi
                        FROM summary_current
                        WHERE COALESCE(customer_center_id, '') <> ''
                        ORDER BY snapshot_time DESC, customer_center_id ASC
                        """
                    ).fetchall()
                ]
            )
            detail_rows = [
                [
                    dict(row)
                    for row in conn.execute(
                        """
                        SELECT
                            customer_center_id,
                            MAX(snapshot_time) AS snapshot_time,
                            'ok' AS status,
                            COUNT(*) AS material_row_count,
                            0 AS error_count
                        FROM material_current
                        WHERE COALESCE(customer_center_id, '') <> ''
                        GROUP BY customer_center_id
                        ORDER BY snapshot_time DESC, customer_center_id ASC
                        """
                    ).fetchall()
                ]
            ][0]

        summary_by_customer_center = {
            str(row.get("customer_center_id") or "").strip(): row for row in summary_rows if str(row.get("customer_center_id") or "").strip()
        }
        detail_by_customer_center = {
            str(row.get("customer_center_id") or "").strip(): row for row in detail_rows if str(row.get("customer_center_id") or "").strip()
        }

        records: dict[str, dict[str, Any]] = {}
        for row in token_rows:
            customer_center_id = str(row.get("customer_center_id") or "").strip()
            if not customer_center_id:
                continue
            records[customer_center_id] = {
                "customer_center_id": customer_center_id,
                "has_saved_token": True,
                "token_updated_at": int(row.get("updated_at") or 0),
                "token_source": str(row.get("source") or "").strip(),
                "token_expires_at": int(row.get("expires_at") or 0),
            }

        items: list[dict[str, Any]] = []
        for customer_center_id, row in records.items():
            summary_row = summary_by_customer_center.get(customer_center_id) or {}
            detail_row = detail_by_customer_center.get(customer_center_id) or {}
            items.append(
                {
                    **row,
                    "is_current": customer_center_id == current_customer_center_id,
                    "is_base_customer_center": customer_center_id == base_customer_center_id,
                    "is_override_customer_center": bool(override_customer_center_id)
                    and customer_center_id == override_customer_center_id,
                    "latest_snapshot_time": str(summary_row.get("snapshot_time") or "").strip(),
                    "latest_detail_snapshot_time": str(detail_row.get("snapshot_time") or "").strip(),
                    "account_count": int(summary_row.get("account_count") or 0),
                    "active_account_count": int(summary_row.get("active_account_count") or 0),
                    "plan_count": int(summary_row.get("plan_count") or 0),
                    "active_plan_count": int(summary_row.get("active_plan_count") or 0),
                    "stat_cost": round(float(summary_row.get("stat_cost", 0.0) or 0.0), 2),
                    "pay_amount": round(float(summary_row.get("pay_amount", 0.0) or 0.0), 2),
                    "order_count": int(summary_row.get("order_count") or 0),
                    "roi": round(float(summary_row.get("roi", 0.0) or 0.0), 2),
                    "detail_status": str(detail_row.get("status") or "").strip(),
                    "detail_material_row_count": int(detail_row.get("material_row_count") or 0),
                    "detail_error_count": int(detail_row.get("error_count") or 0),
                }
            )

        items.sort(
            key=lambda item: (
                0 if bool(item.get("is_current")) else 1,
                0 if bool(item.get("has_saved_token")) else 1,
                -int(item.get("token_updated_at") or 0),
                0 if str(item.get("latest_snapshot_time") or "").strip() else 1,
                str(item.get("customer_center_id") or ""),
            )
        )
        return items

    def ocean_engine_runtime_config(
        self,
        token_payload: dict[str, Any] | None = None,
        bound_customer_centers: list[dict[str, Any]] | None = None,
    ) -> dict[str, Any]:
        base_config = self._base_runtime_config()
        override_row = self._runtime_config_override_row() or {}
        effective_config = self._merge_runtime_config_override(base_config, override_row)
        effective_token_payload = token_payload or self.latest_token_payload(masked=True)
        override_customer_center_id = str(override_row.get("customer_center_id") or "").strip()
        override_refresh_token = str(override_row.get("refresh_token") or "").strip()
        return {
            "app_id": str(effective_config.get("app_id") or ""),
            "customer_center_id": str(effective_config.get("customer_center_id") or ""),
            "base_customer_center_id": str(base_config.get("customer_center_id") or ""),
            "override_customer_center_id": override_customer_center_id,
            "has_customer_center_override": bool(override_customer_center_id),
            "has_refresh_token_override": bool(override_refresh_token),
            "account_source": str(effective_config.get("account_source") or ""),
            "timezone": str(effective_config.get("timezone") or ""),
            "material_sync_interval_minutes": int(effective_config.get("material_sync_interval_minutes") or 0),
            "material_sync_warm_interval_minutes": int(
                effective_config.get("material_sync_warm_interval_minutes") or 0
            ),
            "material_sync_warm_window_hours": int(effective_config.get("material_sync_warm_window_hours") or 0),
            "material_sync_cold_coverage_hours": int(effective_config.get("material_sync_cold_coverage_hours") or 0),
            "token_updated_at": int(effective_token_payload.get("updated_at") or 0),
            "token_source": str(effective_token_payload.get("source") or ""),
            "bound_customer_centers": list(
                bound_customer_centers if bound_customer_centers is not None else self.list_bound_customer_centers()
            ),
        }

    @staticmethod
    def _classify_customer_center_auth_error(message: str) -> tuple[str, str]:
        normalized = str(message or "").strip()
        lowered = normalized.lower()
        if "40002" in normalized or "no permission to operate account" in lowered:
            return (
                "permission_denied",
                "千川侧已取消当前应用/主体对该客群中心的操作权限，需要重新授权。",
            )
        if "refresh token failed" in lowered or "40103" in normalized or "已过期" in normalized:
            return (
                "token_invalid",
                "保存的 refresh_token 已失效，需要重新授权。",
            )
        if "no refresh token is available" in lowered:
            return (
                "token_missing",
                "系统内没有该客群中心可用的 refresh_token，需要重新授权。",
            )
        return ("error", normalized or "unknown error")

    @staticmethod
    def _parse_snapshot_time_text(value: Any) -> datetime | None:
        text = str(value or "").strip()
        if not text:
            return None
        try:
            return datetime.strptime(text[:19], "%Y-%m-%d %H:%M:%S")
        except ValueError:
            return None

    def audit_customer_center_authorizations(
        self,
        stale_hours: int = AUTH_AUDIT_STALE_HOURS,
    ) -> dict[str, Any]:
        stale_seconds = max(int(stale_hours or AUTH_AUDIT_STALE_HOURS), 1) * 3600
        with self._distributed_runtime_lock("oauth-audit", timeout_seconds=1800) as acquired:
            if not acquired:
                return {
                    "ok": True,
                    "skipped": True,
                    "reason": "oauth audit already running",
                    "stale_hours": stale_hours,
                    "customer_center_count": 0,
                    "checked_count": 0,
                    "ok_count": 0,
                    "repaired_count": 0,
                    "error_count": 0,
                    "items": [],
                }

            items: list[dict[str, Any]] = []
            repaired_count = 0
            error_count = 0
            now_dt = datetime.now(ZoneInfo(str(self.read_config().get("timezone") or TIMEZONE)))
            customer_center_ids = self.bound_customer_center_ids()

            for customer_center_id in customer_center_ids:
                latest_snapshot_time = ""
                latest_snapshot_age_hours = 0.0
                with self.db() as conn:
                    latest_meta = self._latest_summary_meta(conn, customer_center_id)
                if latest_meta:
                    latest_snapshot_time = str(latest_meta["snapshot_time"] or "").strip()
                    latest_snapshot_dt = self._parse_snapshot_time_text(latest_snapshot_time)
                    if latest_snapshot_dt:
                        latest_snapshot_age_hours = round(
                            max((now_dt.replace(tzinfo=None) - latest_snapshot_dt).total_seconds(), 0.0) / 3600.0,
                            2,
                        )
                item = {
                    "customer_center_id": customer_center_id,
                    "latest_snapshot_time": latest_snapshot_time,
                    "latest_snapshot_age_hours": latest_snapshot_age_hours,
                    "status": "ok",
                    "reason": "",
                    "account_count": 0,
                    "repaired": False,
                    "repair_summary_snapshot_time": "",
                    "repair_detail_snapshot_time": "",
                }
                try:
                    client = self._build_scoped_customer_center_client(customer_center_id)
                    accounts = client.list_accounts()
                    item["account_count"] = len(accounts)
                    snapshot_dt = self._parse_snapshot_time_text(latest_snapshot_time)
                    needs_repair = (
                        not latest_snapshot_time
                        or snapshot_dt is None
                        or (now_dt.replace(tzinfo=None) - snapshot_dt).total_seconds() >= stale_seconds
                    )
                    if needs_repair:
                        summary_payload = self.collect_snapshot_for_customer_center(customer_center_id)
                        self.persist_snapshot(summary_payload)
                        item["repaired"] = True
                        item["repair_summary_snapshot_time"] = str(summary_payload.get("snapshot_time") or "").strip()
                        detail_payload = self.collect_material_snapshot(force_refresh=True, customer_center_id=customer_center_id)
                        if not detail_payload.get("skipped"):
                            self.persist_material_snapshot(detail_payload, replace_same_day=True)
                            item["repair_detail_snapshot_time"] = str(detail_payload.get("snapshot_time") or "").strip()
                        repaired_count += 1
                except Exception as exc:  # noqa: BLE001
                    error_count += 1
                    status_text, reason_text = self._classify_customer_center_auth_error(str(exc))
                    item["status"] = status_text
                    item["reason"] = reason_text
                    item["error"] = str(exc)
                items.append(item)

            if repaired_count:
                self.cleanup_history()
                self.clear_runtime_caches()

            ok_count = sum(1 for item in items if str(item.get("status") or "") == "ok")
            return {
                "ok": error_count == 0,
                "skipped": False,
                "reason": "" if error_count == 0 else f"{error_count} customer center authorization checks failed",
                "stale_hours": stale_hours,
                "customer_center_count": len(customer_center_ids),
                "checked_count": len(items),
                "ok_count": ok_count,
                "repaired_count": repaired_count,
                "error_count": error_count,
                "items": items,
            }

    def refresh_customer_center_tokens(self) -> dict[str, Any]:
        with self._distributed_runtime_lock("oauth-token-refresh", timeout_seconds=1800) as acquired:
            if not acquired:
                return {
                    "ok": True,
                    "skipped": True,
                    "reason": "oauth token refresh already running",
                    "customer_center_count": 0,
                    "checked_count": 0,
                    "refreshed_count": 0,
                    "error_count": 0,
                    "items": [],
                }

            customer_center_ids = self.bound_customer_center_ids()
            items: list[dict[str, Any]] = []
            refreshed_count = 0
            error_count = 0

            for customer_center_id in customer_center_ids:
                item = {
                    "customer_center_id": customer_center_id,
                    "status": "ok",
                    "reason": "",
                    "refreshed": False,
                    "token_updated_at": 0,
                    "token_expires_at": 0,
                    "token_source": "",
                }
                try:
                    client = self._build_scoped_customer_center_client(customer_center_id)
                    client.get_access_token(force_refresh=True)
                    refreshed_count += 1
                    item["refreshed"] = True
                    scoped_config = self._scoped_config_for_customer_center(customer_center_id)
                    payload = self._stored_token_payload_for_config(scoped_config) or {}
                    item["token_updated_at"] = int(payload.get("updated_at") or 0)
                    item["token_expires_at"] = int(payload.get("expires_at") or 0)
                    item["token_source"] = str(payload.get("source") or "").strip()
                except Exception as exc:  # noqa: BLE001
                    error_count += 1
                    status_text, reason_text = self._classify_customer_center_auth_error(str(exc))
                    item["status"] = status_text
                    item["reason"] = reason_text
                    item["error"] = str(exc)
                items.append(item)

            ok_count = sum(1 for item in items if str(item.get("status") or "") == "ok")
            return {
                "ok": error_count == 0,
                "skipped": False,
                "reason": "" if error_count == 0 else f"{error_count} customer center token refreshes failed",
                "customer_center_count": len(customer_center_ids),
                "checked_count": len(items),
                "ok_count": ok_count,
                "refreshed_count": refreshed_count,
                "error_count": error_count,
                "items": items,
            }

    def refresh_plan_delivery_type_metadata(
        self,
        customer_center_ids: list[str] | None = None,
    ) -> dict[str, Any]:
        with self._distributed_runtime_lock("plan-delivery-type-metadata", timeout_seconds=3600) as acquired:
            if not acquired:
                return {
                    "ok": True,
                    "skipped": True,
                    "reason": "plan delivery type metadata refresh already running",
                    "customer_center_count": 0,
                    "checked_count": 0,
                    "refreshed_count": 0,
                    "metadata_row_count": 0,
                    "error_count": 0,
                    "items": [],
                }

            target_customer_center_ids = [
                str(item or "").strip()
                for item in (customer_center_ids or self.bound_customer_center_ids())
                if str(item or "").strip()
            ]
            items: list[dict[str, Any]] = []
            refreshed_count = 0
            metadata_row_count = 0
            error_count = 0

            for customer_center_id in target_customer_center_ids:
                item = {
                    "customer_center_id": customer_center_id,
                    "status": "ok",
                    "reason": "",
                    "account_count": 0,
                    "refreshed_advertiser_count": 0,
                    "metadata_row_count": 0,
                    "error_count": 0,
                    "errors": [],
                }
                try:
                    scoped_config = self._scoped_config_for_customer_center(customer_center_id)
                    start_dt, end_dt, _title, _label = build_window(
                        "intraday",
                        str(scoped_config.get("timezone") or TIMEZONE),
                    )
                    client = self._build_scoped_customer_center_client(customer_center_id)
                    accounts = client.list_accounts()
                    item["account_count"] = len(accounts)
                    worker_count = max(1, min(int(scoped_config.get("plan_max_workers", 2) or 2), 4))
                    refreshed_at = now_text(str(scoped_config.get("timezone") or TIMEZONE))
                    advertiser_rows: list[tuple[int, list[dict[str, Any]]]] = []
                    advertiser_errors: list[str] = []

                    with ThreadPoolExecutor(max_workers=worker_count) as pool:
                        future_map = {
                            pool.submit(
                                client.list_plan_delivery_type_metadata,
                                int(account.get("advertiser_id", 0) or 0),
                                str(account.get("advertiser_name") or ""),
                                start_dt,
                                end_dt,
                            ): account
                            for account in accounts
                            if int(account.get("advertiser_id", 0) or 0) > 0
                        }
                        for future in as_completed(future_map):
                            account = future_map[future]
                            advertiser_id = int(account.get("advertiser_id", 0) or 0)
                            advertiser_name = str(account.get("advertiser_name") or advertiser_id)
                            try:
                                rows = list(future.result() or [])
                            except Exception as exc:  # noqa: BLE001
                                advertiser_errors.append(f"{advertiser_name}: {exc}")
                                continue
                            if rows:
                                advertiser_rows.append((advertiser_id, rows))

                    with self.db() as conn:
                        for advertiser_id, rows in advertiser_rows:
                            metadata_row_count += self._replace_plan_delivery_type_metadata_for_advertiser_locked(
                                conn,
                                customer_center_id,
                                advertiser_id,
                                rows,
                                refreshed_at,
                            )

                    item["refreshed_advertiser_count"] = len(advertiser_rows)
                    item["metadata_row_count"] = sum(len(rows) for _advertiser_id, rows in advertiser_rows)
                    if advertiser_errors:
                        item["status"] = "partial" if advertiser_rows else "error"
                        item["reason"] = advertiser_errors[0]
                        item["error_count"] = len(advertiser_errors)
                        item["errors"] = advertiser_errors[:20]
                        error_count += len(advertiser_errors)
                    if advertiser_rows:
                        refreshed_count += 1
                except Exception as exc:  # noqa: BLE001
                    item["status"] = "error"
                    item["reason"] = str(exc)
                    item["error_count"] = 1
                    item["errors"] = [str(exc)]
                    error_count += 1
                items.append(item)

            if metadata_row_count > 0:
                self.clear_performance_runtime_caches()

            ok_count = sum(1 for item in items if str(item.get("status") or "") == "ok")
            return {
                "ok": error_count == 0,
                "skipped": False,
                "reason": "" if error_count == 0 else f"{error_count} advertiser metadata refreshes failed",
                "customer_center_count": len(target_customer_center_ids),
                "checked_count": len(items),
                "ok_count": ok_count,
                "refreshed_count": refreshed_count,
                "metadata_row_count": metadata_row_count,
                "error_count": error_count,
                "items": items,
            }

    def update_ocean_engine_runtime_config(self, payload: Any) -> dict[str, Any]:
        target_customer_center_id = str(getattr(payload, "customer_center_id", "") or "").strip()
        auth_code = str(getattr(payload, "auth_code", "") or "").strip()
        if not target_customer_center_id:
            raise ValueError("customer_center_id 不能为空")

        current_config = self.read_config()
        candidate_config = dict(current_config)
        candidate_config["customer_center_id"] = target_customer_center_id

        fallback_refresh_token = str(current_config.get("refresh_token") or "")
        next_token_payload: dict[str, Any] | None = None
        if auth_code:
            next_token_payload = self._exchange_auth_code_payload(candidate_config, auth_code)
            access_token = str(next_token_payload["access_token"])
        else:
            stored_target_payload = self._stored_token_payload_for_config(candidate_config)
            if stored_target_payload and (
                stored_target_payload.get("access_token") or stored_target_payload.get("refresh_token")
            ):
                access_token, next_token_payload = self._access_token_from_payload(candidate_config, stored_target_payload)
            else:
                access_token = self.build_client(current_config).get_access_token()
                current_token_payload = self._stored_token_payload_for_config(current_config)
                if current_token_payload:
                    fallback_refresh_token = str(
                        current_token_payload.get("refresh_token") or current_config.get("refresh_token") or ""
                    )

        try:
            preview = self._customer_center_preview(candidate_config, access_token, sample_limit=6)
        except Exception:
            if not auth_code and not next_token_payload:
                raise ApiError(
                    "The target CC has no saved token in this system, and the current token cannot access it. "
                    "Authorize this account into the system first, then switch by CC ID."
                )
            raise
        if next_token_payload:
            persisted_payload = self._persist_token_cache_for_config(candidate_config, next_token_payload)
            next_refresh_token = str(persisted_payload.get("refresh_token") or "")
        else:
            next_refresh_token = fallback_refresh_token
        self._persist_runtime_config_override(
            target_customer_center_id,
            refresh_token=next_refresh_token,
        )
        self.clear_runtime_caches()
        return {
            "config": self.ocean_engine_runtime_config(),
            "preview": preview,
        }

    def bootstrap_auth_store(self) -> None:
        username = str(DASHBOARD_USERNAME or "").strip()
        password = str(DASHBOARD_PASSWORD or "").strip()
        if not username or not password:
            return
        hashed = build_password_hash(password)
        now = now_text()
        with self.db() as conn:
            row = conn.execute("SELECT id FROM app_users WHERE username = ?", (username,)).fetchone()
            if row:
                if not BOOTSTRAP_AUTH_OVERWRITE_EXISTING:
                    return
                conn.execute(
                    """
                UPDATE app_users
                SET password_hash = ?, role = ?, upload_materials_enabled = 1, enabled = 1, updated_at = ?
                WHERE id = ?
                """,
                    (hashed, ROLE_ADMIN, now, row["id"]),
                )
                return
            conn.execute(
                """
                INSERT INTO app_users (username, password_hash, role, display_name, upload_materials_enabled, enabled, created_at, updated_at)
                VALUES (?, ?, ?, ?, 1, 1, ?, ?)
                """,
                (username, hashed, ROLE_ADMIN, "管理员", now, now),
            )

