    def _performance_snapshot_from_daily_all_customer_centers_locked(
        self,
        conn: Any,
        start_dt: datetime,
        end_dt: datetime,
        snapshots: list[dict[str, Any]],
    ) -> dict[str, Any]:
        selected_day_snapshots = {
            (
                str(row.get("customer_center_id") or "").strip(),
                self.performance_access.summary_row_biz_date(row),
                str(row.get("snapshot_time") or "").strip(),
            )
            for row in snapshots
            if str(row.get("customer_center_id") or "").strip()
            and self.performance_access.summary_row_biz_date(row)
            and str(row.get("snapshot_time") or "").strip()
        }
        account_rows = [
            dict(row)
            for row in conn.execute(
                """
                SELECT *
                FROM account_daily
                WHERE biz_date >= ?
                  AND biz_date <= ?
                ORDER BY biz_date DESC, stat_cost DESC, advertiser_id ASC
                """,
                (
                    start_dt.strftime("%Y-%m-%d"),
                    end_dt.strftime("%Y-%m-%d"),
                ),
            ).fetchall()
        ] if db_table_exists(conn, "account_daily") else []
        account_rows = [
            row
            for row in account_rows
            if (
                str(row.get("customer_center_id") or "").strip(),
                str(row.get("biz_date") or "").strip(),
                str(row.get("snapshot_time") or "").strip(),
            )
            in selected_day_snapshots
        ]
        plan_rows = [
            dict(row)
            for row in conn.execute(
                """
                SELECT *
                FROM plan_daily
                WHERE biz_date >= ?
                  AND biz_date <= ?
                ORDER BY biz_date DESC, order_count DESC, pay_amount DESC, roi DESC, stat_cost DESC, ad_id ASC
                """,
                (
                    start_dt.strftime("%Y-%m-%d"),
                    end_dt.strftime("%Y-%m-%d"),
                ),
            ).fetchall()
        ] if db_table_exists(conn, "plan_daily") else []
        plan_rows = [
            row
            for row in plan_rows
            if (
                str(row.get("customer_center_id") or "").strip(),
                str(row.get("biz_date") or "").strip(),
                str(row.get("snapshot_time") or "").strip(),
            )
            in selected_day_snapshots
        ]
        plan_rows = self._apply_plan_delivery_type_metadata_rows(conn, plan_rows)

        latest_snapshot_by_customer_center: dict[str, str] = {}
        snapshot_times: list[str] = []
        for row in snapshots:
            customer_center_id = str(row.get("customer_center_id") or "").strip()
            snapshot_time = str(row.get("snapshot_time") or "").strip()
            if not customer_center_id or not snapshot_time:
                continue
            snapshot_times.append(snapshot_time)
            current_snapshot = latest_snapshot_by_customer_center.get(customer_center_id, "")
            if snapshot_time > current_snapshot:
                latest_snapshot_by_customer_center[customer_center_id] = snapshot_time
        latest_pairs = {
            (customer_center_id, snapshot_time)
            for customer_center_id, snapshot_time in latest_snapshot_by_customer_center.items()
            if customer_center_id and snapshot_time
        }
        latest_snapshot_times = sorted({snapshot_time for _customer_center_id, snapshot_time in latest_pairs})
        latest_placeholders = ",".join("?" for _ in latest_snapshot_times)
        account_balance_items = self._filter_rows_for_snapshot_pairs(
            [
                dict(row)
                for row in conn.execute(
                    f"""
                    SELECT *
                    FROM account_balances
                    WHERE snapshot_time IN ({latest_placeholders})
                    ORDER BY snapshot_time DESC, advertiser_id ASC
                    """,
                    latest_snapshot_times,
                ).fetchall()
            ],
            latest_pairs,
        )
        shared_wallet_items = self._filter_rows_for_snapshot_pairs(
            [
                dict(row)
                for row in conn.execute(
                    f"""
                    SELECT *
                    FROM shared_wallets
                    WHERE snapshot_time IN ({latest_placeholders})
                    ORDER BY snapshot_time DESC, main_wallet_id ASC
                    """,
                    latest_snapshot_times,
                ).fetchall()
            ],
            latest_pairs,
        )
        wallet_relation_items = self._filter_rows_for_snapshot_pairs(
            [
                dict(row)
                for row in conn.execute(
                    f"""
                    SELECT *
                    FROM shared_wallet_account_relations
                    WHERE snapshot_time IN ({latest_placeholders})
                    ORDER BY snapshot_time DESC, main_wallet_id ASC, advertiser_id ASC
                    """,
                    latest_snapshot_times,
                ).fetchall()
            ],
            latest_pairs,
        )

        return self._build_cross_customer_center_performance_payload(
            start_dt,
            end_dt,
            latest_snapshot_time=max(snapshot_times) if snapshot_times else "",
            snapshot_count=len(snapshots),
            customer_center_count=len(latest_pairs),
            account_rows=account_rows,
            plan_rows=plan_rows,
            account_balance_items=account_balance_items,
            shared_wallet_items=shared_wallet_items,
            wallet_relation_items=wallet_relation_items,
        )

    def _latest_snapshot_all_customer_centers(
        self,
        allowed_advertiser_ids: set[int] | None = None,
    ) -> dict[str, Any] | None:
        with self.db() as conn:
            current_exists = conn.execute(
                "SELECT 1 FROM summary_current WHERE COALESCE(customer_center_id, '') <> '' LIMIT 1"
            ).fetchone()
            if current_exists:
                tz = ZoneInfo(TIMEZONE)
                today_start = datetime.now(tz).replace(hour=0, minute=0, second=0, microsecond=0)
                payload = self._performance_snapshot_from_current_all_customer_centers_locked(
                    conn,
                    today_start,
                    datetime.now(tz),
                )
                if payload.get("snapshot_time"):
                    payload = self._apply_account_scope(payload, allowed_advertiser_ids)
                    payload["extendedSync"] = self._latest_extended_sync_all_customer_centers()
                    return payload
        return None

    def _compute_latest_snapshot(
        self,
        allowed_advertiser_ids: set[int] | None = None,
        display_scope: str = DISPLAY_SCOPE_CURRENT,
    ) -> dict[str, Any] | None:
        all_customer_centers = self._display_scope_uses_all_customer_centers(display_scope)
        timezone_name = str(self.read_config().get("timezone") or TIMEZONE).strip() or TIMEZONE
        if self._display_scope_uses_all_customer_centers(display_scope):
            payload = self._latest_snapshot_all_customer_centers(allowed_advertiser_ids)
            if not payload:
                return payload
            payload = self._safe_apply_material_operator_rankings(
                payload,
                allowed_advertiser_ids=allowed_advertiser_ids,
                snapshot_time=str(payload.get("snapshot_time") or "").strip(),
            )
            payload["materialTodayStatus"] = self._material_today_hot_status(all_customer_centers=all_customer_centers)
            payload["materialHistoryStatus"] = self._material_history_dashboard_status(
                tz_name=timezone_name,
                all_customer_centers=all_customer_centers,
            )
            return payload
        payload = self.performance_access.latest_snapshot(allowed_advertiser_ids)
        if not payload:
            return payload
        payload = self._safe_apply_material_operator_rankings(
            payload,
            allowed_advertiser_ids=allowed_advertiser_ids,
        )
        payload["materialTodayStatus"] = self._material_today_hot_status(all_customer_centers=all_customer_centers)
        payload["materialHistoryStatus"] = self._material_history_dashboard_status(
            tz_name=timezone_name,
            all_customer_centers=all_customer_centers,
        )
        return payload

    def _store_latest_snapshot_cache(self, cache_key: str, payload: dict[str, Any] | None) -> None:
        with self._latest_snapshot_cache_lock:
            self._latest_snapshot_cache[cache_key] = {
                "_cached_at": time.time(),
                "payload": copy.deepcopy(payload),
            }

    def _refresh_latest_snapshot_cache(
        self,
        cache_key: str,
        raw_cache_key: str,
        cache_version: str,
        allowed_advertiser_ids: set[int] | None,
        display_scope: str,
    ) -> None:
        try:
            payload = self._compute_latest_snapshot(allowed_advertiser_ids, display_scope)
            self._store_latest_snapshot_cache(cache_key, payload)
            if isinstance(payload, dict):
                self._shared_dict_cache_set(
                    "latest-snapshot",
                    raw_cache_key,
                    cache_version,
                    payload,
                    LATEST_SNAPSHOT_STALE_SECONDS,
                )
        except Exception:
            pass
        finally:
            with self._latest_snapshot_cache_lock:
                self._latest_snapshot_refreshing.discard(cache_key)

    def _schedule_latest_snapshot_refresh(
        self,
        cache_key: str,
        raw_cache_key: str,
        cache_version: str,
        allowed_advertiser_ids: set[int] | None,
        display_scope: str,
    ) -> None:
        with self._latest_snapshot_cache_lock:
            if cache_key in self._latest_snapshot_refreshing:
                return
            self._latest_snapshot_refreshing.add(cache_key)
        threading.Thread(
            target=self._refresh_latest_snapshot_cache,
            args=(cache_key, raw_cache_key, cache_version, allowed_advertiser_ids, display_scope),
            daemon=True,
            name=f"latest-snapshot-refresh-{display_scope}",
        ).start()

    def latest_snapshot(
        self,
        allowed_advertiser_ids: set[int] | None = None,
        display_scope: str = DISPLAY_SCOPE_CURRENT,
    ) -> dict[str, Any] | None:
        cache_version = self._shared_cache_version("latest-snapshot")
        raw_cache_key = build_latest_snapshot_cache_key(
            allowed_advertiser_ids,
            display_scope,
            self._current_customer_center_id(),
        )
        cache_key = self._versioned_cache_key(cache_version, raw_cache_key)
        now_ts = time.time()
        with self._latest_snapshot_cache_lock:
            cached = copy.deepcopy(self._latest_snapshot_cache.get(cache_key))
        if cached:
            cached_payload = cached.get("payload")
            cached_at = float(cached.get("_cached_at", 0.0) or 0.0)
            age = max(now_ts - cached_at, 0.0)
            if age < LATEST_SNAPSHOT_CACHE_SECONDS:
                return cached_payload
            if age < LATEST_SNAPSHOT_STALE_SECONDS:
                self._schedule_latest_snapshot_refresh(
                    cache_key,
                    raw_cache_key,
                    cache_version,
                    allowed_advertiser_ids,
                    display_scope,
                )
                return cached_payload
        shared_payload = self._shared_dict_cache_get("latest-snapshot", raw_cache_key, cache_version)
        if shared_payload is not None:
            self._store_latest_snapshot_cache(cache_key, shared_payload)
            return copy.deepcopy(shared_payload)
        payload = self._compute_latest_snapshot(allowed_advertiser_ids, display_scope)
        self._store_latest_snapshot_cache(cache_key, payload)
        if isinstance(payload, dict):
            self._shared_dict_cache_set("latest-snapshot", raw_cache_key, cache_version, payload, LATEST_SNAPSHOT_STALE_SECONDS)
        return copy.deepcopy(payload)

    def clear_runtime_caches(self) -> None:
        self.clear_performance_runtime_caches()
        self.clear_material_runtime_caches()
        self.clear_comment_runtime_caches()
        self._backfill_queue_marks.clear()
        self._invalidate_cache_namespaces("latest-snapshot")

    def clear_performance_runtime_caches(self) -> None:
        self._overview_cache.clear()
        self._performance_cache.clear()
        with self._payload_refresh_lock:
            self._payload_refreshing.clear()
        with self._latest_snapshot_cache_lock:
            self._latest_snapshot_cache.clear()
            self._latest_snapshot_refreshing.clear()
        self._invalidate_cache_namespaces(
            "dashboard-overview",
            "performance",
            "latest-snapshot",
        )

    @staticmethod
    def _normalize_material_cache_scope(scope: str = "all") -> str:
        normalized = str(scope or "all").strip().lower() or "all"
        return normalized if normalized in {"all", *MATERIAL_CACHE_SCOPES} else "all"

    @staticmethod
    def _material_cache_scope_from_versioned_key(cache_key: str) -> str:
        normalized = str(cache_key or "").strip().lower()
        if not normalized:
            return MATERIAL_CACHE_SCOPE_HISTORY
        if normalized.startswith("v") and ":" in normalized:
            normalized = normalized.split(":", 1)[1]
        if normalized.startswith("snapshot:") or ":snapshot:" in normalized:
            return MATERIAL_CACHE_SCOPE_HISTORY
        if normalized.startswith("custom:") or ":custom:" in normalized:
            return MATERIAL_CACHE_SCOPE_HISTORY
        if normalized.startswith("day:") or ":day:" in normalized:
            return MATERIAL_CACHE_SCOPE_LIVE
        return MATERIAL_CACHE_SCOPE_HISTORY

    def _material_cache_namespaces(
        self,
        scope: str = "all",
        *,
        include_query: bool = False,
        include_page: bool = False,
    ) -> list[str]:
        normalized_scope = self._normalize_material_cache_scope(scope)
        scopes = (
            [MATERIAL_CACHE_SCOPE_LIVE, MATERIAL_CACHE_SCOPE_HISTORY]
            if normalized_scope == "all"
            else [normalized_scope]
        )
        namespaces: list[str] = []
        for mode in MATERIAL_VIEW_MODES:
            for item_scope in scopes:
                base_namespace = build_material_cache_namespace(mode, scope=item_scope)
                namespaces.append(base_namespace)
                if include_query:
                    namespaces.append(f"{base_namespace}:query")
                if include_page:
                    namespaces.append(f"{base_namespace}:page")
        return namespaces

    def _prune_local_material_cache_store(
        self,
        cache_store: dict[str, dict[str, Any]],
        *,
        scope: str = "all",
    ) -> None:
        normalized_scope = self._normalize_material_cache_scope(scope)
        if normalized_scope == "all":
            cache_store.clear()
            return
        for cache_key in list(cache_store.keys()):
            if self._material_cache_scope_from_versioned_key(cache_key) == normalized_scope:
                cache_store.pop(cache_key, None)

    def _prune_payload_refresh_markers(self, prefixes: list[str]) -> None:
        if not prefixes:
            return
        with self._payload_refresh_lock:
            self._payload_refreshing = {
                marker
                for marker in self._payload_refreshing
                if not any(str(marker or "").startswith(prefix) for prefix in prefixes)
            }

    def clear_material_runtime_caches(self, *, scope: str = "all") -> None:
        normalized_scope = self._normalize_material_cache_scope(scope)
        self._prune_local_material_cache_store(self._material_cache, scope=normalized_scope)
        self._prune_local_material_cache_store(self._material_query_cache, scope=normalized_scope)
        self._material_preview_refresh_cache.clear()
        self._preview_video_resolve_cache.clear()
        refresh_prefixes = [
            f"{namespace}:"
            for namespace in self._material_cache_namespaces(
                normalized_scope,
                include_query=True,
                include_page=True,
            )
        ]
        refresh_prefixes.append("dashboard-overview:")
        self._prune_payload_refresh_markers(refresh_prefixes)
        self._invalidate_cache_namespaces(
            "dashboard-overview",
            *self._material_cache_namespaces(
                normalized_scope,
                include_query=True,
                include_page=True,
            ),
        )

    @staticmethod
    def _material_cache_prewarm_targets() -> list[tuple[str, str, str]]:
        return [
            (DISPLAY_SCOPE_CURRENT, "day", MATERIAL_VIEW_PERFORMANCE),
            (DISPLAY_SCOPE_ALL, "day", MATERIAL_VIEW_PERFORMANCE),
            (DISPLAY_SCOPE_CURRENT, "yesterday", MATERIAL_VIEW_PERFORMANCE),
            (DISPLAY_SCOPE_ALL, "yesterday", MATERIAL_VIEW_PERFORMANCE),
            (DISPLAY_SCOPE_CURRENT, "week", MATERIAL_VIEW_PERFORMANCE),
            (DISPLAY_SCOPE_ALL, "week", MATERIAL_VIEW_PERFORMANCE),
            (DISPLAY_SCOPE_CURRENT, "month", MATERIAL_VIEW_PERFORMANCE),
            (DISPLAY_SCOPE_ALL, "month", MATERIAL_VIEW_PERFORMANCE),
            (DISPLAY_SCOPE_CURRENT, "day", MATERIAL_VIEW_LIBRARY),
            (DISPLAY_SCOPE_ALL, "day", MATERIAL_VIEW_LIBRARY),
        ]

    def _prewarm_material_range_caches(self) -> None:
        for display_scope, range_key, mode in self._material_cache_prewarm_targets():
            try:
                if mode == MATERIAL_VIEW_PERFORMANCE:
                    self._material_performance_page_payload(
                        range_key=range_key,
                        all_customer_centers=self._display_scope_uses_all_customer_centers(display_scope),
                        page=1,
                        page_size=20,
                        sort_key="stat_cost",
                        sort_dir="desc",
                    )
                    continue
                if self._display_scope_uses_all_customer_centers(display_scope):
                    payload = self._cross_customer_center_material_payload(range_key, mode=mode)
                else:
                    payload = self.material_rankings(range_key, mode=mode)
                self.paginate_material_payload(
                    payload,
                    page=1,
                    page_size=20,
                    sort_key="create_time",
                    sort_dir="desc",
                )
            except Exception as exc:  # noqa: BLE001
                self._emit_material_sync_observation(
                    "material_cache_prewarm_error",
                    scope=display_scope,
                    range_key=range_key,
                    mode=mode,
                    error=str(exc),
                )

    @staticmethod
    def _material_performance_page_prewarm_targets() -> list[tuple[str, str]]:
        return [
            (DISPLAY_SCOPE_CURRENT, "day"),
            (DISPLAY_SCOPE_ALL, "day"),
            (DISPLAY_SCOPE_CURRENT, "week"),
            (DISPLAY_SCOPE_ALL, "week"),
            (DISPLAY_SCOPE_CURRENT, "month"),
            (DISPLAY_SCOPE_ALL, "month"),
        ]

    @staticmethod
    def _material_page_prewarm_signature_key() -> str:
        return "dashboard:material-page-prewarm:performance-page1"

    def _material_page_prewarm_signature(self) -> str:
        with self.db() as conn:
            current_meta = self._latest_material_current_meta(conn)
            all_rows = self._latest_material_current_meta_all_customer_centers(conn)
        payload = {
            "current_customer_center_id": str(self._current_customer_center_id() or "").strip(),
            "current": {
                "snapshot_time": str((current_meta or {}).get("snapshot_time") or "").strip(),
                "material_row_count": int((current_meta or {}).get("material_row_count", 0) or 0),
            },
            "all": [
                {
                    "customer_center_id": str(row.get("customer_center_id") or "").strip(),
                    "snapshot_time": str(row.get("snapshot_time") or "").strip(),
                    "material_row_count": int(row.get("material_row_count", 0) or 0),
                }
                for row in all_rows
                if str(row.get("customer_center_id") or "").strip()
            ],
        }
        return hashlib.sha1(
            json.dumps(payload, ensure_ascii=False, sort_keys=True, separators=(",", ":")).encode("utf-8")
        ).hexdigest()

    def _should_prewarm_material_pages(
        self,
        signature: str,
        *,
        force_refresh: bool = False,
    ) -> bool:
        key = self._material_page_prewarm_signature_key()
        client = self._redis()
        previous_signature = ""
        if client is not None:
            try:
                previous_signature = str(client.get(key) or "").strip()
            except Exception:  # noqa: BLE001
                previous_signature = ""
        else:
            previous_signature = str(self._material_page_prewarm_marks.get(key) or "").strip()
        if not force_refresh and previous_signature == signature:
            return False
        if client is not None:
            try:
                client.set(
                    key,
                    signature,
                    ex=max(int(MATERIAL_SYNC_WARM_INTERVAL_MINUTES or 30) * 360, 3600),
                )
            except Exception:  # noqa: BLE001
                pass
        self._material_page_prewarm_marks[key] = signature
        return True

    def _material_performance_page_cache_namespaces(self) -> list[str]:
        return [
            f"{build_material_cache_namespace(MATERIAL_VIEW_PERFORMANCE, scope=MATERIAL_CACHE_SCOPE_LIVE)}:page",
            f"{build_material_cache_namespace(MATERIAL_VIEW_PERFORMANCE, scope=MATERIAL_CACHE_SCOPE_HISTORY)}:page",
        ]

    def _refresh_material_ranking_indexes_after_hot_sync(self) -> None:
        try:
            tz_name = str(self.read_config().get("timezone") or TIMEZONE)
            today = datetime.now(ZoneInfo(tz_name)).date()
            today_key = today.strftime("%Y-%m-%d")
            with self.db() as conn:
                conn.execute(
                    """
                    DELETE FROM material_ranking_index
                    WHERE range_key = 'day'
                      AND start_date = ?
                      AND end_date = ?
                    """,
                    (today_key, today_key),
                )
                conn.execute(
                    """
                    DELETE FROM material_ranking_summary
                    WHERE range_key = 'day'
                      AND start_date = ?
                      AND end_date = ?
                    """,
                    (today_key, today_key),
                )
            for all_customer_centers in (False, True):
                self.refresh_material_ranking_index_for_window(
                    start_day=today_key,
                    end_day=today_key,
                    range_key="day",
                    all_customer_centers=all_customer_centers,
                )
        except Exception as exc:  # noqa: BLE001
            self._emit_material_sync_observation(
                "material_ranking_index_refresh_error",
                error=str(exc),
            )

    def _prewarm_material_performance_page_caches(self, *, force_refresh: bool = False) -> None:
        for display_scope, range_key in self._material_performance_page_prewarm_targets():
            try:
                self._material_performance_page_payload(
                    range_key=range_key,
                    all_customer_centers=self._display_scope_uses_all_customer_centers(display_scope),
                    page=1,
                    page_size=20,
                    sort_key="stat_cost",
                    sort_dir="desc",
                    force_refresh=force_refresh,
                )
            except Exception as exc:  # noqa: BLE001
                self._emit_material_sync_observation(
                    "material_page_prewarm_error",
                    scope=display_scope,
                    range_key=range_key,
                    mode=MATERIAL_VIEW_PERFORMANCE,
                    error=str(exc),
                )

    def _refresh_material_page_caches_after_hot_sync(self, *, force_refresh: bool = False) -> None:
        signature = self._material_page_prewarm_signature()
        if not self._should_prewarm_material_pages(signature, force_refresh=force_refresh):
            self._emit_material_sync_observation(
                "material_page_prewarm_skipped",
                reason="unchanged_signature",
            )
            return
        self.clear_material_runtime_caches(scope=MATERIAL_CACHE_SCOPE_LIVE)
        namespaces = self._material_performance_page_cache_namespaces()
        self._prune_payload_refresh_markers([f"{namespace}:" for namespace in namespaces])
        self._invalidate_cache_namespaces(*namespaces)
        self._refresh_material_ranking_indexes_after_hot_sync()
        self._prewarm_material_performance_page_caches(force_refresh=True)
        self._emit_material_sync_observation(
            "material_page_prewarm_refreshed",
            force_refresh=bool(force_refresh),
        )

