    def _material_relation_current_exists(self, conn: Any, customer_center_id: str) -> bool:
        row = conn.execute(
            "SELECT 1 AS ok FROM material_relation_current WHERE customer_center_id = ? LIMIT 1",
            (str(customer_center_id or "").strip(),),
        ).fetchone()
        return bool(row)

    def _backfill_material_relation_current_from_latest_snapshot(
        self,
        conn: Any,
        customer_center_id: str,
    ) -> int:
        normalized_customer_center_id = str(customer_center_id or "").strip()
        if not normalized_customer_center_id:
            return 0
        latest_row = conn.execute(
            """
            SELECT MAX(snapshot_time) AS snapshot_time
            FROM material_snapshots
            WHERE customer_center_id = ?
            """,
            (normalized_customer_center_id,),
        ).fetchone()
        latest_snapshot_time = str((latest_row or {}).get("snapshot_time") or "").strip()
        if not latest_snapshot_time:
            return 0
        snapshot_rows = [
            dict(row)
            for row in conn.execute(
                """
                SELECT *
                FROM material_snapshots
                WHERE customer_center_id = ?
                  AND snapshot_time = ?
                ORDER BY stat_cost DESC, pay_amount DESC, order_count DESC, material_key ASC
                """,
                (normalized_customer_center_id, latest_snapshot_time),
            ).fetchall()
        ]
        if not snapshot_rows:
            self._replace_material_relation_current_rows(conn, normalized_customer_center_id, [])
            return 0
        material_keys = sorted(
            {
                str(row.get("material_key") or "").strip()
                for row in snapshot_rows
                if str(row.get("material_key") or "").strip()
            }
        )
        profile_map: dict[str, dict[str, Any]] = {}
        for chunk in self._chunked_material_keys(material_keys):
            placeholders = ",".join("?" for _ in chunk)
            profile_rows = conn.execute(
                f"""
                SELECT material_key, top_anchor_name, product_info_text, is_original
                FROM material_profile
                WHERE customer_center_id = ?
                  AND material_key IN ({placeholders})
                """,
                [normalized_customer_center_id, *chunk],
            ).fetchall()
            for raw_profile_row in profile_rows:
                profile_row = dict(raw_profile_row)
                profile_key = str(profile_row.get("material_key") or "").strip()
                if profile_key:
                    profile_map[profile_key] = profile_row
        material_source_rows: list[dict[str, Any]] = []
        for snapshot_row in snapshot_rows:
            profile_row = dict(profile_map.get(str(snapshot_row.get("material_key") or "").strip()) or {})
            material_source_rows.append(
                {
                    "snapshot_time": str(snapshot_row.get("snapshot_time") or ""),
                    "window_start": str(snapshot_row.get("window_start") or ""),
                    "window_end": str(snapshot_row.get("window_end") or ""),
                    "advertiser_id": int(snapshot_row.get("advertiser_id", 0) or 0),
                    "advertiser_name": str(snapshot_row.get("advertiser_name") or ""),
                    "ad_id": int(snapshot_row.get("ad_id", 0) or 0),
                    "ad_name": str(snapshot_row.get("ad_name") or ""),
                    "material_type": str(snapshot_row.get("material_type") or ""),
                    "material_key": str(snapshot_row.get("material_key") or ""),
                    "material_id": str(snapshot_row.get("material_id") or ""),
                    "material_name": str(snapshot_row.get("material_name") or ""),
                    "create_time": str(snapshot_row.get("create_time") or ""),
                    "video_id": str(snapshot_row.get("video_id") or ""),
                    "cover_url": str(snapshot_row.get("cover_url") or ""),
                    "aweme_item_id": str(snapshot_row.get("aweme_item_id") or ""),
                    "video_url": str(snapshot_row.get("video_url") or ""),
                    "product_show_count": int(snapshot_row.get("product_show_count", 0) or 0),
                    "product_click_count": int(snapshot_row.get("product_click_count", 0) or 0),
                    "stat_cost": float(snapshot_row.get("stat_cost", 0.0) or 0.0),
                    "pay_amount": float(snapshot_row.get("pay_amount", 0.0) or 0.0),
                    "total_pay_amount": float(snapshot_row.get("total_pay_amount", 0.0) or 0.0),
                    "settled_pay_amount": float(snapshot_row.get("settled_pay_amount", 0.0) or 0.0),
                    "order_count": int(snapshot_row.get("order_count", 0) or 0),
                    "settled_order_count": int(snapshot_row.get("settled_order_count", 0) or 0),
                    "top_anchor_name": str(profile_row.get("top_anchor_name") or ""),
                    "product_info_text": str(profile_row.get("product_info_text") or ""),
                    "is_original": bool(profile_row.get("is_original")),
                }
            )
        relation_rows = self._build_material_relation_read_rows(
            latest_snapshot_time,
            str(snapshot_rows[0].get("window_start") or ""),
            str(snapshot_rows[0].get("window_end") or ""),
            material_source_rows,
        )
        self._replace_material_relation_current_rows(conn, normalized_customer_center_id, relation_rows)
        return len(relation_rows)

    def _restore_material_history_day_from_latest_snapshot(
        self,
        conn: Any,
        customer_center_id: str,
        biz_date: str,
    ) -> dict[str, Any]:
        normalized_customer_center_id = str(customer_center_id or "").strip()
        day_key = str(biz_date or "").strip()
        if not normalized_customer_center_id or not day_key:
            return {
                "snapshot_time": "",
                "material_daily_row_count": 0,
                "material_relation_row_count": 0,
                "material_snapshot_row_count": 0,
            }
        latest_row = conn.execute(
            """
            SELECT MAX(snapshot_time) AS snapshot_time
            FROM material_snapshots
            WHERE customer_center_id = ?
              AND substr(snapshot_time, 1, 10) = ?
            """,
            (normalized_customer_center_id, day_key),
        ).fetchone()
        latest_snapshot_time = str((latest_row or {}).get("snapshot_time") or "").strip()
        if not latest_snapshot_time:
            self._replace_material_daily_rows(conn, normalized_customer_center_id, day_key, [])
            self._replace_material_relation_daily_rows(conn, normalized_customer_center_id, day_key, [])
            return {
                "snapshot_time": "",
                "material_daily_row_count": 0,
                "material_relation_row_count": 0,
                "material_snapshot_row_count": 0,
            }
        snapshot_rows = [
            dict(row)
            for row in conn.execute(
                """
                SELECT *
                FROM material_snapshots
                WHERE customer_center_id = ?
                  AND snapshot_time = ?
                ORDER BY stat_cost DESC, pay_amount DESC, order_count DESC, material_key ASC
                """,
                (normalized_customer_center_id, latest_snapshot_time),
            ).fetchall()
        ]
        if not snapshot_rows:
            self._replace_material_daily_rows(conn, normalized_customer_center_id, day_key, [])
            self._replace_material_relation_daily_rows(conn, normalized_customer_center_id, day_key, [])
            return {
                "snapshot_time": latest_snapshot_time,
                "material_daily_row_count": 0,
                "material_relation_row_count": 0,
                "material_snapshot_row_count": 0,
            }
        material_keys = sorted(
            {
                str(row.get("material_key") or "").strip()
                for row in snapshot_rows
                if str(row.get("material_key") or "").strip()
            }
        )
        profile_map: dict[str, dict[str, Any]] = {}
        for chunk in self._chunked_material_keys(material_keys):
            placeholders = ",".join("?" for _ in chunk)
            profile_rows = conn.execute(
                f"""
                SELECT
                    material_key,
                    top_plan_name,
                    top_account_name,
                    top_anchor_name,
                    product_info_text,
                    product_names_json,
                    plan_ids_json,
                    advertiser_ids_json,
                    is_original
                FROM material_profile
                WHERE customer_center_id = ?
                  AND material_key IN ({placeholders})
                """,
                [normalized_customer_center_id, *chunk],
            ).fetchall()
            for raw_profile_row in profile_rows:
                profile_row = dict(raw_profile_row)
                profile_key = str(profile_row.get("material_key") or "").strip()
                if profile_key:
                    profile_map[profile_key] = profile_row
        video_origin_rows = conn.execute(
            """
            SELECT advertiser_id, material_id
            FROM video_origin_flags
            WHERE customer_center_id = ?
              AND snapshot_time = ?
              AND is_original = 1
            """,
            (normalized_customer_center_id, latest_snapshot_time),
        ).fetchall()
        original_material_keys = {
            (int(row.get("advertiser_id", 0) or 0), str(row.get("material_id") or "").strip())
            for row in video_origin_rows
            if int(row.get("advertiser_id", 0) or 0) > 0 and str(row.get("material_id") or "").strip()
        }
        material_source_rows: list[dict[str, Any]] = []
        for snapshot_row in snapshot_rows:
            advertiser_id = int(snapshot_row.get("advertiser_id", 0) or 0)
            material_key = str(snapshot_row.get("material_key") or "").strip()
            material_id = str(snapshot_row.get("material_id") or "").strip()
            profile_row = dict(profile_map.get(material_key) or {})
            material_source_rows.append(
                {
                    "snapshot_time": latest_snapshot_time,
                    "window_start": str(snapshot_row.get("window_start") or ""),
                    "window_end": str(snapshot_row.get("window_end") or ""),
                    "advertiser_id": advertiser_id,
                    "advertiser_name": str(snapshot_row.get("advertiser_name") or ""),
                    "ad_id": int(snapshot_row.get("ad_id", 0) or 0),
                    "ad_name": str(snapshot_row.get("ad_name") or ""),
                    "material_type": str(snapshot_row.get("material_type") or ""),
                    "material_key": material_key,
                    "material_id": material_id,
                    "material_name": str(snapshot_row.get("material_name") or ""),
                    "create_time": str(snapshot_row.get("create_time") or ""),
                    "video_id": str(snapshot_row.get("video_id") or ""),
                    "cover_url": str(snapshot_row.get("cover_url") or ""),
                    "aweme_item_id": str(snapshot_row.get("aweme_item_id") or ""),
                    "video_url": str(snapshot_row.get("video_url") or ""),
                    "product_show_count": int(snapshot_row.get("product_show_count", 0) or 0),
                    "product_click_count": int(snapshot_row.get("product_click_count", 0) or 0),
                    "stat_cost": float(snapshot_row.get("stat_cost", 0.0) or 0.0),
                    "pay_amount": float(snapshot_row.get("pay_amount", 0.0) or 0.0),
                    "total_pay_amount": float(snapshot_row.get("total_pay_amount", 0.0) or 0.0),
                    "settled_pay_amount": float(snapshot_row.get("settled_pay_amount", 0.0) or 0.0),
                    "order_count": int(snapshot_row.get("order_count", 0) or 0),
                    "settled_order_count": int(snapshot_row.get("settled_order_count", 0) or 0),
                    "top_plan_name": str(profile_row.get("top_plan_name") or snapshot_row.get("ad_name") or ""),
                    "top_account_name": str(profile_row.get("top_account_name") or snapshot_row.get("advertiser_name") or ""),
                    "top_anchor_name": str(profile_row.get("top_anchor_name") or ""),
                    "product_info_text": str(profile_row.get("product_info_text") or ""),
                    "product_names": self._json_text_list(profile_row.get("product_names_json")),
                    "plan_ids": sorted(self._json_int_set(profile_row.get("plan_ids_json"))),
                    "advertiser_ids": sorted(
                        self._json_int_set(profile_row.get("advertiser_ids_json")) or ({advertiser_id} if advertiser_id > 0 else set())
                    ),
                    "raw_json": str(snapshot_row.get("raw_json") or "{}"),
                    "is_original": (
                        (advertiser_id, material_id) in original_material_keys
                        or bool(profile_row.get("is_original"))
                    ),
                }
            )
        material_source_rows = self._normalize_material_source_rows_to_plan_metrics(
            conn,
            normalized_customer_center_id,
            material_source_rows,
            snapshot_time=latest_snapshot_time,
            use_current=False,
        )
        material_rollup_rows = self._build_material_rollup_rows(
            latest_snapshot_time,
            str(snapshot_rows[0].get("window_start") or ""),
            str(snapshot_rows[0].get("window_end") or ""),
            groups=self._group_material_rows(material_source_rows),
        )
        material_relation_rows = self._build_material_relation_read_rows(
            latest_snapshot_time,
            str(snapshot_rows[0].get("window_start") or ""),
            str(snapshot_rows[0].get("window_end") or ""),
            material_source_rows,
        )
        self._replace_material_daily_rows(conn, normalized_customer_center_id, day_key, material_rollup_rows)
        self._replace_material_relation_daily_rows(conn, normalized_customer_center_id, day_key, material_relation_rows)
        return {
            "snapshot_time": latest_snapshot_time,
            "material_daily_row_count": len(material_rollup_rows),
            "material_relation_row_count": len(material_relation_rows),
            "material_snapshot_row_count": len(snapshot_rows),
        }

    def _replace_material_snapshot_rows(
        self,
        conn: Any,
        customer_center_id: str,
        material_rows: list[tuple[Any, ...]] | list[list[Any]],
        *,
        snapshot_time: str,
        replace_same_day: bool = False,
    ) -> None:
        normalized_snapshot_time = str(snapshot_time or "").strip()
        if not customer_center_id or not normalized_snapshot_time:
            return
        day_key = normalized_snapshot_time[:10]
        if replace_same_day and day_key:
            conn.execute(
                "DELETE FROM material_snapshots WHERE substr(snapshot_time, 1, 10) = ? AND customer_center_id = ?",
                (day_key, customer_center_id),
            )
        else:
            conn.execute(
                "DELETE FROM material_snapshots WHERE snapshot_time = ? AND customer_center_id = ?",
                (normalized_snapshot_time, customer_center_id),
            )
        normalized_rows = self._dedupe_material_snapshot_rows_for_insert(material_rows)
        if not normalized_rows:
            return
        conn.executemany(
            """
            INSERT INTO material_snapshots (
                snapshot_time, customer_center_id, window_start, window_end, advertiser_id, advertiser_name,
                ad_id, ad_name, material_type, material_key, material_id, material_name, create_time,
                video_id, cover_url, aweme_item_id, video_url, product_show_count,
                product_click_count, stat_cost, pay_amount, total_pay_amount, settled_pay_amount,
                order_count, settled_order_count, roi, raw_json
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            [(row[0], customer_center_id, *row[1:]) for row in normalized_rows],
        )

    def _replace_material_snapshot_plan_subset(
        self,
        conn: Any,
        customer_center_id: str,
        biz_date: str,
        ad_ids: set[int] | list[int] | tuple[int, ...],
        material_rows: list[tuple[Any, ...]] | list[list[Any]],
    ) -> int:
        normalized_customer_center_id = str(customer_center_id or "").strip()
        day_key = str(biz_date or "").strip()
        normalized_ad_ids = sorted({int(item or 0) for item in ad_ids if int(item or 0) > 0})
        if not normalized_customer_center_id or not day_key or not normalized_ad_ids:
            return 0
        for start in range(0, len(normalized_ad_ids), 400):
            chunk = normalized_ad_ids[start : start + 400]
            placeholders = ",".join("?" for _ in chunk)
            conn.execute(
                f"""
                DELETE FROM material_snapshots
                WHERE customer_center_id = ?
                  AND substr(snapshot_time, 1, 10) = ?
                  AND ad_id IN ({placeholders})
                """,
                [normalized_customer_center_id, day_key, *chunk],
            )
        normalized_rows = self._dedupe_material_snapshot_rows_for_insert(material_rows)
        if not normalized_rows:
            return 0
        conn.executemany(
            """
            INSERT INTO material_snapshots (
                snapshot_time, customer_center_id, window_start, window_end, advertiser_id, advertiser_name,
                ad_id, ad_name, material_type, material_key, material_id, material_name, create_time,
                video_id, cover_url, aweme_item_id, video_url, product_show_count,
                product_click_count, stat_cost, pay_amount, total_pay_amount, settled_pay_amount,
                order_count, settled_order_count, roi, raw_json
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            [(row[0], normalized_customer_center_id, *row[1:]) for row in normalized_rows],
        )
        return len(normalized_rows)

    def _material_source_rows_from_snapshot_rows(
        self,
        conn: Any,
        customer_center_id: str,
        snapshot_rows: list[dict[str, Any]],
        *,
        biz_date: str = "",
    ) -> list[dict[str, Any]]:
        normalized_customer_center_id = str(customer_center_id or "").strip()
        material_keys = sorted(
            {
                str(row.get("material_key") or "").strip()
                for row in snapshot_rows
                if str(row.get("material_key") or "").strip()
            }
        )
        profile_map: dict[str, dict[str, Any]] = {}
        for chunk in self._chunked_material_keys(material_keys):
            placeholders = ",".join("?" for _ in chunk)
            profile_rows = conn.execute(
                f"""
                SELECT
                    material_key,
                    top_anchor_name,
                    product_info_text,
                    product_names_json,
                    is_original
                FROM material_profile
                WHERE customer_center_id = ?
                  AND material_key IN ({placeholders})
                """,
                [normalized_customer_center_id, *chunk],
            ).fetchall()
            for raw_profile_row in profile_rows:
                profile_row = dict(raw_profile_row)
                profile_key = str(profile_row.get("material_key") or "").strip()
                if profile_key:
                    profile_map[profile_key] = profile_row

        original_material_keys: set[tuple[int, str]] = set()
        day_key = str(biz_date or "").strip()
        if day_key:
            video_origin_rows = conn.execute(
                """
                SELECT advertiser_id, material_id
                FROM video_origin_flags
                WHERE customer_center_id = ?
                  AND substr(snapshot_time, 1, 10) = ?
                  AND is_original = 1
                """,
                (normalized_customer_center_id, day_key),
            ).fetchall()
            original_material_keys = {
                (int(row.get("advertiser_id", 0) or 0), str(row.get("material_id") or "").strip())
                for row in video_origin_rows
                if int(row.get("advertiser_id", 0) or 0) > 0 and str(row.get("material_id") or "").strip()
            }

        material_source_rows: list[dict[str, Any]] = []
        for snapshot_row in snapshot_rows:
            advertiser_id = int(snapshot_row.get("advertiser_id", 0) or 0)
            ad_id = int(snapshot_row.get("ad_id", 0) or 0)
            material_key = str(snapshot_row.get("material_key") or "").strip()
            material_id = str(snapshot_row.get("material_id") or "").strip()
            profile_row = dict(profile_map.get(material_key) or {})
            material_source_rows.append(
                {
                    "snapshot_time": str(snapshot_row.get("snapshot_time") or ""),
                    "window_start": str(snapshot_row.get("window_start") or ""),
                    "window_end": str(snapshot_row.get("window_end") or ""),
                    "advertiser_id": advertiser_id,
                    "advertiser_name": str(snapshot_row.get("advertiser_name") or ""),
                    "ad_id": ad_id,
                    "ad_name": str(snapshot_row.get("ad_name") or ""),
                    "material_type": str(snapshot_row.get("material_type") or ""),
                    "material_key": material_key,
                    "material_id": material_id,
                    "material_name": str(snapshot_row.get("material_name") or ""),
                    "create_time": str(snapshot_row.get("create_time") or ""),
                    "video_id": str(snapshot_row.get("video_id") or ""),
                    "cover_url": str(snapshot_row.get("cover_url") or ""),
                    "aweme_item_id": str(snapshot_row.get("aweme_item_id") or ""),
                    "video_url": str(snapshot_row.get("video_url") or ""),
                    "product_show_count": int(snapshot_row.get("product_show_count", 0) or 0),
                    "product_click_count": int(snapshot_row.get("product_click_count", 0) or 0),
                    "stat_cost": float(snapshot_row.get("stat_cost", 0.0) or 0.0),
                    "pay_amount": float(snapshot_row.get("pay_amount", 0.0) or 0.0),
                    "total_pay_amount": float(snapshot_row.get("total_pay_amount", 0.0) or 0.0),
                    "settled_pay_amount": float(snapshot_row.get("settled_pay_amount", 0.0) or 0.0),
                    "order_count": int(snapshot_row.get("order_count", 0) or 0),
                    "settled_order_count": int(snapshot_row.get("settled_order_count", 0) or 0),
                    "top_anchor_name": str(profile_row.get("top_anchor_name") or ""),
                    "product_info_text": str(profile_row.get("product_info_text") or ""),
                    "product_names": self._json_text_list(profile_row.get("product_names_json")),
                    "plan_ids": [ad_id] if ad_id > 0 else [],
                    "advertiser_ids": [advertiser_id] if advertiser_id > 0 else [],
                    "raw_json": str(snapshot_row.get("raw_json") or "{}"),
                    "is_original": (
                        (advertiser_id, material_id) in original_material_keys
                        or int(profile_row.get("is_original", 0) or 0) == 1
                    ),
                }
            )
        return material_source_rows

    def _restore_material_history_day_from_all_snapshots(
        self,
        conn: Any,
        customer_center_id: str,
        biz_date: str,
    ) -> dict[str, Any]:
        normalized_customer_center_id = str(customer_center_id or "").strip()
        day_key = str(biz_date or "").strip()
        if not normalized_customer_center_id or not day_key:
            return {
                "snapshot_time": "",
                "material_daily_row_count": 0,
                "material_relation_row_count": 0,
                "material_snapshot_row_count": 0,
            }
        ordered_rows = [
            dict(row)
            for row in conn.execute(
                """
                SELECT *
                FROM material_snapshots
                WHERE customer_center_id = ?
                  AND substr(snapshot_time, 1, 10) = ?
                ORDER BY snapshot_time ASC, advertiser_id ASC, ad_id ASC, material_type ASC, material_key ASC
                """,
                (normalized_customer_center_id, day_key),
            ).fetchall()
        ]
        if not ordered_rows:
            self._replace_material_daily_rows(conn, normalized_customer_center_id, day_key, [])
            self._replace_material_relation_daily_rows(conn, normalized_customer_center_id, day_key, [])
            return {
                "snapshot_time": "",
                "material_daily_row_count": 0,
                "material_relation_row_count": 0,
                "material_snapshot_row_count": 0,
            }
        latest_by_relation: dict[tuple[int, int, str, str], dict[str, Any]] = {}
        for row in ordered_rows:
            key = (
                int(row.get("advertiser_id", 0) or 0),
                int(row.get("ad_id", 0) or 0),
                str(row.get("material_type") or "").strip(),
                str(row.get("material_key") or "").strip(),
            )
            if key[0] <= 0 or key[1] <= 0 or not key[2] or not key[3]:
                continue
            latest_by_relation[key] = row
        snapshot_rows = list(latest_by_relation.values())
        if not snapshot_rows:
            self._replace_material_daily_rows(conn, normalized_customer_center_id, day_key, [])
            self._replace_material_relation_daily_rows(conn, normalized_customer_center_id, day_key, [])
            return {
                "snapshot_time": "",
                "material_daily_row_count": 0,
                "material_relation_row_count": 0,
                "material_snapshot_row_count": 0,
            }
        latest_snapshot_time = max(str(row.get("snapshot_time") or "") for row in snapshot_rows)
        latest_row = sorted(
            snapshot_rows,
            key=lambda row: str(row.get("snapshot_time") or ""),
            reverse=True,
        )[0]
        window_start = str(latest_row.get("window_start") or f"{day_key} 00:00:00")
        window_end = str(latest_row.get("window_end") or f"{day_key} 23:59:59")
        material_source_rows = self._material_source_rows_from_snapshot_rows(
            conn,
            normalized_customer_center_id,
            snapshot_rows,
            biz_date=day_key,
        )
        material_source_rows = self._normalize_material_source_rows_to_plan_metrics(
            conn,
            normalized_customer_center_id,
            material_source_rows,
            snapshot_time=latest_snapshot_time,
            use_current=False,
        )
        material_rollup_rows = self._build_material_rollup_rows(
            latest_snapshot_time,
            window_start,
            window_end,
            groups=self._group_material_rows(material_source_rows),
        )
        material_relation_rows = self._build_material_relation_read_rows(
            latest_snapshot_time,
            window_start,
            window_end,
            material_source_rows,
        )
        self._replace_material_daily_rows(conn, normalized_customer_center_id, day_key, material_rollup_rows)
        self._replace_material_relation_daily_rows(conn, normalized_customer_center_id, day_key, material_relation_rows)
        updated_at = now_text()
        self._upsert_material_relation_edges(
            conn,
            normalized_customer_center_id,
            material_source_rows,
            updated_at=updated_at,
            snapshot_time=latest_snapshot_time,
        )
        self._upsert_material_profile_rows(
            conn,
            normalized_customer_center_id,
            material_rollup_rows,
            updated_at=updated_at,
        )
        return {
            "snapshot_time": latest_snapshot_time,
            "material_daily_row_count": len(material_rollup_rows),
            "material_relation_row_count": len(material_relation_rows),
            "material_snapshot_row_count": len(snapshot_rows),
        }

    @staticmethod
    def _invalidate_material_ranking_indexes_for_day(conn: Any, biz_date: str) -> None:
        day_key = str(biz_date or "").strip()
        if not day_key:
            return
        conn.execute(
            "DELETE FROM material_ranking_index WHERE start_date <= ? AND end_date >= ?",
            (day_key, day_key),
        )
        conn.execute(
            "DELETE FROM material_ranking_summary WHERE start_date <= ? AND end_date >= ?",
            (day_key, day_key),
        )

    def _refresh_material_history_for_changed_plans(
        self,
        *,
        client: OceanEngineClient,
        customer_center_id: str,
        target_date: str,
        snapshot_time: str,
        window_start: str,
        window_end: str,
        scoped_config: dict[str, Any],
        changed_plan_ids: set[int] | list[int] | tuple[int, ...],
        changed_plan_rows: list[PlanSummary] | list[dict[str, Any]],
    ) -> dict[str, Any]:
        normalized_plan_ids = sorted({int(item or 0) for item in changed_plan_ids if int(item or 0) > 0})
        if not normalized_plan_ids:
            return {
                "changed_plan_count": 0,
                "material_plan_fetch_count": 0,
                "material_row_count": 0,
                "material_snapshot_row_count": 0,
                "material_daily_row_count": 0,
                "material_relation_row_count": 0,
                "error_count": 0,
                "errors": [],
            }
        plan_context_by_ad_id: dict[int, dict[str, Any]] = {}
        material_candidate_rows: list[dict[str, Any]] = []
        for raw_plan_row in changed_plan_rows:
            plan_row = asdict(raw_plan_row) if isinstance(raw_plan_row, PlanSummary) else dict(raw_plan_row or {})
            ad_id = int(plan_row.get("ad_id", 0) or 0)
            if ad_id <= 0 or ad_id not in normalized_plan_ids:
                continue
            plan_context_by_ad_id[ad_id] = plan_row
            if str(plan_row.get("plan_source") or "").strip().upper() not in {PLAN_SOURCE_UNI_PROMOTION, PLAN_SOURCE_UNI_CUBIC}:
                continue
            if not self._plan_row_has_material_activity(plan_row):
                continue
            material_candidate_rows.append(plan_row)

        errors: list[dict[str, Any]] = []
        material_rows: list[tuple[Any, ...]] = []
        plan_sync_results: list[dict[str, Any]] = []
        material_types = self._detail_material_types(scoped_config)
        workers = self._material_sync_workers(scoped_config)
        request_timeout_seconds = self._material_sync_request_timeout_seconds()
        request_attempts = self._material_sync_request_attempts()
        plan_material_requests_per_minute = self._nightly_plan_material_requests_per_minute_default()
        if plan_material_requests_per_minute > 0:
            client.configure_plan_material_rate_limit(plan_material_requests_per_minute)
        plan_material_batch_size = self._nightly_plan_material_batch_size_default()
        plan_material_batch_sleep_seconds = self._nightly_plan_material_batch_sleep_seconds_default()
        start_date = str(window_start or target_date)[:10]
        end_date = str(window_end or target_date)[:10]
        if material_candidate_rows:
            if plan_material_batch_size > 0:
                plan_batches = [
                    material_candidate_rows[index : index + plan_material_batch_size]
                    for index in range(0, len(material_candidate_rows), plan_material_batch_size)
                ]
            else:
                plan_batches = [material_candidate_rows]
            total_plan_batches = len(plan_batches)
            for batch_index, plan_batch in enumerate(plan_batches, start=1):
                if not plan_batch:
                    continue
                with ThreadPoolExecutor(max_workers=min(workers, len(plan_batch))) as pool:
                    future_map = {
                        pool.submit(
                            self._collect_plan_materials_bundle,
                            client,
                            snapshot_time,
                            window_start,
                            window_end,
                            start_date,
                            end_date,
                            material_types,
                            plan_row,
                            customer_center_id,
                            batch_index,
                            total_plan_batches,
                            request_timeout_seconds,
                            request_attempts,
                            plan_material_requests_per_minute,
                        ): plan_row
                        for plan_row in plan_batch
                    }
                    for future in as_completed(future_map):
                        plan_row = future_map[future]
                        ad_id = int(plan_row.get("ad_id", 0) or 0)
                        plan_error_items: list[dict[str, Any]] = []
                        fetched_rows: list[tuple[Any, ...]] = []
                        try:
                            payload = future.result()
                        except Exception as exc:  # noqa: BLE001
                            plan_error_items.append(
                                self._api_error_payload(
                                    exc,
                                    stage="history_changed_plan_materials",
                                    advertiser_id=int(plan_row.get("advertiser_id", 0) or 0),
                                    ad_id=ad_id,
                                    start_date=start_date,
                                    end_date=end_date,
                                    window_start=window_start,
                                    window_end=window_end,
                                )
                            )
                        else:
                            fetched_rows = list(payload.get("material_rows") or [])
                            material_rows.extend(fetched_rows)
                            plan_error_items.extend(dict(item) for item in (payload.get("errors") or []))
                        errors.extend(plan_error_items)
                        plan_sync_results.append(
                            {
                                "ad_id": ad_id,
                                "advertiser_id": int(plan_row.get("advertiser_id", 0) or 0),
                                "advertiser_name": str(plan_row.get("advertiser_name") or ""),
                                "ad_name": str(plan_row.get("ad_name") or ""),
                                "status": str(plan_row.get("status") or ""),
                                "opt_status": str(plan_row.get("opt_status") or ""),
                                "stat_cost": float(plan_row.get("stat_cost", 0.0) or 0.0),
                                "pay_amount": float(plan_row.get("pay_amount", 0.0) or 0.0),
                                "order_count": int(float(plan_row.get("order_count", 0) or 0)),
                                "material_row_count": len(fetched_rows),
                                "error_items": plan_error_items,
                                "had_errors": bool(plan_error_items),
                                "selected_hot": False,
                                "selected_warm": False,
                                "selected_priority": "history_account_diff",
                            }
                        )
                if plan_material_batch_sleep_seconds > 0 and batch_index < total_plan_batches:
                    time.sleep(plan_material_batch_sleep_seconds)

        if material_rows:
            material_rows, library_errors = self._enrich_material_rows_with_library_create_time(
                client,
                material_rows,
                customer_center_id=customer_center_id,
                apply_preview_media=False,
            )
            errors.extend(library_errors)

        payload = {
            "snapshot_time": snapshot_time,
            "window_start": window_start,
            "window_end": window_end,
            "material_rows": material_rows,
            "video_flag_rows": [],
            "detail_rows": [],
        }
        material_source_rows = self._material_source_rows_from_extended_payload(payload)
        for row in material_source_rows:
            context = plan_context_by_ad_id.get(int(row.get("ad_id", 0) or 0), {})
            if not str(row.get("top_anchor_name") or "").strip():
                row["top_anchor_name"] = str(context.get("anchor_name") or "").strip()
            product_name = str(context.get("product_name") or "").strip()
            if product_name and not str(row.get("product_info_text") or "").strip():
                row["product_info_text"] = product_name
            if product_name and not row.get("product_names"):
                row["product_names"] = [product_name]
        with self.db() as conn:
            if material_source_rows:
                material_source_rows = self._normalize_material_source_rows_to_plan_metrics(
                    conn,
                    customer_center_id,
                    material_source_rows,
                    snapshot_time=snapshot_time,
                    use_current=False,
                )
            material_snapshot_rows = [
                self._material_snapshot_tuple_from_source_row(row)
                for row in material_source_rows
            ]
            inserted_snapshot_rows = self._replace_material_snapshot_plan_subset(
                conn,
                customer_center_id,
                target_date,
                normalized_plan_ids,
                material_snapshot_rows,
            )
            if material_source_rows:
                updated_at = now_text()
                material_rollup_rows = self._build_material_rollup_rows(
                    snapshot_time,
                    window_start,
                    window_end,
                    groups=self._group_material_rows(material_source_rows),
                )
                self._upsert_material_relation_edges(
                    conn,
                    customer_center_id,
                    material_source_rows,
                    updated_at=updated_at,
                    snapshot_time=snapshot_time,
                )
                self._upsert_material_profile_rows(
                    conn,
                    customer_center_id,
                    material_rollup_rows,
                    updated_at=updated_at,
                )
            rebuild_result = self._restore_material_history_day_from_latest_snapshot(
                conn,
                customer_center_id,
                target_date,
            )
            if not str(rebuild_result.get("snapshot_time") or "").strip():
                rebuild_result = self._restore_material_history_day_from_all_snapshots(
                    conn,
                    customer_center_id,
                    target_date,
                )
            self._invalidate_material_ranking_indexes_for_day(conn, target_date)
            self._persist_plan_refresh_states(conn, customer_center_id, plan_sync_results)
        return {
            "changed_plan_count": len(normalized_plan_ids),
            "material_plan_fetch_count": len(material_candidate_rows),
            "material_row_count": len(material_rows),
            "material_snapshot_row_count": inserted_snapshot_rows,
            "material_daily_row_count": int(rebuild_result.get("material_daily_row_count", 0) or 0),
            "material_relation_row_count": int(rebuild_result.get("material_relation_row_count", 0) or 0),
            "error_count": len(errors),
            "errors": errors,
        }

    def _material_history_day_row_counts(
        self,
        conn: Any,
        customer_center_id: str,
        biz_date: str,
    ) -> dict[str, int]:
        normalized_customer_center_id = str(customer_center_id or "").strip()
        day_key = str(biz_date or "").strip()
        if not normalized_customer_center_id or not day_key:
            return {
                "material_daily_row_count": 0,
                "material_relation_row_count": 0,
                "material_snapshot_row_count": 0,
            }
        material_daily_row = conn.execute(
            """
            SELECT COUNT(*) AS row_count
            FROM material_daily
            WHERE customer_center_id = ?
              AND biz_date = ?
            """,
            (normalized_customer_center_id, day_key),
        ).fetchone()
        material_relation_row = conn.execute(
            """
            SELECT COUNT(*) AS row_count
            FROM material_relation_daily
            WHERE customer_center_id = ?
              AND biz_date = ?
            """,
            (normalized_customer_center_id, day_key),
        ).fetchone()
        material_snapshot_row = conn.execute(
            """
            SELECT COUNT(*) AS row_count
            FROM material_snapshots
            WHERE customer_center_id = ?
              AND substr(snapshot_time, 1, 10) = ?
            """,
            (normalized_customer_center_id, day_key),
        ).fetchone()
        return {
            "material_daily_row_count": int((material_daily_row or {}).get("row_count") or 0),
            "material_relation_row_count": int((material_relation_row or {}).get("row_count") or 0),
            "material_snapshot_row_count": int((material_snapshot_row or {}).get("row_count") or 0),
        }

    def _should_replace_material_history_day(
        self,
        existing_counts: dict[str, int],
        new_counts: dict[str, int],
        error_items: list[dict[str, Any]] | None = None,
    ) -> tuple[bool, str]:
        existing_daily = max(int(existing_counts.get("material_daily_row_count", 0) or 0), 0)
        existing_relation = max(int(existing_counts.get("material_relation_row_count", 0) or 0), 0)
        existing_snapshot = max(int(existing_counts.get("material_snapshot_row_count", 0) or 0), 0)
        new_daily = max(int(new_counts.get("material_daily_row_count", 0) or 0), 0)
        new_relation = max(int(new_counts.get("material_relation_row_count", 0) or 0), 0)
        new_snapshot = max(int(new_counts.get("material_snapshot_row_count", 0) or 0), 0)
        existing_has_rows = any((existing_daily, existing_relation, existing_snapshot))
        new_has_rows = any((new_daily, new_relation, new_snapshot))
        regresses = (
            new_daily < existing_daily
            or new_relation < existing_relation
            or new_snapshot < existing_snapshot
        )
        improves = (
            new_daily > existing_daily
            or new_relation > existing_relation
            or new_snapshot > existing_snapshot
        )
        errors = [dict(item) for item in (error_items or []) if isinstance(item, dict)]
        blocking_errors = [
            item
            for item in errors
            if not str(item.get("stage") or "").strip().startswith("material_library_")
        ]
        if existing_has_rows and not new_has_rows:
            return False, "empty_replacement_blocked"
        if regresses:
            return False, "smaller_replacement_blocked"
        if not blocking_errors:
            return True, "complete_refresh"
        if any(not bool(item.get("retryable")) for item in blocking_errors):
            return False, "nonretryable_error_blocked"
        if improves or not existing_has_rows:
            return True, "retryable_partial_refresh_improved"
        return False, "retryable_partial_refresh_not_improved"

    def _dedupe_material_snapshot_rows_for_insert(
        self,
        material_rows: list[tuple[Any, ...]] | list[list[Any]],
    ) -> list[tuple[Any, ...]]:
        if not material_rows:
            return []
        deduped_rows: dict[tuple[str, int, int, str, str], list[Any]] = {}
        for raw_row in material_rows:
            row = list(raw_row)
            snapshot_time = str(row[0] or "").strip()
            advertiser_id = int(row[3] or 0)
            ad_id = int(row[5] or 0)
            material_type = str(row[7] or "").strip()
            material_key = str(row[8] or "").strip()
            key = (snapshot_time, advertiser_id, ad_id, material_type, material_key)
            bucket = deduped_rows.get(key)
            if bucket is None:
                deduped_rows[key] = row
                continue
            if not str(bucket[4] or "").strip():
                bucket[4] = str(row[4] or "").strip()
            if not str(bucket[6] or "").strip():
                bucket[6] = str(row[6] or "").strip()
            if not str(bucket[9] or "").strip():
                bucket[9] = str(row[9] or "").strip()
            if not str(bucket[10] or "").strip():
                bucket[10] = str(row[10] or "").strip()
            row_create_time = self._normalize_datetime_text(row[11])
            bucket_create_time = self._normalize_datetime_text(bucket[11])
            if row_create_time and (not bucket_create_time or row_create_time < bucket_create_time):
                bucket[11] = row_create_time
            if not str(bucket[12] or "").strip():
                bucket[12] = str(row[12] or "").strip()
            if self._should_prefer_cover_url(
                self._normalize_media_url(row[13]),
                self._normalize_media_url(bucket[13]),
            ):
                bucket[13] = str(row[13] or "").strip()
            if not str(bucket[14] or "").strip():
                bucket[14] = str(row[14] or "").strip()
            candidate_video_url = self._normalize_media_url(row[15])
            current_video_url = self._normalize_media_url(bucket[15])
            if candidate_video_url and (
                not current_video_url
                or (
                    self._is_public_preview_video_url(candidate_video_url)
                    and not self._is_public_preview_video_url(current_video_url)
                )
            ):
                bucket[15] = candidate_video_url
            bucket[16] = int(bucket[16] or 0) + int(row[16] or 0)
            bucket[17] = int(bucket[17] or 0) + int(row[17] or 0)
            bucket[18] = round(float(bucket[18] or 0.0) + float(row[18] or 0.0), 2)
            bucket[19] = round(float(bucket[19] or 0.0) + float(row[19] or 0.0), 2)
            bucket[20] = round(float(bucket[20] or 0.0) + float(row[20] or 0.0), 2)
            bucket[21] = round(float(bucket[21] or 0.0) + float(row[21] or 0.0), 2)
            bucket[22] = int(bucket[22] or 0) + int(row[22] or 0)
            bucket[23] = int(bucket[23] or 0) + int(row[23] or 0)
            bucket[24] = round(float(bucket[19] or 0.0) / float(bucket[18] or 0.0), 2) if float(bucket[18] or 0.0) > 0 else 0.0
            if not str(bucket[25] or "").strip():
                bucket[25] = str(row[25] or "{}")
        return [tuple(row) for row in deduped_rows.values()]

    def _merge_material_daily_rows(
        self,
        conn: Any,
        customer_center_id: str,
        biz_date: str,
        *,
        snapshot_time: str,
        window_start: str,
        window_end: str,
        material_rollup_rows: list[tuple[Any, ...]],
    ) -> list[tuple[Any, ...]]:
        existing_rows = [
            dict(row)
            for row in conn.execute(
                """
                SELECT *
                FROM material_daily
                WHERE customer_center_id = ?
                  AND biz_date = ?
                ORDER BY stat_cost DESC, material_key ASC
                """,
                (customer_center_id, biz_date),
            ).fetchall()
        ]
        incoming_rows = [
            self._material_rollup_record_from_tuple(row)
            for row in material_rollup_rows
        ]
        merged_rows = self._aggregate_material_rollups([*existing_rows, *incoming_rows])
        merged_rollup_rows: list[tuple[Any, ...]] = []
        for row in merged_rows:
            row["snapshot_time"] = str(snapshot_time or row.get("snapshot_time") or "")
            row["window_start"] = str(window_start or row.get("window_start") or "")
            row["window_end"] = str(window_end or row.get("window_end") or "")
            merged_rollup_rows.append(self._material_rollup_tuple_from_record(row))
        self._replace_material_daily_rows(conn, customer_center_id, biz_date, merged_rollup_rows)
        return merged_rollup_rows

    def _persist_plan_refresh_states(
        self,
        conn: Any,
        customer_center_id: str,
        plan_sync_results: list[dict[str, Any]],
    ) -> None:
        normalized_results = [
            dict(item)
            for item in (plan_sync_results or [])
            if int(item.get("ad_id", 0) or 0) > 0
        ]
        if not normalized_results:
            return
        existing_state_map = self._plan_refresh_state_map(
            conn,
            customer_center_id,
            {int(item.get("ad_id", 0) or 0) for item in normalized_results},
        )
        synced_at = now_text()
        runtime_config = self.read_config()
        next_cold_due_at = self._material_sync_next_cold_due_at(synced_at, runtime_config)
        upsert_rows: list[tuple[Any, ...]] = []
        for item in normalized_results:
            ad_id = int(item.get("ad_id", 0) or 0)
            previous = dict(existing_state_map.get(ad_id) or {})
            error_items = [dict(error) for error in (item.get("error_items") or []) if isinstance(error, dict)]
            had_errors = bool(item.get("had_errors")) or bool(error_items)
            selected_hot = bool(item.get("selected_hot"))
            selected_warm = bool(item.get("selected_warm"))
            stat_cost = float(item.get("stat_cost", 0.0) or 0.0)
            pay_amount = float(item.get("pay_amount", 0.0) or 0.0)
            order_count = int(float(item.get("order_count", 0) or 0))
            material_row_count = int(item.get("material_row_count", 0) or 0)

            last_hot_sync_at = str(previous.get("last_hot_sync_at") or "").strip()
            last_warm_sync_at = str(previous.get("last_warm_sync_at") or "").strip()
            last_cold_sync_at = str(previous.get("last_cold_sync_at") or "").strip()
            last_material_sync_at = str(previous.get("last_material_sync_at") or "").strip()
            current_next_cold_due_at = str(previous.get("next_cold_due_at") or "").strip()
            last_material_change_at = str(previous.get("last_material_change_at") or "").strip()
            last_status_change_at = str(previous.get("last_status_change_at") or "").strip()
            if previous and (
                str(previous.get("status") or "").strip() != str(item.get("status") or "").strip()
                or str(previous.get("opt_status") or "").strip() != str(item.get("opt_status") or "").strip()
            ):
                last_status_change_at = synced_at

            last_nonzero_perf_at = str(previous.get("last_nonzero_perf_at") or "").strip()
            if stat_cost > 0.0 or pay_amount > 0.0 or order_count > 0:
                last_nonzero_perf_at = synced_at

            last_material_error_at = str(previous.get("last_material_error_at") or "").strip()
            last_material_error_code = int(previous.get("last_material_error_code", 0) or 0)
            last_material_error_message = str(previous.get("last_material_error_message") or "").strip()
            last_material_error_retryable = int(previous.get("last_material_error_retryable", 0) or 0)
            consecutive_material_error_count = int(previous.get("consecutive_material_error_count", 0) or 0)
            next_material_retry_at = str(previous.get("next_material_retry_at") or "").strip()
            last_material_row_count = int(previous.get("last_material_row_count", 0) or 0)
            sync_priority = str(item.get("selected_priority") or "cold").strip() or "cold"

            if not had_errors:
                if selected_hot:
                    last_hot_sync_at = synced_at
                elif selected_warm:
                    last_warm_sync_at = synced_at
                else:
                    last_cold_sync_at = synced_at
                last_material_sync_at = synced_at
                current_next_cold_due_at = next_cold_due_at
                if previous and int(previous.get("last_material_row_count", 0) or 0) != material_row_count:
                    last_material_change_at = synced_at
                last_material_error_at = ""
                last_material_error_code = 0
                last_material_error_message = ""
                last_material_error_retryable = 0
                consecutive_material_error_count = 0
                next_material_retry_at = ""
                last_material_row_count = material_row_count
            else:
                primary_error = error_items[0] if error_items else {}
                retryable_error = any(bool(error.get("retryable")) for error in error_items)
                consecutive_material_error_count = max(consecutive_material_error_count, 0) + 1
                last_material_error_at = synced_at
                last_material_error_code = int(primary_error.get("code", 0) or 0)
                last_material_error_message = str(primary_error.get("message") or primary_error.get("error") or "").strip()
                last_material_error_retryable = 1 if retryable_error else 0
                next_material_retry_at = self._next_material_retry_at_for_error(
                    synced_at,
                    runtime_config,
                    consecutive_error_count=consecutive_material_error_count,
                    retryable=retryable_error,
                )
                sync_priority = "error_backoff"

            upsert_rows.append(
                (
                    customer_center_id,
                    ad_id,
                    int(item.get("advertiser_id", 0) or 0),
                    str(item.get("advertiser_name") or "").strip(),
                    str(item.get("ad_name") or "").strip(),
                    str(item.get("status") or "").strip(),
                    str(item.get("opt_status") or "").strip(),
                    last_hot_sync_at,
                    last_warm_sync_at,
                    last_cold_sync_at,
                    current_next_cold_due_at,
                    last_material_sync_at,
                    last_material_change_at,
                    last_status_change_at,
                    last_nonzero_perf_at,
                    last_material_error_at,
                    last_material_error_code,
                    last_material_error_message,
                    last_material_error_retryable,
                    consecutive_material_error_count,
                    next_material_retry_at,
                    last_material_row_count,
                    sync_priority,
                    synced_at,
                )
            )

        conn.executemany(
            """
            INSERT INTO plan_refresh_states (
                customer_center_id,
                ad_id,
                advertiser_id,
                advertiser_name,
                ad_name,
                status,
                opt_status,
                last_hot_sync_at,
                last_warm_sync_at,
                last_cold_sync_at,
                next_cold_due_at,
                last_material_sync_at,
                last_material_change_at,
                last_status_change_at,
                last_nonzero_perf_at,
                last_material_error_at,
                last_material_error_code,
                last_material_error_message,
                last_material_error_retryable,
                consecutive_material_error_count,
                next_material_retry_at,
                last_material_row_count,
                sync_priority,
                updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT (customer_center_id, ad_id) DO UPDATE SET
                advertiser_id = excluded.advertiser_id,
                advertiser_name = excluded.advertiser_name,
                ad_name = excluded.ad_name,
                status = excluded.status,
                opt_status = excluded.opt_status,
                last_hot_sync_at = excluded.last_hot_sync_at,
                last_warm_sync_at = excluded.last_warm_sync_at,
                last_cold_sync_at = excluded.last_cold_sync_at,
                next_cold_due_at = excluded.next_cold_due_at,
                last_material_sync_at = excluded.last_material_sync_at,
                last_material_change_at = excluded.last_material_change_at,
                last_status_change_at = excluded.last_status_change_at,
                last_nonzero_perf_at = excluded.last_nonzero_perf_at,
                last_material_error_at = excluded.last_material_error_at,
                last_material_error_code = excluded.last_material_error_code,
                last_material_error_message = excluded.last_material_error_message,
                last_material_error_retryable = excluded.last_material_error_retryable,
                consecutive_material_error_count = excluded.consecutive_material_error_count,
                next_material_retry_at = excluded.next_material_retry_at,
                last_material_row_count = excluded.last_material_row_count,
                sync_priority = excluded.sync_priority,
                updated_at = excluded.updated_at
            """,
            upsert_rows,
        )

    @staticmethod
    def _chunked_material_keys(material_keys: list[str], size: int = 400) -> list[list[str]]:
        items = [str(item or "").strip() for item in material_keys if str(item or "").strip()]
        return [items[index : index + size] for index in range(0, len(items), size)]

    @staticmethod
    def _empty_material_preview_fields() -> dict[str, str]:
        return {
            "video_id": "",
            "cover_url": "",
            "aweme_item_id": "",
            "video_url": "",
        }

    @classmethod
    def _merge_material_preview_fields(cls, target: dict[str, str], row: dict[str, Any]) -> None:
        for field in ("video_id", "cover_url", "aweme_item_id", "video_url"):
            if target.get(field):
                continue
            text = str(row.get(field) or "").strip()
            if text:
                target[field] = text

    @staticmethod
    def _material_preview_available(preview: dict[str, str]) -> bool:
        return any(
            str(preview.get(field) or "").strip()
            for field in ("cover_url", "aweme_item_id", "video_url")
        )

    def _latest_material_preview_map(self, conn: Any, material_keys: list[str]) -> dict[str, dict[str, str]]:
        requested_keys = {str(item or "").strip() for item in material_keys if str(item or "").strip()}
        if not requested_keys:
            return {}
        preview_map: dict[str, dict[str, str]] = {}
        for table_name in ("material_rollups", "material_snapshots"):
            for batch in self._chunked_material_keys(sorted(requested_keys), 400):
                placeholders = ",".join("?" for _ in batch)
                rows = conn.execute(
                    f"""
                    SELECT material_key, video_id, cover_url, aweme_item_id, video_url
                    FROM {table_name}
                    WHERE snapshot_time = (SELECT MAX(snapshot_time) FROM {table_name})
                      AND material_key IN ({placeholders})
                    ORDER BY material_key ASC
                    """,
                    batch,
                ).fetchall()
                for raw_row in rows:
                    row = dict(raw_row)
                    material_key = str(row.get("material_key") or "").strip()
                    if not material_key:
                        continue
                    preview = preview_map.setdefault(material_key, self._empty_material_preview_fields())
                    self._merge_material_preview_fields(preview, row)
        return {
            key: value
            for key, value in preview_map.items()
            if self._material_preview_available(value) or str(value.get("video_id") or "").strip()
        }

    def _apply_latest_material_previews(self, conn: Any, items: list[dict[str, Any]]) -> list[dict[str, Any]]:
        if not items:
            return items
        preview_map = self._latest_material_preview_map(
            conn,
            [str(item.get("material_key") or "").strip() for item in items],
        )
        if not preview_map:
            return items
        for item in items:
            preview = preview_map.get(str(item.get("material_key") or "").strip())
            if not preview:
                continue
            for field in ("video_id", "cover_url", "aweme_item_id", "video_url"):
                text = str(preview.get(field) or "").strip()
                if text:
                    item[field] = text
        return items

    def _sanitize_material_preview_fields_for_payload(self, items: list[dict[str, Any]]) -> list[dict[str, Any]]:
        if not items:
            return items
        sanitized_items: list[dict[str, Any]] = []
        for raw_item in items:
            item = dict(raw_item)
            cover_url = self._normalize_media_url(item.get("cover_url"))
            video_url = self._normalize_media_url(item.get("video_url"))
            item["cover_url"] = self._coerce_public_preview_cover_url(cover_url)
            item["video_url"] = (
                video_url
                if self._is_public_preview_video_url(video_url) and not self._needs_preview_video_redirect_resolution(video_url)
                else ""
            )
            item["preview_available"] = bool(
                item["cover_url"]
                or item["video_url"]
                or str(item.get("aweme_item_id") or "").strip()
                or str(item.get("video_id") or "").strip()
                or str(item.get("material_id") or "").strip()
                or str(item.get("material_key") or "").strip()
            )
            sanitized_items.append(item)
        return sanitized_items

    @staticmethod
    def _preview_url_expires_at(url: str) -> int:
        text = str(url or "").strip()
        if not text:
            return 0
        try:
            query = parse_qs(urlsplit(text).query)
        except ValueError:
            return 0
        values = query.get("x-expires") or query.get("expires") or []
        if not values:
            return 0
        raw_value = str(values[0] or "").strip()
        return int(raw_value) if raw_value.isdigit() else 0

    @classmethod
    def _preview_url_needs_refresh(cls, url: str, *, leeway_seconds: int = 300) -> bool:
        text = str(url or "").strip()
        if not text:
            return True
        expires_at = cls._preview_url_expires_at(text)
        if expires_at <= 0:
            return False
        return expires_at <= int(time.time()) + max(leeway_seconds, 0)

    @staticmethod
    def _normalize_media_url(url: Any) -> str:
        text = str(url or "").strip()
        if text.startswith("//"):
            return f"https:{text}"
        return text

    @classmethod
    def _coerce_public_preview_cover_url(cls, url: Any) -> str:
        text = cls._normalize_media_url(url)
        if not text:
            return ""
        return text if cls._is_public_preview_cover_url(text) else ""

    @classmethod
    def _is_temporary_signed_cover_url(cls, url: Any) -> bool:
        text = cls._normalize_media_url(url)
        if not text:
            return False
        try:
            parsed = urlsplit(text)
        except ValueError:
            return False
        host = str(parsed.netloc or "").strip().lower()
        return host.endswith("creativityeco.com") and cls._preview_url_expires_at(text) > 0

    @classmethod
    def _should_prefer_cover_url(cls, candidate_url: Any, current_url: Any) -> bool:
        candidate = cls._normalize_media_url(candidate_url)
        if not cls._is_public_preview_cover_url(candidate):
            return False
        current = cls._normalize_media_url(current_url)
        if not current:
            return True
        if cls._is_temporary_signed_cover_url(current) and not cls._is_temporary_signed_cover_url(candidate):
            return True
        if cls._preview_url_needs_refresh(current, leeway_seconds=0) and not cls._preview_url_needs_refresh(
            candidate,
            leeway_seconds=0,
        ):
            return True
        return cls._is_public_preview_cover_url(candidate) and not cls._is_public_preview_cover_url(current)

    @staticmethod
    def _preview_proxy_signature(target_url: str, expires_at: int) -> str:
        payload = f"{int(expires_at)}:{str(target_url or '').strip()}".encode("utf-8")
        return hmac.new(str(SESSION_SECRET or "preview-proxy").encode("utf-8"), payload, hashlib.sha256).hexdigest()

    @classmethod
    def _preview_proxy_allowed(cls, target_url: Any) -> bool:
        text = cls._normalize_media_url(target_url)
        if not text:
            return False
        if cls._needs_preview_video_redirect_resolution(text):
            return True
        if cls._is_internal_preview_video_url(text):
            return bool(ALLOW_INTERNAL_PREVIEW_PROXY)
        return False

    def build_material_preview_proxy_url(self, target_url: Any, expires_in_seconds: int = 3600) -> str:
        normalized_url = self._normalize_media_url(target_url)
        if not normalized_url:
            return ""
        if self._needs_preview_video_redirect_resolution(normalized_url):
            resolved_url = self._resolve_preview_video_url(normalized_url, timeout=10)
            if self._is_public_preview_video_url(resolved_url):
                return resolved_url
            return ""
        if self._preview_url_needs_refresh(normalized_url, leeway_seconds=60):
            return ""
        if not self._preview_proxy_allowed(normalized_url):
            return ""
        expires_at = int(time.time()) + max(int(expires_in_seconds or 0), 60)
        signature = self._preview_proxy_signature(normalized_url, expires_at)
        encoded_target = quote(normalized_url, safe="")
        return f"/api/material-preview-stream?target={encoded_target}&expires={expires_at}&sig={signature}"

    def resolve_material_preview_proxy_target(self, target: str, expires: int, sig: str) -> str:
        normalized_target = self._normalize_media_url(unquote(str(target or "").strip()))
        if not normalized_target or not self._preview_proxy_allowed(normalized_target):
            raise ValueError("preview proxy target is not allowed")
        expires_at = int(expires or 0)
        if expires_at <= int(time.time()):
            raise ValueError("preview proxy url expired")
        expected_sig = self._preview_proxy_signature(normalized_target, expires_at)
        if not secrets.compare_digest(str(sig or "").strip(), expected_sig):
            raise ValueError("preview proxy signature invalid")
        return normalized_target

    def _merge_material_preview_seed_row(
        self,
        resolved_row: dict[str, Any] | None,
        seed_row: dict[str, Any] | None,
    ) -> dict[str, Any]:
        merged_row = dict(resolved_row or {})
        seed_payload = dict(seed_row or {})
        for key, value in seed_payload.items():
            if key not in merged_row or merged_row.get(key) in (None, ""):
                merged_row[key] = value

        seed_cover_url = self._normalize_media_url(seed_payload.get("cover_url"))
        merged_cover_url = self._normalize_media_url(merged_row.get("cover_url"))
        if self._should_prefer_cover_url(seed_cover_url, merged_cover_url):
            merged_row["cover_url"] = seed_cover_url

        seed_video_url = self._normalize_media_url(seed_payload.get("video_url"))
        merged_video_url = self._normalize_media_url(merged_row.get("video_url"))
        if self._is_public_preview_video_url(seed_video_url) and not self._is_public_preview_video_url(merged_video_url):
            merged_row["video_url"] = seed_video_url
        return merged_row

    def _should_defer_material_preview_proxy(self, video_url: Any) -> bool:
        normalized_url = self._normalize_media_url(video_url)
        if not normalized_url:
            return False
        return (
            self._needs_preview_video_redirect_resolution(normalized_url)
            or self._is_internal_preview_video_url(normalized_url)
        )

    @classmethod
    def _is_internal_preview_video_url(cls, url: Any) -> bool:
        text = cls._normalize_media_url(url)
        if not text:
            return False
        try:
            parsed = urlsplit(text)
        except ValueError:
            return False
        host = str(parsed.netloc or "").strip().lower()
        return host in {"localhost", "127.0.0.1"} or host.endswith(".local")

    @classmethod
    def _is_public_preview_cover_url(cls, url: Any) -> bool:
        text = cls._normalize_media_url(url)
        if not text:
            return False
        try:
            parsed = urlsplit(text)
        except ValueError:
            return False
        host = str(parsed.netloc or "").strip().lower()
        if parsed.scheme not in {"http", "https"} or not host:
            return False
        if host.endswith("creativityeco.com"):
            # Signed creativityeco cover URLs are browser-accessible; only reject
            # them when they are already expired and need refresh first.
            return not cls._preview_url_needs_refresh(text, leeway_seconds=0)
        return True

    @classmethod
    def _is_public_preview_video_url(cls, url: Any) -> bool:
        text = cls._normalize_media_url(url)
        if not text:
            return False
        try:
            parsed = urlsplit(text)
        except ValueError:
            return False
        host = str(parsed.netloc or "").strip().lower()
        if parsed.scheme not in {"http", "https"} or not host:
            return False
        if cls._is_internal_preview_video_url(text):
            return False
        # cc.oceanengine.com is only a platform preview address, not a direct public file.
        return not host.endswith("cc.oceanengine.com")

    @classmethod
    def _needs_preview_video_redirect_resolution(cls, url: Any) -> bool:
        text = cls._normalize_media_url(url)
        if not text:
            return False
        try:
            parsed = urlsplit(text)
        except ValueError:
            return False
        host = str(parsed.netloc or "").strip().lower()
        return host.endswith("cc.oceanengine.com")

    @classmethod
    def _preferred_video_url_from_values(cls, *values: Any) -> str:
        candidates: list[str] = []
        seen: set[str] = set()
        for value in values:
            if isinstance(value, (list, tuple, set)):
                nested = list(value)
            else:
                nested = [value]
            for item in nested:
                text = cls._normalize_media_url(item)
                if not text or text in seen:
                    continue
                seen.add(text)
                candidates.append(text)
        for text in candidates:
            if cls._is_public_preview_video_url(text):
                return text
        return candidates[0] if candidates else ""

    def _resolve_preview_video_url(self, url: Any, *, timeout: int = 20) -> str:
        text = self._normalize_media_url(url)
        if not text:
            return ""
        if not self._needs_preview_video_redirect_resolution(text):
            return text
        now_ts = time.time()
        cached = self._preview_video_resolve_cache.get(text)
        if cached and now_ts - float(cached.get("_cached_at", 0.0)) < PREVIEW_VIDEO_RESOLVE_CACHE_SECONDS:
            cached_url = self._normalize_media_url(cached.get("resolved_url"))
            if cached_url and not self._preview_url_needs_refresh(cached_url, leeway_seconds=60):
                return cached_url
        request = urllib.request.Request(
            text,
            headers={
                "User-Agent": "Mozilla/5.0",
                "Range": "bytes=0-0",
            },
            method="GET",
        )
        try:
            with urllib.request.urlopen(request, timeout=timeout) as response:
                resolved_url = self._normalize_media_url(response.geturl())
                content_type = str(response.headers.get("Content-Type") or "").strip().lower()
                response.read(1)
        except (urllib.error.HTTPError, urllib.error.URLError, TimeoutError, ValueError, OSError):
            return text
        if not resolved_url or not self._is_public_preview_video_url(resolved_url):
            return text
        if content_type and not content_type.startswith("video/"):
            return text
        self._preview_video_resolve_cache[text] = {
            "_cached_at": now_ts,
            "resolved_url": resolved_url,
        }
        return resolved_url

    @classmethod
    def _video_url_candidates_from_payload(cls, payload: Any) -> list[str]:
        if not isinstance(payload, dict):
            return []
        values: list[Any] = []
        for key in (
            "video_url",
            "videoUrl",
            "url",
            "play_url",
            "playUrl",
            "download_url",
            "downloadUrl",
            "download_url_https",
            "downloadUrlHttps",
            "material_url",
            "materialUrl",
            "origin_url",
            "originUrl",
            "file_url",
            "fileUrl",
        ):
            if payload.get(key) not in (None, ""):
                values.append(payload.get(key))
        return [text for text in [cls._preferred_video_url_from_values(values)] if text]

    @staticmethod
    def _material_preview_refresh_cache_key(
        customer_center_id: str,
        advertiser_id: int,
        ad_id: int,
        material_type: str,
    ) -> str:
        return ":".join(
            [
                str(customer_center_id or "").strip(),
                str(int(advertiser_id or 0)),
                str(int(ad_id or 0)),
                str(material_type or "").strip().upper(),
            ]
        )

    def _plan_material_rows_for_preview_refresh(
        self,
        customer_center_id: str,
        advertiser_id: int,
        ad_id: int,
        material_type: str,
    ) -> list[dict[str, Any]]:
        cache_key = self._material_preview_refresh_cache_key(customer_center_id, advertiser_id, ad_id, material_type)
        now_ts = time.time()
        cached = self._material_preview_refresh_cache.get(cache_key)
        if cached and now_ts - float(cached.get("_cached_at", 0.0)) < MATERIAL_PREVIEW_REFRESH_CACHE_SECONDS:
            return [dict(row) for row in cached.get("rows", [])]
        client = self._build_scoped_customer_center_client(customer_center_id)
        rows = client.list_plan_materials(
            int(advertiser_id),
            int(ad_id),
            {"material_type": str(material_type or "").strip().upper()},
        )
        normalized_rows = [dict(row) for row in rows if isinstance(row, dict)]
        self._material_preview_refresh_cache[cache_key] = {
            "_cached_at": now_ts,
            "rows": normalized_rows,
        }
        return [dict(row) for row in normalized_rows]

    @classmethod
    def _material_preview_candidate_indexes(
        cls,
        rows: list[dict[str, Any]],
        material_type: str,
    ) -> dict[str, dict[str, dict[str, Any]]]:
        indexes = {
            "material_id": {},
            "material_key": {},
            "video_id": {},
            "aweme_item_id": {},
        }
        for row in rows:
            if not isinstance(row, dict):
                continue
            raw_material_info = cls._json_object(row.get("material_info"))
            resolved_material_type = str(
                row.get("material_type")
                or raw_material_info.get("material_type")
                or material_type
                or "VIDEO"
            ).strip().upper()
            identity = cls._extract_material_identity(resolved_material_type, row)
            preview = cls._extract_material_preview(resolved_material_type, row)
            if not cls._material_preview_available(preview):
                continue
            candidate = {
                "material_type": resolved_material_type,
                "identity": identity,
                "preview": preview,
            }
            material_id = cls._numeric_material_id_text(identity.get("material_id"))
            if material_id and material_id not in indexes["material_id"]:
                indexes["material_id"][material_id] = candidate
            material_key = str(identity.get("material_key") or "").strip()
            if material_key and material_key not in indexes["material_key"]:
                indexes["material_key"][material_key] = candidate
            video_id = str(identity.get("video_id") or "").strip()
            if video_id and video_id not in indexes["video_id"]:
                indexes["video_id"][video_id] = candidate
            aweme_item_id = str(preview.get("aweme_item_id") or "").strip()
            if aweme_item_id and aweme_item_id not in indexes["aweme_item_id"]:
                indexes["aweme_item_id"][aweme_item_id] = candidate
        return indexes

    @classmethod
    def _match_refreshed_material_preview(
        cls,
        item: dict[str, Any],
        source: dict[str, Any],
        indexes: dict[str, dict[str, dict[str, Any]]],
    ) -> dict[str, Any] | None:
        material_id = cls._numeric_material_id_text(source.get("material_id"), item.get("material_id"))
        if material_id:
            candidate = indexes["material_id"].get(material_id)
            if candidate:
                return candidate
        video_id = cls._first_text(source.get("video_id"), item.get("video_id"))
        if video_id:
            candidate = indexes["video_id"].get(video_id)
            if candidate:
                return candidate
        aweme_item_id = cls._first_text(source.get("aweme_item_id"), item.get("aweme_item_id"))
        if aweme_item_id:
            candidate = indexes["aweme_item_id"].get(aweme_item_id)
            if candidate:
                return candidate
        material_key = cls._first_text(source.get("material_key"), item.get("material_key"))
        if material_key:
            return indexes["material_key"].get(material_key)
        return None

    def _refresh_stale_material_previews(
        self,
        items: list[dict[str, Any]],
        start_date: str,
        end_date: str,
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        *,
        search_all_customer_centers: bool = False,
    ) -> list[dict[str, Any]]:
        if not items:
            return items
        refresh_targets: dict[tuple[str, int, int, str], list[tuple[dict[str, Any], dict[str, Any]]]] = {}
        current_customer_center_id = self._current_customer_center_id()
        for item in items:
            material_type = str(item.get("material_type") or "VIDEO").strip().upper()
            cover_needs_refresh = self._preview_url_needs_refresh(str(item.get("cover_url") or ""))
            video_needs_refresh = self._preview_url_needs_refresh(str(item.get("video_url") or ""))
            if material_type == "VIDEO":
                should_refresh = video_needs_refresh or cover_needs_refresh
            else:
                should_refresh = cover_needs_refresh
            if not should_refresh:
                continue
            source = self._resolve_material_curve_source(
                item,
                start_date,
                end_date,
                snapshot_time,
                allowed_advertiser_ids,
                search_all_customer_centers=search_all_customer_centers,
            )
            if not source:
                continue
            customer_center_id = str(source.get("customer_center_id") or current_customer_center_id).strip()
            advertiser_id = int(source.get("advertiser_id", 0) or 0)
            ad_id = int(source.get("ad_id", 0) or 0)
            material_type = str(source.get("material_type") or item.get("material_type") or "VIDEO").strip().upper()
            if not customer_center_id or advertiser_id <= 0 or ad_id <= 0 or material_type not in PLAN_MATERIAL_TYPES:
                continue
            refresh_targets.setdefault(
                (customer_center_id, advertiser_id, ad_id, material_type),
                [],
            ).append((item, source))
        if not refresh_targets:
            return items

        refreshed_rows: dict[tuple[str, int, int, str], list[dict[str, Any]]] = {}
        with ThreadPoolExecutor(max_workers=min(len(refresh_targets), 4)) as executor:
            future_map = {
                executor.submit(
                    self._plan_material_rows_for_preview_refresh,
                    customer_center_id,
                    advertiser_id,
                    ad_id,
                    material_type,
                ): (customer_center_id, advertiser_id, ad_id, material_type)
                for customer_center_id, advertiser_id, ad_id, material_type in refresh_targets
            }
            for future in as_completed(future_map):
                group_key = future_map[future]
                try:
                    refreshed_rows[group_key] = future.result()
                except Exception:
                    refreshed_rows[group_key] = []

        for group_key, targets in refresh_targets.items():
            customer_center_id, advertiser_id, ad_id, material_type = group_key
            candidate_rows = refreshed_rows.get(group_key) or []
            if not candidate_rows:
                continue
            indexes = self._material_preview_candidate_indexes(candidate_rows, material_type)
            for item, source in targets:
                candidate = self._match_refreshed_material_preview(item, source, indexes)
                if not candidate:
                    continue
                preview = candidate.get("preview") or {}
                identity = candidate.get("identity") or {}
                cover_url = str(preview.get("cover_url") or "").strip()
                if cover_url:
                    item["cover_url"] = cover_url
                aweme_item_id = str(preview.get("aweme_item_id") or "").strip()
                if aweme_item_id:
                    item["aweme_item_id"] = aweme_item_id
                video_url = str(preview.get("video_url") or "").strip()
                if video_url:
                    item["video_url"] = video_url
                video_id = str(identity.get("video_id") or "").strip()
                if video_id:
                    item["video_id"] = video_id
                item["_preview_refreshed"] = True
                item["_preview_refresh_customer_center_id"] = customer_center_id
                item["_preview_refresh_advertiser_id"] = advertiser_id
                item["_preview_refresh_ad_id"] = ad_id
        return items

    def _apply_material_top_anchor_names(
        self,
        conn: Any,
        items: list[dict[str, Any]],
        snapshot_times: list[str],
    ) -> list[dict[str, Any]]:
        if not items or not snapshot_times:
            return items
        unresolved_keys = {
            (
                str(item.get("top_account_name") or "").strip(),
                str(item.get("top_plan_name") or "").strip(),
            )
            for item in items
            if not str(item.get("top_anchor_name") or "").strip()
            and str(item.get("top_account_name") or "").strip()
            and str(item.get("top_plan_name") or "").strip()
        }
        if not unresolved_keys:
            return items
        placeholders = ",".join("?" for _ in snapshot_times)
        customer_center_id = self._current_customer_center_id()
        rows = conn.execute(
            f"""
            SELECT snapshot_time, advertiser_name, ad_name, anchor_name
            FROM plan_snapshots
            WHERE snapshot_time IN ({placeholders})
              AND customer_center_id = ?
              AND COALESCE(anchor_name, '') <> ''
            ORDER BY snapshot_time DESC, ad_id DESC
            """,
            [*snapshot_times, customer_center_id],
        ).fetchall()
        anchor_map: dict[tuple[str, str], str] = {}
        for row in rows:
            row = dict(row)
            key = (
                str(row.get("advertiser_name") or "").strip(),
                str(row.get("ad_name") or "").strip(),
            )
            if key not in unresolved_keys or key in anchor_map:
                continue
            anchor_name = str(row.get("anchor_name") or "").strip()
            if anchor_name:
                anchor_map[key] = anchor_name
        if not anchor_map:
            return items
        enriched_items: list[dict[str, Any]] = []
        for item in items:
            enriched = dict(item)
            if not str(enriched.get("top_anchor_name") or "").strip():
                enriched["top_anchor_name"] = anchor_map.get(
                    (
                        str(enriched.get("top_account_name") or "").strip(),
                        str(enriched.get("top_plan_name") or "").strip(),
                    ),
                    "",
                )
            enriched_items.append(enriched)
        return enriched_items

    def _aggregate_material_rollups(self, rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
        groups: dict[str, dict[str, Any]] = {}
        for row in rows:
            material_key = str(row.get("material_key") or "").strip()
            if not material_key:
                continue
            plan_ids = {int(item) for item in json.loads(str(row.get("plan_ids_json") or "[]")) if int(item or 0)}
            advertiser_ids = {int(item) for item in json.loads(str(row.get("advertiser_ids_json") or "[]")) if int(item or 0)}
            group = groups.get(material_key)
            if group is None:
                group = dict(row)
                group["stat_cost"] = 0.0
                group["pay_amount"] = 0.0
                group["total_pay_amount"] = 0.0
                group["settled_pay_amount"] = 0.0
                group["refund_amount_1h"] = 0.0
                group["has_refund_metric"] = False
                group["order_count"] = 0
                group["settled_order_count"] = 0
                group["overall_show_count"] = 0
                group["overall_click_count"] = 0
                group["product_names"] = set()
                group["product_info_text"] = str(row.get("product_info_text") or "")
                group["plan_ids"] = set()
                group["advertiser_ids"] = set()
                group["_top_plan_orders"] = -1
                group["_top_plan_pay_amount"] = -1.0
                group["top_anchor_name"] = str(group.get("top_anchor_name") or row.get("top_anchor_name") or row.get("anchor_name") or "")
                groups[material_key] = group
            stat_cost = round(float(row.get("stat_cost", 0.0) or 0.0), 2)
            pay_amount = round(float(row.get("pay_amount", 0.0) or 0.0), 2)
            total_pay_amount = round(float(row.get("total_pay_amount", 0.0) or 0.0), 2)
            settled_pay_amount = round(float(row.get("settled_pay_amount", 0.0) or 0.0), 2)
            refund_amount_1h = round(float(row.get("refund_amount_1h", 0.0) or 0.0), 2)
            order_count = int(float(row.get("order_count", 0.0) or 0.0))
            settled_order_count = int(float(row.get("settled_order_count", 0.0) or 0.0))
            overall_show_count = int(float(row.get("overall_show_count", 0.0) or 0.0))
            overall_click_count = int(float(row.get("overall_click_count", 0.0) or 0.0))
            group["stat_cost"] = round(float(group["stat_cost"] or 0.0) + stat_cost, 2)
            group["pay_amount"] = round(float(group["pay_amount"] or 0.0) + pay_amount, 2)
            group["total_pay_amount"] = round(float(group["total_pay_amount"] or 0.0) + total_pay_amount, 2)
            group["settled_pay_amount"] = round(float(group["settled_pay_amount"] or 0.0) + settled_pay_amount, 2)
            group["refund_amount_1h"] = round(float(group.get("refund_amount_1h", 0.0) or 0.0) + refund_amount_1h, 2)
            group["has_refund_metric"] = bool(group.get("has_refund_metric")) or row.get("refund_rate_1h") is not None
            group["order_count"] = int(group["order_count"] or 0) + order_count
            group["settled_order_count"] = int(group["settled_order_count"] or 0) + settled_order_count
            group["overall_show_count"] = int(group["overall_show_count"] or 0) + overall_show_count
            group["overall_click_count"] = int(group["overall_click_count"] or 0) + overall_click_count
            group["plan_ids"].update(plan_ids)
            group["advertiser_ids"].update(advertiser_ids)
            group["is_original"] = bool(group.get("is_original")) or bool(row.get("is_original"))
            row_create_time = str(row.get("create_time") or "").strip()
            if row_create_time and (
                not str(group.get("create_time") or "").strip()
                or row_create_time < str(group.get("create_time") or "").strip()
            ):
                group["create_time"] = row_create_time
            if not str(group.get("product_info_text") or "").strip():
                group["product_info_text"] = str(row.get("product_info_text") or "").strip()
            raw_product_names = row.get("product_names_json")
            if raw_product_names:
                try:
                    parsed_names = json.loads(str(raw_product_names or "[]"))
                except Exception:
                    parsed_names = []
                if isinstance(parsed_names, list):
                    for name in parsed_names:
                        text = str(name or "").strip()
                        if text:
                            group["product_names"].add(text)
            if (
                order_count > int(group.get("_top_plan_orders", -1))
                or (
                    order_count == int(group.get("_top_plan_orders", -1))
                    and pay_amount > float(group.get("_top_plan_pay_amount", -1.0))
                )
            ):
                group["top_plan_name"] = str(row.get("top_plan_name") or "")
                group["top_account_name"] = str(row.get("top_account_name") or "")
                group["top_anchor_name"] = str(row.get("top_anchor_name") or row.get("anchor_name") or "")
                group["_top_plan_orders"] = order_count
                group["_top_plan_pay_amount"] = pay_amount

        rankings: list[dict[str, Any]] = []
        for group in groups.values():
            stat_cost = round(float(group.get("stat_cost", 0.0) or 0.0), 2)
            pay_amount = round(float(group.get("pay_amount", 0.0) or 0.0), 2)
            total_pay_amount = round(float(group.get("total_pay_amount", 0.0) or 0.0), 2)
            settled_pay_amount = round(float(group.get("settled_pay_amount", 0.0) or 0.0), 2)
            refund_amount_1h = round(float(group.get("refund_amount_1h", 0.0) or 0.0), 2)
            order_count = int(group.get("order_count", 0) or 0)
            settled_order_count = int(group.get("settled_order_count", 0) or 0)
            overall_show_count = int(group.get("overall_show_count", 0) or 0)
            overall_click_count = int(group.get("overall_click_count", 0) or 0)
            product_info_text = self._summarize_material_product_names(
                sorted(str(name) for name in group.get("product_names", set()) if str(name or "").strip())
            ) or str(group.get("product_info_text") or "")
            rankings.append(
                {
                    "customer_center_id": str(group.get("customer_center_id") or ""),
                    "material_key": str(group.get("material_key") or ""),
                    "material_id": str(group.get("material_id") or ""),
                    "create_time": str(group.get("create_time") or ""),
                    "material_name": str(group.get("material_name") or "") or "未命名素材",
                    "material_type": str(group.get("material_type") or "") or "OTHER",
                    "video_id": str(group.get("video_id") or ""),
                    "cover_url": str(group.get("cover_url") or ""),
                    "aweme_item_id": str(group.get("aweme_item_id") or ""),
                    "video_url": str(group.get("video_url") or ""),
                    "stat_cost": stat_cost,
                    "pay_amount": pay_amount,
                    "total_pay_amount": total_pay_amount,
                    "settled_pay_amount": settled_pay_amount,
                    "order_count": order_count,
                    "settled_order_count": settled_order_count,
                    "plan_count": len(group["plan_ids"]),
                    "advertiser_count": len(group["advertiser_ids"]),
                    "plan_ids": sorted(int(item) for item in group["plan_ids"] if int(item or 0)),
                    "advertiser_ids": sorted(int(item) for item in group["advertiser_ids"] if int(item or 0)),
                    "plan_ids_json": self._json_text(sorted(int(item) for item in group["plan_ids"] if int(item or 0))),
                    "advertiser_ids_json": self._json_text(
                        sorted(int(item) for item in group["advertiser_ids"] if int(item or 0))
                    ),
                    "is_original": bool(group.get("is_original")),
                    "top_plan_name": str(group.get("top_plan_name") or ""),
                    "top_account_name": str(group.get("top_account_name") or ""),
                    "top_anchor_name": str(group.get("top_anchor_name") or ""),
                    "roi": round(pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0,
                    "settled_roi": round(settled_pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0,
                    "pay_order_cost": round(stat_cost / order_count, 2) if order_count > 0 else 0.0,
                    "settled_amount_rate": round(settled_pay_amount / total_pay_amount * 100.0, 2) if total_pay_amount > 0 else 0.0,
                    "refund_amount_1h": refund_amount_1h,
                    "refund_rate_1h": (
                        round(refund_amount_1h / total_pay_amount * 100.0, 2)
                        if total_pay_amount > 0 and bool(group.get("has_refund_metric"))
                        else None
                    ),
                    "product_info_text": product_info_text,
                    "overall_show_count": overall_show_count,
                    "overall_click_count": overall_click_count,
                    "overall_ctr": round(overall_click_count / overall_show_count * 100.0, 2) if overall_show_count > 0 else 0.0,
                }
            )
        rankings.sort(
            key=lambda item: (
                float(item["stat_cost"]),
                float(item["pay_amount"]),
                int(item["order_count"]),
                float(item["roi"]),
                str(item.get("create_time") or ""),
            ),
            reverse=True,
        )
        return rankings

    def _filter_material_rows_by_create_time_window(
        self,
        rows: list[dict[str, Any]],
        start_dt: datetime | None,
        end_dt: datetime | None,
        tz_name: str,
    ) -> list[dict[str, Any]]:
        if start_dt is None or end_dt is None:
            return rows
        tz = ZoneInfo(str(tz_name or TIMEZONE))
        start_text = start_dt.astimezone(tz).strftime("%Y-%m-%d %H:%M:%S")
        end_text = end_dt.astimezone(tz).strftime("%Y-%m-%d %H:%M:%S")
        filtered_rows: list[dict[str, Any]] = []
        for raw_row in rows:
            row = dict(raw_row)
            create_time = self._normalize_datetime_text(row.get("create_time"))
            if not create_time:
                continue
            row["create_time"] = create_time
            if start_text <= create_time <= end_text:
                filtered_rows.append(row)
        return filtered_rows

    def _apply_material_snapshot_context(
        self,
        conn: Any,
        items: list[dict[str, Any]],
        snapshot_times: list[str],
        allowed_advertiser_ids: set[int] | None = None,
    ) -> list[dict[str, Any]]:
        if not items or not snapshot_times:
            return items
        placeholders = ",".join("?" for _ in snapshot_times)
        clauses = [f"snapshot_time IN ({placeholders})"]
        params: list[Any] = list(snapshot_times)
        if allowed_advertiser_ids:
            allowed = sorted(int(item) for item in allowed_advertiser_ids if int(item or 0))
            if allowed:
                clauses.append(f"advertiser_id IN ({','.join('?' for _ in allowed)})")
                params.extend(allowed)
        clauses.append("customer_center_id = ?")
        params.append(self._current_customer_center_id())
        rows = conn.execute(
            f"""
            SELECT material_key, product_show_count, product_click_count, raw_json
            FROM material_snapshots
            WHERE {" AND ".join(clauses)}
            """,
            params,
        ).fetchall()
        context_by_key: dict[str, dict[str, Any]] = {}
        for raw_row in rows:
            row = dict(raw_row)
            material_key = str(row.get("material_key") or "").strip()
            if not material_key:
                continue
            group = context_by_key.setdefault(
                material_key,
                {
                    "product_show_count": 0,
                    "product_click_count": 0,
                    "product_names": [],
                },
            )
            group["product_show_count"] += int(row.get("product_show_count", 0) or 0)
            group["product_click_count"] += int(row.get("product_click_count", 0) or 0)
            for name in self._extract_material_product_names(row.get("raw_json")):
                if name not in group["product_names"]:
                    group["product_names"].append(name)
        for item in items:
            context = context_by_key.get(str(item.get("material_key") or "").strip())
            if not context:
                continue
            show_count = int(context.get("product_show_count", 0) or 0)
            click_count = int(context.get("product_click_count", 0) or 0)
            item["product_info_text"] = self._summarize_material_product_names(list(context.get("product_names") or []))
            item["overall_show_count"] = show_count
            item["overall_click_count"] = click_count
            item["overall_ctr"] = round(click_count / show_count * 100.0, 2) if show_count > 0 else 0.0
        return items

    def _rankings_bundle(
        self, summary: dict[str, Any], accounts: list[dict[str, Any]], plans: list[dict[str, Any]]
    ) -> tuple[dict[str, Any], list[dict[str, Any]], list[dict[str, Any]], list[dict[str, Any]]]:
        products = self._build_product_rankings(plans)
        employees = self._build_employee_rankings(plans)
        operators = self._build_operator_rankings(plans)
        enriched_summary = dict(summary)
        enriched_summary["product_count"] = len(products)
        enriched_summary["active_product_count"] = sum(1 for item in products if float(item["stat_cost"]) > 0)
        enriched_summary["employee_count"] = len(employees)
        enriched_summary["active_employee_count"] = sum(1 for item in employees if float(item["stat_cost"]) > 0)
        enriched_summary["operator_count"] = len(operators)
        enriched_summary["active_operator_count"] = sum(1 for item in operators if float(item["stat_cost"]) > 0)
        enriched_summary["account_count"] = enriched_summary.get("account_count", len(accounts))
        enriched_summary["active_account_count"] = enriched_summary.get(
            "active_account_count",
            sum(1 for item in accounts if bool(item.get("ok", True)) and float(item.get("stat_cost", 0.0) or 0.0) > 0),
        )
        enriched_summary["plan_count"] = enriched_summary.get("plan_count", len(plans))
        enriched_summary["active_plan_count"] = enriched_summary.get(
            "active_plan_count",
            sum(1 for item in plans if float(item.get("stat_cost", 0.0) or 0.0) > 0),
        )
        return enriched_summary, products, employees, operators

    @staticmethod
    def _scoped_summary(accounts: list[dict[str, Any]], plans: list[dict[str, Any]]) -> dict[str, Any]:
        stat_cost = round(sum(float(item.get("stat_cost", 0.0) or 0.0) for item in accounts), 2)
        pay_amount = round(sum(float(item.get("pay_amount", 0.0) or 0.0) for item in accounts), 2)
        order_count = int(sum(int(float(item.get("order_count", 0.0) or 0.0)) for item in accounts))
        roi = round(pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0
        return {
            "account_count": len(accounts),
            "active_account_count": sum(
                1 for item in accounts if bool(item.get("ok", True)) and float(item.get("stat_cost", 0.0) or 0.0) > 0
            ),
            "plan_count": len(plans),
            "active_plan_count": sum(1 for item in plans if float(item.get("stat_cost", 0.0) or 0.0) > 0),
            "stat_cost": stat_cost,
            "pay_amount": pay_amount,
            "order_count": order_count,
            "roi": roi,
            "account_failures": sum(1 for item in accounts if not bool(item.get("ok", True))),
            "plan_failures": 0,
        }

    def _aggregate_accounts_from_plans(
        self,
        plans: list[dict[str, Any]],
        account_catalog: list[dict[str, Any]] | None = None,
    ) -> list[dict[str, Any]]:
        catalog = {int(item.get("advertiser_id", 0) or 0): dict(item) for item in (account_catalog or [])}
        groups: dict[int, dict[str, Any]] = {}
        for row in plans:
            advertiser_id = int(row.get("advertiser_id", 0) or 0)
            if not advertiser_id:
                continue
            base = catalog.get(advertiser_id, {})
            group = groups.setdefault(
                advertiser_id,
                {
                    "advertiser_id": advertiser_id,
                    "advertiser_name": str(row.get("advertiser_name") or base.get("advertiser_name") or advertiser_id),
                    "ok": bool(base.get("ok", True)),
                    "status": str(base.get("status") or ""),
                    "stat_cost": 0.0,
                    "pay_amount": 0.0,
                    "order_count": 0,
                },
            )
            group["stat_cost"] = round(group["stat_cost"] + float(row.get("stat_cost", 0.0) or 0.0), 2)
            group["pay_amount"] = round(group["pay_amount"] + float(row.get("pay_amount", 0.0) or 0.0), 2)
            group["order_count"] += int(float(row.get("order_count", 0.0) or 0.0))
        rows: list[dict[str, Any]] = []
        for item in groups.values():
            stat_cost = round(float(item.get("stat_cost", 0.0) or 0.0), 2)
            pay_amount = round(float(item.get("pay_amount", 0.0) or 0.0), 2)
            row = dict(item)
            row["roi"] = round(pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0
            rows.append(row)
        rows.sort(key=lambda item: (-float(item.get("stat_cost", 0.0) or 0.0), int(item.get("advertiser_id", 0) or 0)))
        return rows

    def _filter_plans_for_operator(
        self,
        plans: list[dict[str, Any]],
        user_id: int,
        operators: dict[int, dict[str, Any]] | None = None,
        keywords: list[dict[str, Any]] | None = None,
    ) -> list[dict[str, Any]]:
        if operators is None or keywords is None:
            operators, keywords = self._active_operator_config()
        if int(user_id or 0) not in operators:
            return []
        result: list[dict[str, Any]] = []
        for row in plans:
            matches = self._matched_operators_for_plan(row, operators, keywords)
            if any(int(item["operator_id"]) == int(user_id) for item in matches):
                result.append(dict(row))
        return result

    def _filter_material_items_for_operator(
        self,
        items: list[dict[str, Any]],
        user_id: int,
        operators: dict[int, dict[str, Any]] | None = None,
        keywords: list[dict[str, Any]] | None = None,
    ) -> list[dict[str, Any]]:
        if operators is None or keywords is None:
            operators, keywords = self._active_operator_config()
        if int(user_id or 0) not in operators:
            return []
        result: list[dict[str, Any]] = []
        for row in items:
            matches = self._matched_operators_for_material(row, operators, keywords)
            if any(int(item["operator_id"]) == int(user_id) for item in matches):
                result.append(dict(row))
        return result

    def _apply_operator_scope(self, payload: dict[str, Any], user: dict[str, Any]) -> dict[str, Any]:
        user_id = int(user.get("id", 0) or 0)
        operator_plans = self._filter_plans_for_operator(payload.get("plans", []), user_id)
        operator_accounts = self._aggregate_accounts_from_plans(operator_plans, payload.get("accounts", []))
        next_payload = dict(payload)
        next_payload["accounts"] = operator_accounts
        next_payload["plans"] = operator_plans
        next_payload["accountBalances"] = []
        next_payload["sharedWallets"] = []
        next_payload["walletRelations"] = []
        next_payload["summary"], next_payload["products"], next_payload["employees"], _operators = self._rankings_bundle(
            self._scoped_summary(operator_accounts, operator_plans),
            operator_accounts,
            operator_plans,
        )
        next_payload["operators"] = [dict(item) for item in payload.get("operators", [])]
        next_payload["summary"]["operator_count"] = len(next_payload["operators"])
        next_payload["summary"]["active_operator_count"] = sum(
            1 for item in next_payload["operators"] if float(item.get("stat_cost", 0.0) or 0.0) > 0
        )
        return next_payload

    def _apply_material_scope(self, payload: dict[str, Any], user: dict[str, Any]) -> dict[str, Any]:
        if str(user.get("role") or "") != ROLE_OPERATOR:
            return payload
        next_payload = dict(payload)
        next_payload["items"] = self._filter_material_items_for_operator(payload.get("items", []), int(user.get("id", 0) or 0))
        return next_payload

    def _apply_comment_scope(self, payload: dict[str, Any], user: dict[str, Any]) -> dict[str, Any]:
        if str(user.get("role") or "") != ROLE_OPERATOR:
            return payload
        user_id = int(user.get("id", 0) or 0)
        scoped_items = self._filter_material_items_for_operator(payload.get("items", []), user_id)
        account_map: dict[int, dict[str, Any]] = {}
        for row in scoped_items:
            advertiser_id = int(row.get("advertiser_id", 0) or 0)
            if not advertiser_id or advertiser_id in account_map:
                continue
            account_map[advertiser_id] = {
                "advertiser_id": advertiser_id,
                "advertiser_name": str(row.get("advertiser_name") or advertiser_id),
            }
        next_payload = dict(payload)
        next_payload["items"] = scoped_items
        next_payload["accounts"] = sorted(account_map.values(), key=lambda item: (str(item["advertiser_name"]), item["advertiser_id"]))
        meta = dict(next_payload.get("meta") or {})
        meta["visible_count"] = len(scoped_items)
        next_payload["meta"] = meta
        return next_payload

    @staticmethod
    def _comment_account_candidates(
        client: OceanEngineClient,
        allowed_advertiser_ids: set[int] | None = None,
    ) -> list[dict[str, Any]]:
        accounts: list[dict[str, Any]] = []
        allowed = {int(item) for item in allowed_advertiser_ids} if allowed_advertiser_ids is not None else None
        for item in client.list_accounts():
            advertiser_id = int(item.get("advertiser_id") or item.get("account_id") or 0)
            if not advertiser_id:
                continue
            if allowed is not None and advertiser_id not in allowed:
                continue
            advertiser_name = str(
                item.get("advertiser_name")
                or item.get("account_name")
                or item.get("name")
                or advertiser_id
            ).strip()
            accounts.append(
                {
                    "advertiser_id": advertiser_id,
                    "advertiser_name": advertiser_name,
                }
            )
        accounts.sort(key=lambda item: (str(item["advertiser_name"]), int(item["advertiser_id"])))
        return accounts

    def _comment_stored_account_catalog(
        self,
        allowed_advertiser_ids: set[int] | None = None,
    ) -> list[dict[str, Any]]:
        allowed = None if allowed_advertiser_ids is None else sorted(int(item) for item in allowed_advertiser_ids if int(item or 0) > 0)
        if allowed_advertiser_ids is not None and not allowed:
            return []
        allowed_clause = ""
        params: list[Any] = [self._current_customer_center_id()]
        if allowed:
            allowed_clause = f" AND advertiser_id IN ({','.join('?' for _ in allowed)})"
            params.extend(allowed)
        with self.db() as conn:
            rows = conn.execute(
                f"""
                SELECT advertiser_id, advertiser_name
                FROM account_current
                WHERE customer_center_id = ?
                  AND advertiser_id > 0
                  {allowed_clause}
                ORDER BY advertiser_name ASC, advertiser_id ASC
                """,
                params,
            ).fetchall()
        items: list[dict[str, Any]] = []
        seen: set[int] = set()
        for row in rows:
            advertiser_id = int(row["advertiser_id"] or 0)
            if advertiser_id <= 0 or advertiser_id in seen:
                continue
            seen.add(advertiser_id)
            items.append(
                {
                    "advertiser_id": advertiser_id,
                    "advertiser_name": str(row["advertiser_name"] or advertiser_id).strip(),
                }
            )
        return items or self.latest_account_catalog(allowed_advertiser_ids)

    def _fetch_account_comments(
        self,
        client: OceanEngineClient,
        advertiser_id: int,
        advertiser_name: str,
        start_date: str,
        end_date: str,
    ) -> tuple[list[dict[str, Any]], dict[str, Any] | None]:
        try:
            rows = client.list_comments(
                advertiser_id=advertiser_id,
                start_time=start_date,
                end_time=end_date,
                page_size=100,
            )
        except Exception as exc:  # noqa: BLE001
            return [], {
                "advertiser_id": int(advertiser_id),
                "advertiser_name": str(advertiser_name or advertiser_id),
                "error": str(exc),
            }

        items: list[dict[str, Any]] = []
        for row in rows:
            reply_count = int(float(row.get("reply_count", 0) or 0))
            like_count = int(float(row.get("like_count", 0) or 0))
            hide_status = str(row.get("hide_status") or "NOT_HIDE").strip().upper()
            level_type = str(row.get("level_type") or "").strip().upper()
            comment_type = str(row.get("comment_type") or "").strip().upper()
            material_id = str(row.get("material_id") or "").strip()
            promotion_id = str(row.get("promotion_id") or "").strip()
            item_payload = {
                "comment_id": str(row.get("comment_id") or "").strip(),
                "advertiser_id": int(advertiser_id),
                "advertiser_name": str(advertiser_name or advertiser_id),
                "text": str(row.get("text") or "").strip(),
                "reply_count": reply_count,
                "is_replied": reply_count > 0,
                "reply_status_text": "已回复" if reply_count > 0 else "未回复",
                "hide_status": hide_status,
                "hide_status_text": self._comment_hide_status_label(hide_status),
                "level_type": level_type,
                "level_type_text": self._comment_level_label(level_type),
                "comment_user_name": str(row.get("aweme_name") or "").strip(),
                "comment_user_id": str(row.get("aweme_id") or "").strip(),
                "create_time": str(row.get("create_time") or "").strip(),
                "reply_count_text": reply_count,
                "like_count": like_count,
                "item_title": str(row.get("item_title") or "").strip(),
                "video_owner_aweme_id": "",
                "comment_anchor_name": "",
                "comment_type": comment_type,
                "comment_type_text": self._comment_type_label(comment_type),
                "promotion_id": promotion_id,
                "promotion_name": "",
                "promotion_display_name": f"计划 {promotion_id}" if promotion_id else "-",
                "material_id": material_id,
                "material_name": "",
                "material_display_name": f"素材 {material_id}" if material_id else "-",
                "item_id": str(row.get("item_id") or "").strip(),
            }
            item_payload["material_name"] = item_payload["material_name"]
            items.append(item_payload)
        return items, None

    def _comment_plan_context_maps(
        self,
        conn: Any,
        advertiser_ids: set[int],
        promotion_ids: set[int],
    ) -> tuple[dict[tuple[int, int], dict[str, str]], dict[int, dict[str, str]]]:
        if not advertiser_ids or not promotion_ids:
            return {}, {}
        advertiser_placeholders = ",".join("?" for _ in advertiser_ids)
        promotion_placeholders = ",".join("?" for _ in promotion_ids)
        params: list[Any] = [
            *sorted(promotion_ids),
            *sorted(advertiser_ids),
            self._current_customer_center_id(),
            *sorted(promotion_ids),
            *sorted(advertiser_ids),
            self._current_customer_center_id(),
        ]
        rows = conn.execute(
            f"""
            SELECT 0 AS priority, snapshot_time, advertiser_id, ad_id, ad_name, anchor_name, plan_source
            FROM plan_current
            WHERE ad_id IN ({promotion_placeholders})
              AND advertiser_id IN ({advertiser_placeholders})
              AND customer_center_id = ?
            UNION ALL
            SELECT 1 AS priority, snapshot_time, advertiser_id, ad_id, ad_name, anchor_name, plan_source
            FROM plan_snapshots
            WHERE ad_id IN ({promotion_placeholders})
              AND advertiser_id IN ({advertiser_placeholders})
              AND customer_center_id = ?
            ORDER BY priority ASC, snapshot_time DESC
            """,
            params,
        ).fetchall()
        exact: dict[tuple[int, int], dict[str, str]] = {}
        fallback: dict[int, dict[str, str]] = {}

        def merge_context(target: dict[str, str], source: dict[str, str]) -> None:
            for key, value in source.items():
                if value and not target.get(key):
                    target[key] = value

        for row in rows:
            advertiser_id = int(row["advertiser_id"])
            ad_id = int(row["ad_id"])
            ad_name = str(row["ad_name"] or ad_id).strip()
            context = {
                "promotion_id": str(ad_id) if ad_id else "",
                "promotion_name": ad_name,
                "comment_anchor_name": str(row["anchor_name"] or "").strip(),
                "plan_source": str(row["plan_source"] or "").strip(),
            }
            key = (advertiser_id, ad_id)
            if key not in exact:
                exact[key] = dict(context)
            else:
                merge_context(exact[key], context)
            if ad_id not in fallback:
                fallback[ad_id] = dict(context)
            else:
                merge_context(fallback[ad_id], context)
        return exact, fallback

    def _comment_material_context_maps(
        self,
        conn: Any,
        advertiser_ids: set[int],
        material_ids: set[str],
        item_ids: set[str],
    ) -> dict[str, dict[Any, dict[str, str]]]:
        result: dict[str, dict[Any, dict[str, str]]] = {
            "exact_item": {},
            "fallback_item": {},
            "exact_material": {},
            "fallback_material": {},
        }
        normalized_material_ids = sorted(str(item).strip() for item in material_ids if str(item).strip())
        normalized_item_ids = sorted(str(item).strip() for item in item_ids if str(item).strip())
        if not advertiser_ids or (not normalized_material_ids and not normalized_item_ids):
            return result

        advertiser_placeholders = ",".join("?" for _ in advertiser_ids)
        source_queries: list[str] = []
        params: list[Any] = []

        def append_source(table_name: str, priority: int, has_top_anchor: bool) -> None:
            match_clauses: list[str] = []
            source_params: list[Any] = [self._current_customer_center_id(), *sorted(advertiser_ids)]
            if normalized_material_ids:
                material_placeholders = ",".join("?" for _ in normalized_material_ids)
                match_clauses.append(f"COALESCE(mr.material_id, '') IN ({material_placeholders})")
                source_params.extend(normalized_material_ids)
            if normalized_item_ids:
                item_placeholders = ",".join("?" for _ in normalized_item_ids)
                match_clauses.append(
                    f"(COALESCE(mr.aweme_item_id, '') IN ({item_placeholders}) OR COALESCE(mr.video_id, '') IN ({item_placeholders}))"
                )
                source_params.extend(normalized_item_ids)
                source_params.extend(normalized_item_ids)
            top_anchor_expr = "NULLIF(mr.top_anchor_name, '')" if has_top_anchor else "NULL"
            source_queries.append(
                f"""
                SELECT
                    {priority} AS priority,
                    mr.snapshot_time,
                    mr.advertiser_id,
                    mr.ad_id,
                    mr.ad_name,
                    mr.material_id,
                    mr.material_name,
                    mr.video_id,
                    mr.aweme_item_id,
                    COALESCE({top_anchor_expr}, NULLIF(pc.anchor_name, ''), '') AS comment_anchor_name,
                    COALESCE(NULLIF(pc.plan_source, ''), '') AS plan_source
                FROM {table_name} mr
                LEFT JOIN plan_current pc
                  ON pc.customer_center_id = mr.customer_center_id
                 AND pc.advertiser_id = mr.advertiser_id
                 AND pc.ad_id = mr.ad_id
                WHERE mr.customer_center_id = ?
                  AND mr.advertiser_id IN ({advertiser_placeholders})
                  AND ({' OR '.join(match_clauses)})
                """
            )
            params.extend(source_params)

        append_source("material_relation_current", 0, True)
        append_source("material_relation_daily", 1, True)
        append_source("material_snapshots", 2, False)

        rows = conn.execute(
            f"""
            {' UNION ALL '.join(source_queries)}
            ORDER BY priority ASC, snapshot_time DESC
            """,
            params,
        ).fetchall()

        def merge_context(target: dict[str, str], source: dict[str, str]) -> None:
            for key, value in source.items():
                if value and not target.get(key):
                    target[key] = value

        def store(mapping: dict[Any, dict[str, str]], key: Any, context: dict[str, str]) -> None:
            if key in mapping:
                merge_context(mapping[key], context)
            else:
                mapping[key] = dict(context)

        for row in rows:
            advertiser_id = int(row["advertiser_id"] or 0)
            ad_id = int(row["ad_id"] or 0)
            material_id = str(row["material_id"] or "").strip()
            aweme_item_id = str(row["aweme_item_id"] or "").strip()
            video_id = str(row["video_id"] or "").strip()
            context = {
                "promotion_id": str(ad_id) if ad_id else "",
                "promotion_name": str(row["ad_name"] or "").strip(),
                "material_name": str(row["material_name"] or "").strip(),
                "comment_anchor_name": str(row["comment_anchor_name"] or "").strip(),
                "plan_source": str(row["plan_source"] or "").strip(),
            }
            if material_id:
                store(result["exact_material"], (advertiser_id, material_id), context)
                store(result["fallback_material"], material_id, context)
            for item_id in (aweme_item_id, video_id):
                if not item_id:
                    continue
                store(result["exact_item"], (advertiser_id, item_id), context)
                store(result["fallback_item"], item_id, context)
        return result

    def _comment_material_name_maps(
        self,
        conn: Any,
        advertiser_ids: set[int],
        material_ids: set[str],
    ) -> tuple[dict[tuple[int, str], str], dict[str, str]]:
        normalized_material_ids = sorted(str(item).strip() for item in material_ids if str(item).strip())
        if not advertiser_ids or not normalized_material_ids:
            return {}, {}
        material_placeholders = ",".join("?" for _ in normalized_material_ids)
        profile_rows = conn.execute(
            f"""
            SELECT material_id, material_name, updated_at
            FROM material_profile
            WHERE customer_center_id = ?
              AND material_id IN ({material_placeholders})
              AND COALESCE(material_id, '') <> ''
              AND COALESCE(material_name, '') <> ''
            ORDER BY updated_at DESC
            """,
            [self._current_customer_center_id(), *normalized_material_ids],
        ).fetchall()
        exact: dict[tuple[int, str], str] = {}
        fallback: dict[str, str] = {}
        for row in profile_rows:
            material_id = str(row["material_id"] or "").strip()
            material_name = str(row["material_name"] or material_id).strip()
            if material_id and material_name:
                fallback.setdefault(material_id, material_name)
        missing_material_ids = [item for item in normalized_material_ids if item not in fallback]
        if not missing_material_ids:
            return exact, fallback
        advertiser_placeholders = ",".join("?" for _ in advertiser_ids)
        missing_placeholders = ",".join("?" for _ in missing_material_ids)
        params: list[Any] = [*missing_material_ids, *sorted(advertiser_ids), self._current_customer_center_id()]
        rows = conn.execute(
            f"""
            SELECT snapshot_time, advertiser_id, material_id, material_name
            FROM material_snapshots
            WHERE material_id IN ({missing_placeholders})
              AND advertiser_id IN ({advertiser_placeholders})
              AND customer_center_id = ?
              AND COALESCE(material_id, '') <> ''
            ORDER BY snapshot_time DESC
            """,
            params,
        ).fetchall()
        for row in rows:
            advertiser_id = int(row["advertiser_id"])
            material_id = str(row["material_id"] or "").strip()
            material_name = str(row["material_name"] or material_id).strip()
            if not material_id:
                continue
            exact.setdefault((advertiser_id, material_id), material_name)
            fallback.setdefault(material_id, material_name)
        return exact, fallback

    @classmethod
    def _comment_record_from_item(
        cls,
        item: dict[str, Any],
        fetched_at: str,
        fallback_date: str = "",
    ) -> dict[str, Any]:
        create_time = cls._normalize_datetime_text(item.get("create_time"))
        return {
            "comment_id": str(item.get("comment_id") or "").strip(),
            "advertiser_id": int(item.get("advertiser_id", 0) or 0),
            "advertiser_name": str(item.get("advertiser_name") or item.get("advertiser_id") or "").strip(),
            "comment_date": create_time[:10] if len(create_time) >= 10 else str(fallback_date or "").strip(),
            "create_time": create_time,
            "text": str(item.get("text") or "").strip(),
            "reply_count": cls._safe_int(item.get("reply_count", 0)),
            "hide_status": str(item.get("hide_status") or "NOT_HIDE").strip().upper(),
            "level_type": str(item.get("level_type") or "").strip().upper(),
            "comment_user_name": str(item.get("comment_user_name") or "").strip(),
            "comment_user_id": str(item.get("comment_user_id") or "").strip(),
            "like_count": cls._safe_int(item.get("like_count", 0)),
            "item_title": str(item.get("item_title") or "").strip(),
            "comment_type": str(item.get("comment_type") or "").strip().upper(),
            "promotion_id": str(item.get("promotion_id") or "").strip(),
            "material_id": str(item.get("material_id") or "").strip(),
            "item_id": str(item.get("item_id") or "").strip(),
            "raw_json": cls._json_text(item if isinstance(item, dict) else {}),
            "fetched_at": str(fetched_at or "").strip(),
            "updated_at": str(fetched_at or "").strip(),
        }

