    def _material_performance_page_payload(
        self,
        *,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        all_customer_centers: bool = False,
        page: int = 1,
        page_size: int = 0,
        sort_key: str = "",
        sort_dir: str = "desc",
        search: str = "",
        force_refresh: bool = False,
        material_name_keywords: list[str] | None = None,
        cache_key_suffix: str = "",
        require_nonzero_metrics: bool = False,
    ) -> dict[str, Any]:
        normalized = str(range_key or "day").strip().lower()
        if normalized not in MATERIAL_RANGES:
            raise ValueError("range must be one of day/yesterday/week/month/all/custom")

        config = self.read_config()
        tz_name = str(config.get("timezone") or TIMEZONE)
        if normalized == "custom":
            start_dt, end_dt, range_label = build_material_custom_window(start_date, end_date, tz_name)
        elif normalized == "all":
            start_dt, end_dt, range_label = build_all_material_window(tz_name)
        else:
            start_dt, end_dt, range_label = build_performance_window(normalized, tz_name)

        normalized_page = self._query_page_value(page)
        normalized_page_size = self._query_page_size_value(page_size, 20)
        sort_sql, normalized_sort_key, normalized_sort_dir = self._material_performance_sort_sql(sort_key, sort_dir)
        search_text = self._query_text(search)
        material_keywords = [
            str(item or "").strip()
            for item in list(material_name_keywords or [])
            if str(item or "").strip()
        ]
        material_name_patterns = [self._sql_like_pattern(item) for item in material_keywords]
        cache_customer_center_id = "__all_customer_centers__" if all_customer_centers else self._current_customer_center_id()
        base_cache_key = build_material_cache_key(
            normalized,
            start_date,
            end_date,
            "",
            allowed_advertiser_ids,
            cache_customer_center_id,
            MATERIAL_VIEW_PERFORMANCE,
        )
        if cache_key_suffix:
            base_cache_key = f"{base_cache_key}:{cache_key_suffix}"
        cache_scope = material_cache_scope_for_range(normalized, snapshot_time="")
        cache_namespace = f"{build_material_cache_namespace(MATERIAL_VIEW_PERFORMANCE, scope=cache_scope)}:page"
        cache_version = self._shared_cache_version(cache_namespace)
        fresh_ttl, stale_ttl = material_cache_ttls_for_scope(cache_scope)
        if cache_scope == MATERIAL_CACHE_SCOPE_HISTORY:
            fresh_ttl = max(fresh_ttl, 3600)
            stale_ttl = max(stale_ttl, 21600)
        query_cache_key = (
            f"{base_cache_key}:sql-metric-page:"
            f"{normalized_page}:{normalized_page_size}:{normalized_sort_key}:{normalized_sort_dir}:"
            f"{hashlib.sha1(search_text.encode('utf-8')).hexdigest()[:16]}"
        )

        def build_payload() -> dict[str, Any]:
            tz = ZoneInfo(str(tz_name or TIMEZONE))
            today_key = datetime.now(tz).strftime("%Y-%m-%d")
            start_day = start_dt.astimezone(tz).strftime("%Y-%m-%d")
            end_day = end_dt.astimezone(tz).strftime("%Y-%m-%d")
            allowed = (
                None
                if allowed_advertiser_ids is None
                else sorted(int(item) for item in allowed_advertiser_ids if int(item or 0) > 0)
            )

            def empty_payload() -> dict[str, Any]:
                payload = {
                    "snapshot_time": "",
                    "snapshot_count": 0,
                    "items": [],
                    "meta": {
                        "snapshot_time": "",
                        "status": "ok",
                        "plan_count": 0,
                        "detail_count": 0,
                        "product_count": 0,
                        "material_count": 0,
                        "video_count": 0,
                        "error_count": 0,
                        "snapshot_dates": [],
                        "snapshot_fallback_used": False,
                    },
                    "range_key": normalized,
                    "range_label": range_label,
                    "material_mode": MATERIAL_VIEW_PERFORMANCE,
                    "query_start_date": start_day,
                    "query_end_date": end_day,
                    "pagination": {
                        "page": 1,
                        "page_size": normalized_page_size,
                        "total_count": 0,
                        "total_pages": 1,
                        "start_index": 0,
                        "end_index": 0,
                        "sort_key": normalized_sort_key,
                        "sort_dir": normalized_sort_dir,
                        "search": str(search or "").strip(),
                    },
                    "materials_aggregate": None,
                    "metrics_semantics": {
                        "money_scope": "material_reuse_aggregation",
                        "reconcilable_to_account_summary": False,
                        "notice": "当前素材表现金额为素材复用聚合口径，同一素材复用于多个计划或账户时会重复累计，不直接与账户总消耗核平。",
                    },
                    "materialTodayStatus": self._material_today_hot_status(
                        all_customer_centers=all_customer_centers,
                    ),
                }
                payload.update(
                    self._history_backfill_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind="material",
                        all_customer_centers=all_customer_centers,
                    )
                )
                payload.update(
                    self._history_correction_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind="material",
                        all_customer_centers=all_customer_centers,
                    )
                )
                return self._attach_freshness(
                    payload,
                    data_time="",
                    synced_at="",
                    source="material_current_daily",
                    partial=False,
                )

            if allowed_advertiser_ids is not None and not allowed:
                return empty_payload()

            source_queries: list[str] = []
            source_params: list[Any] = []
            daily_end_day = min(
                end_day,
                (datetime.strptime(today_key, "%Y-%m-%d").date() - timedelta(days=1)).strftime("%Y-%m-%d"),
            )
            if start_day <= daily_end_day:
                daily_where = ["md.biz_date >= ?", "md.biz_date <= ?"]
                source_params.extend([start_day, daily_end_day])
                daily_where.append(
                    self._material_history_stable_day_sql(
                        day_expr="md.biz_date",
                        customer_center_expr="md.customer_center_id",
                    )
                )
                if all_customer_centers:
                    daily_where.append("COALESCE(md.customer_center_id, '') <> ''")
                else:
                    daily_where.append("md.customer_center_id = ?")
                    source_params.append(self._current_customer_center_id())
                if allowed:
                    daily_where.append(
                        f"""
                        EXISTS (
                            SELECT 1
                            FROM jsonb_array_elements_text(COALESCE(NULLIF(md.advertiser_ids_json, ''), '[]')::jsonb) AS adv(value)
                            WHERE CAST(adv.value AS BIGINT) IN ({','.join('?' for _ in allowed)})
                        )
                        """
                    )
                    source_params.extend(allowed)
                if require_nonzero_metrics:
                    daily_where.append(self._material_performance_nonzero_sql("md"))
                if material_name_patterns:
                    daily_where.append(
                        "(" + " OR ".join(["LOWER(COALESCE(md.material_name, '')) LIKE ? ESCAPE '\\'" for _ in material_name_patterns]) + ")"
                    )
                    source_params.extend(material_name_patterns)
                source_queries.append(
                    f"""
                    SELECT
                        md.customer_center_id,
                        md.snapshot_time,
                        md.biz_date AS source_day,
                        md.window_start,
                        md.window_end,
                        md.material_key,
                        md.material_id,
                        md.material_name,
                        md.create_time,
                        md.material_type,
                        md.video_id,
                        md.cover_url,
                        md.aweme_item_id,
                        md.video_url,
                        md.stat_cost,
                        md.pay_amount,
                        md.total_pay_amount,
                        md.settled_pay_amount,
                        md.order_count,
                        md.settled_order_count,
                        md.plan_count,
                        md.advertiser_count,
                        md.plan_ids_json,
                        md.advertiser_ids_json,
                        md.is_original,
                        md.top_plan_name,
                        md.top_account_name,
                        md.top_anchor_name,
                        md.product_info_text,
                        md.product_names_json,
                        md.overall_show_count,
                        md.overall_click_count,
                        md.overall_ctr,
                        md.roi,
                        md.settled_roi,
                        md.pay_order_cost,
                        md.settled_amount_rate,
                        md.refund_amount_1h,
                        md.refund_rate_1h
                    FROM material_daily md
                    WHERE {' AND '.join(daily_where)}
                    """
                )
            if end_day >= today_key:
                current_where: list[str] = []
                if all_customer_centers:
                    current_where.append("COALESCE(mc.customer_center_id, '') <> ''")
                else:
                    current_where.append("mc.customer_center_id = ?")
                    source_params.append(self._current_customer_center_id())
                if allowed:
                    current_where.append(
                        f"""
                        EXISTS (
                            SELECT 1
                            FROM jsonb_array_elements_text(COALESCE(NULLIF(mc.advertiser_ids_json, ''), '[]')::jsonb) AS adv(value)
                            WHERE CAST(adv.value AS BIGINT) IN ({','.join('?' for _ in allowed)})
                        )
                        """
                    )
                    source_params.extend(allowed)
                if require_nonzero_metrics:
                    current_where.append(self._material_performance_nonzero_sql("mc"))
                if material_name_patterns:
                    current_where.append(
                        "(" + " OR ".join(["LOWER(COALESCE(mc.material_name, '')) LIKE ? ESCAPE '\\'" for _ in material_name_patterns]) + ")"
                    )
                    source_params.extend(material_name_patterns)
                source_queries.append(
                    f"""
                    SELECT
                        mc.customer_center_id,
                        mc.snapshot_time,
                        substr(mc.snapshot_time, 1, 10) AS source_day,
                        mc.window_start,
                        mc.window_end,
                        mc.material_key,
                        mc.material_id,
                        mc.material_name,
                        mc.create_time,
                        mc.material_type,
                        mc.video_id,
                        mc.cover_url,
                        mc.aweme_item_id,
                        mc.video_url,
                        mc.stat_cost,
                        mc.pay_amount,
                        mc.total_pay_amount,
                        mc.settled_pay_amount,
                        mc.order_count,
                        mc.settled_order_count,
                        mc.plan_count,
                        mc.advertiser_count,
                        mc.plan_ids_json,
                        mc.advertiser_ids_json,
                        mc.is_original,
                        mc.top_plan_name,
                        mc.top_account_name,
                        mc.top_anchor_name,
                        mc.product_info_text,
                        mc.product_names_json,
                        mc.overall_show_count,
                        mc.overall_click_count,
                        mc.overall_ctr,
                        mc.roi,
                        mc.settled_roi,
                        mc.pay_order_cost,
                        mc.settled_amount_rate,
                        mc.refund_amount_1h,
                        mc.refund_rate_1h
                    FROM material_current mc
                    WHERE {' AND '.join(current_where) if current_where else '1 = 1'}
                    """
                )

            if not source_queries:
                return empty_payload()

            index_range_key = material_ranking_index.index_range_key(normalized, start_day, end_day)
            can_use_ranking_index = (
                bool(index_range_key)
                and allowed_advertiser_ids is None
                and not search_text
                and not material_name_patterns
                and not require_nonzero_metrics
                and normalized_sort_key in material_ranking_index.SORT_KEYS
            )
            if can_use_ranking_index:
                with self.db() as index_conn:
                    indexed_payload = material_ranking_index.payload_from_index(
                        self,
                        index_conn,
                        source_queries=source_queries,
                        source_params=source_params,
                        scope_key_value=material_ranking_index.scope_key(
                            self,
                            all_customer_centers=all_customer_centers,
                        ),
                        index_range_key_value=index_range_key,
                        start_day=start_day,
                        end_day=end_day,
                        normalized=normalized,
                        range_label=range_label,
                        start_dt=start_dt,
                        end_dt=end_dt,
                        tz_name=tz_name,
                        page=normalized_page,
                        page_size=normalized_page_size,
                        sort_key=normalized_sort_key,
                        sort_dir=normalized_sort_dir,
                        all_customer_centers=all_customer_centers,
                    )
                if indexed_payload is not None:
                    return indexed_payload

            escaped_search = search_text.replace("\\", "\\\\").replace("%", "\\%").replace("_", "\\_")
            search_like = f"%{escaped_search}%"
            search_params = [search_like] * 10 if search_text else []
            search_source_filter = ""
            aggregated_source_filter = ""
            if search_text:
                search_source_filter = """
                WHERE (
                    LOWER(COALESCE(source.material_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.material_id, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.video_id, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.product_info_text, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.top_anchor_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.top_plan_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.top_account_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.material_key, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.aweme_item_id, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.material_type, '')) LIKE ? ESCAPE '\\'
                )
                """
                aggregated_source_filter = "WHERE source.material_key IN (SELECT material_key FROM matching_materials)"

            page_sql = f"""
            WITH source AS (
                {' UNION ALL '.join(source_queries)}
            ),
            matching_materials AS (
                SELECT DISTINCT source.material_key
                FROM source
                {search_source_filter}
            ),
            material_plan_ids AS (
                SELECT DISTINCT source.material_key, CAST(plan_item.value AS BIGINT) AS plan_id
                FROM source
                {"INNER JOIN matching_materials mm ON mm.material_key = source.material_key" if search_text else ""}
                CROSS JOIN LATERAL jsonb_array_elements_text(COALESCE(NULLIF(source.plan_ids_json, ''), '[]')::jsonb) AS plan_item(value)
            ),
            material_advertiser_ids AS (
                SELECT DISTINCT source.material_key, CAST(adv_item.value AS BIGINT) AS advertiser_id
                FROM source
                {"INNER JOIN matching_materials mm ON mm.material_key = source.material_key" if search_text else ""}
                CROSS JOIN LATERAL jsonb_array_elements_text(COALESCE(NULLIF(source.advertiser_ids_json, ''), '[]')::jsonb) AS adv_item(value)
            ),
            aggregated AS (
                SELECT
                    source.material_key,
                    COALESCE(MAX(NULLIF(source.material_name, '')), '') AS material_name,
                    COALESCE(MIN(NULLIF(source.create_time, '')), '') AS create_time,
                    COALESCE(MAX(NULLIF(source.top_account_name, '')), '') AS top_account_name,
                    COALESCE(MAX(NULLIF(source.top_plan_name, '')), '') AS top_plan_name,
                    COALESCE(MAX(NULLIF(source.top_anchor_name, '')), '') AS top_anchor_name,
                    MAX(source.snapshot_time) AS snapshot_time,
                    CAST(ROUND(COALESCE(SUM(source.stat_cost), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                    CAST(ROUND(COALESCE(SUM(source.pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                    CAST(ROUND(COALESCE(SUM(source.total_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                    CAST(ROUND(COALESCE(SUM(source.settled_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                    CAST(COALESCE(SUM(source.order_count), 0) AS INTEGER) AS order_count,
                    CAST(COALESCE(SUM(source.settled_order_count), 0) AS INTEGER) AS settled_order_count,
                    CAST(COALESCE(SUM(source.overall_show_count), 0) AS INTEGER) AS overall_show_count,
                    CAST(COALESCE(SUM(source.overall_click_count), 0) AS INTEGER) AS overall_click_count,
                    CAST(ROUND(COALESCE(SUM(source.refund_amount_1h), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS refund_amount_1h,
                    CAST(COALESCE((SELECT COUNT(DISTINCT mpi.plan_id) FROM material_plan_ids mpi WHERE mpi.material_key = source.material_key), 0) AS INTEGER) AS plan_count,
                    CAST(COALESCE((SELECT COUNT(DISTINCT mai.advertiser_id) FROM material_advertiser_ids mai WHERE mai.material_key = source.material_key), 0) AS INTEGER) AS advertiser_count,
                    CAST(ROUND(COALESCE(
                        (COALESCE(SUM(source.overall_click_count), 0)::numeric / NULLIF(COALESCE(SUM(source.overall_show_count), 0)::numeric, 0)) * 100,
                        0
                    ), 2) AS DOUBLE PRECISION) AS overall_ctr,
                    CAST(ROUND(COALESCE(
                        COALESCE(SUM(source.pay_amount), 0.0)::numeric / NULLIF(COALESCE(SUM(source.stat_cost), 0.0)::numeric, 0),
                        0
                    ), 2) AS DOUBLE PRECISION) AS roi,
                    CAST(ROUND(COALESCE(
                        COALESCE(SUM(source.settled_pay_amount), 0.0)::numeric / NULLIF(COALESCE(SUM(source.stat_cost), 0.0)::numeric, 0),
                        0
                    ), 2) AS DOUBLE PRECISION) AS settled_roi,
                    CAST(ROUND(COALESCE(
                        COALESCE(SUM(source.stat_cost), 0.0)::numeric / NULLIF(COALESCE(SUM(source.order_count), 0)::numeric, 0),
                        0
                    ), 2) AS DOUBLE PRECISION) AS pay_order_cost,
                    CAST(ROUND(COALESCE(
                        (COALESCE(SUM(source.settled_pay_amount), 0.0)::numeric / NULLIF(COALESCE(SUM(source.total_pay_amount), 0.0)::numeric, 0)) * 100,
                        0
                    ), 2) AS DOUBLE PRECISION) AS settled_amount_rate,
                    CAST(ROUND(COALESCE(
                        (COALESCE(SUM(source.refund_amount_1h), 0.0)::numeric / NULLIF(COALESCE(SUM(source.total_pay_amount), 0.0)::numeric, 0)) * 100,
                        0
                    ), 2) AS DOUBLE PRECISION) AS refund_rate_1h
                FROM source
                {aggregated_source_filter}
                GROUP BY source.material_key
            ),
            summary AS (
                SELECT
                    COUNT(*) AS total_count,
                    CAST(ROUND(COALESCE(SUM(stat_cost), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_stat_cost,
                    CAST(ROUND(COALESCE(SUM(pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_pay_amount,
                    CAST(ROUND(COALESCE(SUM(total_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_total_pay_amount,
                    CAST(ROUND(COALESCE(SUM(settled_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_settled_pay_amount,
                    CAST(COALESCE(SUM(order_count), 0) AS INTEGER) AS aggregate_order_count,
                    CAST(COALESCE(SUM(settled_order_count), 0) AS INTEGER) AS aggregate_settled_order_count,
                    CAST(COALESCE(SUM(overall_show_count), 0) AS INTEGER) AS aggregate_overall_show_count,
                    CAST(COALESCE(SUM(overall_click_count), 0) AS INTEGER) AS aggregate_overall_click_count,
                    CAST(ROUND(COALESCE(SUM(refund_amount_1h), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_refund_amount_1h,
                    COALESCE((SELECT COUNT(DISTINCT plan_id) FROM material_plan_ids), 0) AS aggregate_plan_count,
                    COALESCE((SELECT COUNT(DISTINCT advertiser_id) FROM material_advertiser_ids), 0) AS aggregate_advertiser_count
                FROM aggregated
            ),
            source_meta AS (
                SELECT
                    COALESCE(MAX(snapshot_time), '') AS latest_snapshot_time,
                    COUNT(DISTINCT snapshot_time) AS snapshot_count,
                    COUNT(DISTINCT customer_center_id) AS customer_center_count
                FROM source
            ),
            paged AS (
                SELECT *
                FROM (
                    SELECT aggregated.material_key, ROW_NUMBER() OVER (ORDER BY {sort_sql}) AS __page_order
                    FROM aggregated
                ) ranked
                WHERE ranked.__page_order > ?
                  AND ranked.__page_order <= ?
            )
            SELECT source_meta.latest_snapshot_time, source_meta.snapshot_count, source_meta.customer_center_count,
                   summary.total_count, summary.aggregate_stat_cost, summary.aggregate_pay_amount,
                   summary.aggregate_total_pay_amount, summary.aggregate_settled_pay_amount,
                   summary.aggregate_order_count, summary.aggregate_settled_order_count,
                   summary.aggregate_overall_show_count, summary.aggregate_overall_click_count,
                   summary.aggregate_refund_amount_1h, summary.aggregate_plan_count, summary.aggregate_advertiser_count,
                   paged.material_key, paged.__page_order
            FROM summary
            LEFT JOIN source_meta ON TRUE
            LEFT JOIN paged ON TRUE
            ORDER BY paged.__page_order NULLS LAST
            """

            def run_performance_page(conn: Any, page_value: int) -> list[dict[str, Any]]:
                start_index = max(page_value - 1, 0) * normalized_page_size
                params = [
                    *source_params,
                    *search_params,
                    start_index,
                    start_index + normalized_page_size,
                ]
                return [dict(row) for row in conn.execute(page_sql, params).fetchall()]

            with self.db() as conn:
                query_rows = run_performance_page(conn, normalized_page)
                summary_row = dict(query_rows[0] or {}) if query_rows else {}
                total_count = int(summary_row.get("total_count", 0) or 0)
                total_pages = max(1, (total_count + normalized_page_size - 1) // normalized_page_size)
                current_page = min(max(1, normalized_page), total_pages)
                if current_page != normalized_page:
                    query_rows = run_performance_page(conn, current_page)
                    summary_row = dict(query_rows[0] or {}) if query_rows else summary_row
                page_material_keys = [
                    str(row.get("material_key") or "").strip()
                    for row in query_rows
                    if str(row.get("material_key") or "").strip()
                ]
                latest_snapshot_time = str(summary_row.get("latest_snapshot_time") or "").strip()
                if page_material_keys:
                    page_source_sql = f"""
                    WITH source AS (
                        {' UNION ALL '.join(source_queries)}
                    )
                    SELECT *
                    FROM source
                    WHERE material_key IN ({','.join('?' for _ in page_material_keys)})
                    """
                    page_source_rows = [
                        dict(row)
                        for row in conn.execute(page_source_sql, [*source_params, *page_material_keys]).fetchall()
                    ]
                    payload = self._build_material_payload_from_rows(
                        conn,
                        page_source_rows,
                        latest_snapshot_time=latest_snapshot_time,
                        all_customer_centers=all_customer_centers,
                        meta_rows=page_source_rows,
                        enrich_snapshot_context=True,
                        query_context_ready=True,
                    )
                    key_order = {key: index for index, key in enumerate(page_material_keys)}
                    items = self._sanitize_material_preview_fields_for_payload(
                        self._apply_latest_material_previews(
                            conn,
                            payload.get("items") or [],
                        )
                    )
                    items = [dict(item or {}) for item in items]
                    items.sort(
                        key=lambda item: key_order.get(
                            str(item.get("material_key") or "").strip(),
                            len(key_order),
                        )
                    )
                    payload["items"] = items
                else:
                    payload = empty_payload()

            total_stat_cost = round(float(summary_row.get("aggregate_stat_cost", 0.0) or 0.0), 2)
            total_pay_amount = round(float(summary_row.get("aggregate_pay_amount", 0.0) or 0.0), 2)
            total_total_pay_amount = round(float(summary_row.get("aggregate_total_pay_amount", 0.0) or 0.0), 2)
            total_settled_pay_amount = round(float(summary_row.get("aggregate_settled_pay_amount", 0.0) or 0.0), 2)
            total_order_count = int(summary_row.get("aggregate_order_count", 0) or 0)
            total_settled_order_count = int(summary_row.get("aggregate_settled_order_count", 0) or 0)
            total_show_count = int(summary_row.get("aggregate_overall_show_count", 0) or 0)
            total_click_count = int(summary_row.get("aggregate_overall_click_count", 0) or 0)
            total_refund_amount_1h = round(float(summary_row.get("aggregate_refund_amount_1h", 0.0) or 0.0), 2)
            total_count = int(summary_row.get("total_count", 0) or 0)
            total_pages = max(1, (total_count + normalized_page_size - 1) // normalized_page_size)
            current_page = min(max(1, normalized_page), total_pages)
            start_index = (current_page - 1) * normalized_page_size
            page_items = list(payload.get("items") or [])
            snapshot_count = int(summary_row.get("snapshot_count", 0) or 0)
            source_customer_center_count = int(summary_row.get("customer_center_count", 0) or 0)

            payload["snapshot_time"] = str(summary_row.get("latest_snapshot_time") or "").strip()
            payload["snapshot_count"] = snapshot_count
            payload["meta"] = self._material_meta_from_rows(
                list(page_items or []),
                payload.get("snapshot_time") or "",
                material_count=total_count,
            )
            if all_customer_centers:
                payload["customer_center_count"] = source_customer_center_count
            payload["range_key"] = normalized
            payload["range_label"] = range_label
            payload["material_mode"] = MATERIAL_VIEW_PERFORMANCE
            payload["query_start_date"] = start_day
            payload["query_end_date"] = end_day
            payload["pagination"] = {
                "page": current_page,
                "page_size": normalized_page_size,
                "total_count": total_count,
                "total_pages": total_pages,
                "start_index": start_index + 1 if total_count > 0 else 0,
                "end_index": start_index + len(page_items),
                "sort_key": normalized_sort_key,
                "sort_dir": normalized_sort_dir,
                "search": "",
            }
            payload["materials_aggregate"] = {
                "material_mode": MATERIAL_VIEW_PERFORMANCE,
                "material_count": total_count,
                "stat_cost": total_stat_cost,
                "pay_amount": total_pay_amount,
                "total_pay_amount": total_total_pay_amount,
                "settled_pay_amount": total_settled_pay_amount,
                "order_count": total_order_count,
                "settled_order_count": total_settled_order_count,
                "overall_show_count": total_show_count,
                "overall_click_count": total_click_count,
                "overall_ctr": round(total_click_count / total_show_count * 100.0, 2) if total_show_count > 0 else 0.0,
                "roi": round(total_pay_amount / total_stat_cost, 2) if total_stat_cost > 0 else 0.0,
                "settled_roi": round(total_settled_pay_amount / total_stat_cost, 2) if total_stat_cost > 0 else 0.0,
                "pay_order_cost": round(total_stat_cost / total_order_count, 2) if total_order_count > 0 else 0.0,
                "settled_amount_rate": round(total_settled_pay_amount / total_total_pay_amount * 100.0, 2) if total_total_pay_amount > 0 else 0.0,
                "refund_amount_1h": total_refund_amount_1h,
                "refund_rate_1h": round(total_refund_amount_1h / total_total_pay_amount * 100.0, 2) if total_total_pay_amount > 0 else 0.0,
                "plan_count": int(summary_row.get("aggregate_plan_count", 0) or 0),
                "advertiser_count": int(summary_row.get("aggregate_advertiser_count", 0) or 0),
                "summary_text": f"共{total_count}条素材",
            }
            payload["metrics_semantics"] = {
                "money_scope": "material_reuse_aggregation",
                "reconcilable_to_account_summary": False,
                "notice": "当前素材表现金额为素材复用聚合口径，同一素材复用于多个计划或账户时会重复累计，不直接与账户总消耗核平。",
            }
            payload["materialTodayStatus"] = self._material_today_hot_status(
                all_customer_centers=all_customer_centers,
            )
            payload.update(
                self._history_backfill_status_for_window(
                    start_dt,
                    end_dt,
                    tz_name=tz_name,
                    kind="material",
                    all_customer_centers=all_customer_centers,
                )
            )
            payload.update(
                self._history_correction_status_for_window(
                    start_dt,
                    end_dt,
                    tz_name=tz_name,
                    kind="material",
                    all_customer_centers=all_customer_centers,
                )
            )
            return self._attach_freshness(
                payload,
                data_time=payload.get("snapshot_time"),
                synced_at=payload.get("snapshot_time"),
                source="material_current_daily",
                partial=False,
            )

        return self._read_payload_cache_swr(
            namespace=cache_namespace,
            cache_store=self._material_query_cache,
            cache_key=self._versioned_cache_key(cache_version, query_cache_key),
            raw_cache_key=query_cache_key,
            cache_version=cache_version,
            force_refresh=force_refresh,
            builder=build_payload,
            fresh_ttl_seconds=max(fresh_ttl, 300),
            stale_ttl_seconds=max(stale_ttl, 900),
        )

    def _material_relation_sort_sql(
        self,
        sort_key: str = "",
        sort_dir: str = "desc",
    ) -> tuple[str, str, str]:
        numeric_sort_map = {
            "overall_ctr": "overall_ctr",
            "stat_cost": "stat_cost",
            "total_pay_amount": "total_pay_amount",
            "settled_pay_amount": "settled_pay_amount",
            "roi": "roi",
            "pay_amount": "pay_amount",
            "order_count": "order_count",
            "seen_count": "seen_count",
            "active_day_count": "active_day_count",
        }
        text_sort_map = {
            "material_name": "LOWER(COALESCE(material_name, ''))",
            "create_time": "LOWER(COALESCE(create_time, ''))",
            "advertiser_name": "LOWER(COALESCE(advertiser_name, ''))",
            "ad_name": "LOWER(COALESCE(ad_name, ''))",
            "top_anchor_name": "LOWER(COALESCE(top_anchor_name, ''))",
            "first_seen_at": "LOWER(COALESCE(first_seen_at, ''))",
            "last_seen_at": "LOWER(COALESCE(last_seen_at, ''))",
        }
        normalized_key = str(sort_key or "").strip()
        if normalized_key not in numeric_sort_map and normalized_key not in text_sort_map:
            normalized_key = "stat_cost"
        normalized_dir = self._query_sort_dir(sort_dir)
        normalized_dir_sql = normalized_dir.upper()
        sort_expr = numeric_sort_map.get(normalized_key) or text_sort_map.get(normalized_key) or "stat_cost"
        return (
            f"{sort_expr} {normalized_dir_sql}, material_row_key {normalized_dir_sql}",
            normalized_key,
            normalized_dir,
        )

    def _material_relation_page_payload(
        self,
        *,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        all_customer_centers: bool = False,
        page: int = 1,
        page_size: int = 0,
        sort_key: str = "",
        sort_dir: str = "desc",
        search: str = "",
        force_refresh: bool = False,
    ) -> dict[str, Any]:
        target_snapshot = str(snapshot_time or "").strip()
        if target_snapshot:
            payload = self._material_rankings_read_model_payload(
                range_key,
                start_date,
                end_date,
                target_snapshot,
                allowed_advertiser_ids,
                MATERIAL_VIEW_RELATION,
                all_customer_centers=all_customer_centers,
                force_refresh=force_refresh,
            )
            return self.paginate_material_payload(
                payload,
                page=page,
                page_size=page_size,
                sort_key=sort_key,
                sort_dir=sort_dir,
                search=search,
                allowed_advertiser_ids=allowed_advertiser_ids,
                force_refresh=force_refresh,
            )

        normalized = str(range_key or "day").strip().lower()
        if normalized not in MATERIAL_RANGES:
            raise ValueError("range must be one of day/yesterday/week/month/all/custom")

        config = self.read_config()
        tz_name = str(config.get("timezone") or TIMEZONE)
        if normalized == "custom":
            start_dt, end_dt, range_label = build_material_custom_window(start_date, end_date, tz_name)
        elif normalized == "all":
            start_dt, end_dt, range_label = build_all_material_window(tz_name)
        else:
            start_dt, end_dt, range_label = build_performance_window(normalized, tz_name)

        normalized_page = self._query_page_value(page)
        normalized_page_size = self._query_page_size_value(page_size, 10)
        cache_customer_center_id = "__all_customer_centers__" if all_customer_centers else self._current_customer_center_id()
        base_cache_key = build_material_cache_key(
            normalized,
            start_date,
            end_date,
            "",
            allowed_advertiser_ids,
            cache_customer_center_id,
            MATERIAL_VIEW_RELATION,
        )
        search_text = self._query_text(search)
        sort_sql, normalized_sort_key, normalized_sort_dir = self._material_relation_sort_sql(sort_key, sort_dir)
        cache_scope = material_cache_scope_for_range(normalized, snapshot_time="")
        cache_namespace = f"{build_material_cache_namespace(MATERIAL_VIEW_RELATION, scope=cache_scope)}:page"
        cache_version = self._shared_cache_version(cache_namespace)
        fresh_ttl, stale_ttl = material_cache_ttls_for_scope(cache_scope)
        if cache_scope == MATERIAL_CACHE_SCOPE_HISTORY:
            fresh_ttl = max(fresh_ttl, 3600)
            stale_ttl = max(stale_ttl, 21600)
        query_cache_key = (
            f"{base_cache_key}:sql-page:"
            f"{normalized_page}:{normalized_page_size}:{normalized_sort_key}:{normalized_sort_dir}:"
            f"{hashlib.sha1(search_text.encode('utf-8')).hexdigest()[:16]}"
        )

        def build_payload() -> dict[str, Any]:
            tz = ZoneInfo(str(tz_name or TIMEZONE))
            today_key = datetime.now(tz).strftime("%Y-%m-%d")
            start_day = start_dt.astimezone(tz).strftime("%Y-%m-%d")
            end_day = end_dt.astimezone(tz).strftime("%Y-%m-%d")
            allowed = None if allowed_advertiser_ids is None else sorted(int(item) for item in allowed_advertiser_ids if int(item or 0))
            if allowed_advertiser_ids is not None and not allowed:
                empty_payload = {
                    "snapshot_time": "",
                    "snapshot_count": 0,
                    "items": [],
                    "meta": {
                        "snapshot_time": "",
                        "status": "ok",
                        "plan_count": 0,
                        "detail_count": 0,
                        "product_count": 0,
                        "material_count": 0,
                        "relation_count": 0,
                        "video_count": 0,
                        "error_count": 0,
                        "snapshot_dates": [],
                        "snapshot_fallback_used": False,
                    },
                    "range_key": normalized,
                    "range_label": range_label,
                    "material_mode": MATERIAL_VIEW_RELATION,
                    "query_start_date": start_day,
                    "query_end_date": end_day,
                    "pagination": {
                        "page": 1,
                        "page_size": normalized_page_size,
                        "total_count": 0,
                        "total_pages": 1,
                        "start_index": 0,
                        "end_index": 0,
                        "sort_key": normalized_sort_key,
                        "sort_dir": normalized_sort_dir,
                        "search": str(search or "").strip(),
                    },
                    "materials_aggregate": self._material_aggregate_row([], material_mode=MATERIAL_VIEW_RELATION),
                    "metrics_semantics": {
                        "money_scope": "material_relation_grain",
                        "reconcilable_to_account_summary": True,
                        "reconcile_requires_relation_grain": True,
                        "notice": "当前按素材 x 账户 x 计划关系逐行展示，可用于核对账户或计划总额；如果再按素材去重汇总，结果会与账户总表不一致。",
                    },
                    "materialTodayStatus": self._material_today_hot_status(
                        all_customer_centers=all_customer_centers,
                    ),
                }
                empty_payload.update(
                    self._history_backfill_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind="material_relation",
                        all_customer_centers=all_customer_centers,
                    )
                )
                empty_payload.update(
                    self._history_correction_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind="material_relation",
                        all_customer_centers=all_customer_centers,
                    )
                )
                return self._attach_freshness(
                    empty_payload,
                    data_time="",
                    synced_at="",
                    source="material_relation_current_daily",
                    partial=False,
                )

            source_queries: list[str] = []
            source_params: list[Any] = []
            daily_end_day = min(
                end_day,
                (datetime.strptime(today_key, "%Y-%m-%d").date() - timedelta(days=1)).strftime("%Y-%m-%d"),
            )
            if start_day <= daily_end_day:
                daily_where = ["mrd.biz_date >= ?", "mrd.biz_date <= ?"]
                source_params.extend([start_day, daily_end_day])
                daily_where.append(
                    self._material_history_stable_day_sql(
                        day_expr="mrd.biz_date",
                        customer_center_expr="mrd.customer_center_id",
                    )
                )
                if all_customer_centers:
                    daily_where.append("COALESCE(mrd.customer_center_id, '') <> ''")
                else:
                    daily_where.append("mrd.customer_center_id = ?")
                    source_params.append(self._current_customer_center_id())
                if allowed:
                    daily_where.append(f"mrd.advertiser_id IN ({','.join('?' for _ in allowed)})")
                    source_params.extend(allowed)
                source_queries.append(
                    f"""
                    SELECT
                        mrd.customer_center_id,
                        mrd.snapshot_time,
                        mrd.biz_date AS source_day,
                        mrd.advertiser_id,
                        mrd.advertiser_name,
                        mrd.ad_id,
                        mrd.ad_name,
                        mrd.material_type,
                        mrd.material_key,
                        mrd.material_id,
                        mrd.material_name,
                        mrd.create_time,
                        mrd.video_id,
                        mrd.cover_url,
                        mrd.aweme_item_id,
                        mrd.video_url,
                        mrd.stat_cost,
                        mrd.pay_amount,
                        mrd.total_pay_amount,
                        mrd.settled_pay_amount,
                        mrd.order_count,
                        mrd.settled_order_count,
                        mrd.overall_show_count,
                        mrd.overall_click_count,
                        mrd.top_anchor_name,
                        mrd.product_info_text,
                        mrd.is_original
                    FROM material_relation_daily mrd
                    WHERE {' AND '.join(daily_where)}
                    """
                )
            if end_day >= today_key:
                current_where: list[str] = []
                if all_customer_centers:
                    current_where.append("COALESCE(mrc.customer_center_id, '') <> ''")
                else:
                    current_where.append("mrc.customer_center_id = ?")
                    source_params.append(self._current_customer_center_id())
                if allowed:
                    current_where.append(f"mrc.advertiser_id IN ({','.join('?' for _ in allowed)})")
                    source_params.extend(allowed)
                source_queries.append(
                    f"""
                    SELECT
                        mrc.customer_center_id,
                        mrc.snapshot_time,
                        substr(mrc.snapshot_time, 1, 10) AS source_day,
                        mrc.advertiser_id,
                        mrc.advertiser_name,
                        mrc.ad_id,
                        mrc.ad_name,
                        mrc.material_type,
                        mrc.material_key,
                        mrc.material_id,
                        mrc.material_name,
                        mrc.create_time,
                        mrc.video_id,
                        mrc.cover_url,
                        mrc.aweme_item_id,
                        mrc.video_url,
                        mrc.stat_cost,
                        mrc.pay_amount,
                        mrc.total_pay_amount,
                        mrc.settled_pay_amount,
                        mrc.order_count,
                        mrc.settled_order_count,
                        mrc.overall_show_count,
                        mrc.overall_click_count,
                        mrc.top_anchor_name,
                        mrc.product_info_text,
                        mrc.is_original
                    FROM material_relation_current mrc
                    WHERE {' AND '.join(current_where) if current_where else '1 = 1'}
                    """
                )

            if not source_queries:
                payload = {
                    "snapshot_time": "",
                    "snapshot_count": 0,
                    "items": [],
                    "meta": {
                        "snapshot_time": "",
                        "status": "ok",
                        "plan_count": 0,
                        "detail_count": 0,
                        "product_count": 0,
                        "material_count": 0,
                        "relation_count": 0,
                        "video_count": 0,
                        "error_count": 0,
                        "snapshot_dates": [],
                        "snapshot_fallback_used": False,
                    },
                    "range_key": normalized,
                    "range_label": range_label,
                    "material_mode": MATERIAL_VIEW_RELATION,
                    "query_start_date": start_day,
                    "query_end_date": end_day,
                    "pagination": {
                        "page": 1,
                        "page_size": normalized_page_size,
                        "total_count": 0,
                        "total_pages": 1,
                        "start_index": 0,
                        "end_index": 0,
                        "sort_key": normalized_sort_key,
                        "sort_dir": normalized_sort_dir,
                        "search": str(search or "").strip(),
                    },
                    "materials_aggregate": self._material_aggregate_row([], material_mode=MATERIAL_VIEW_RELATION),
                    "metrics_semantics": {
                        "money_scope": "material_relation_grain",
                        "reconcilable_to_account_summary": True,
                        "reconcile_requires_relation_grain": True,
                        "notice": "当前按素材 x 账户 x 计划关系逐行展示，可用于核对账户或计划总额；如果再按素材去重汇总，结果会与账户总表不一致。",
                    },
                    "materialTodayStatus": self._material_today_hot_status(
                        all_customer_centers=all_customer_centers,
                    ),
                }
                payload.update(
                    self._history_backfill_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind="material_relation",
                        all_customer_centers=all_customer_centers,
                    )
                )
                payload.update(
                    self._history_correction_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind="material_relation",
                        all_customer_centers=all_customer_centers,
                    )
                )
                return self._attach_freshness(
                    payload,
                    data_time="",
                    synced_at="",
                    source="material_relation_current_daily",
                    partial=False,
                )

            escaped_search = search_text.replace("\\", "\\\\").replace("%", "\\%").replace("_", "\\_")
            search_like = f"%{escaped_search}%"
            search_params = (
                [search_like] * 11
                if search_text
                else []
            )
            search_clause = ""
            if search_text:
                search_clause = """
                WHERE (
                    LOWER(COALESCE(material_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(material_id, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(video_id, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(product_info_text, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(top_anchor_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(advertiser_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(ad_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(first_seen_at, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(last_seen_at, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(material_key, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(aweme_item_id, '')) LIKE ? ESCAPE '\\'
                )
                """
            relation_sql = f"""
            WITH source AS (
                {' UNION ALL '.join(source_queries)}
            ),
            metrics AS (
                SELECT
                    customer_center_id,
                    advertiser_id,
                    ad_id,
                    material_type,
                    material_key,
                    MAX(snapshot_time) AS snapshot_time,
                    CAST(ROUND(SUM(COALESCE(stat_cost, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                    CAST(ROUND(SUM(COALESCE(pay_amount, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                    CAST(ROUND(SUM(COALESCE(total_pay_amount, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                    CAST(ROUND(SUM(COALESCE(settled_pay_amount, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                    CAST(SUM(COALESCE(order_count, 0)) AS INTEGER) AS order_count,
                    CAST(SUM(COALESCE(settled_order_count, 0)) AS INTEGER) AS settled_order_count,
                    CAST(SUM(COALESCE(overall_show_count, 0)) AS INTEGER) AS overall_show_count,
                    CAST(SUM(COALESCE(overall_click_count, 0)) AS INTEGER) AS overall_click_count,
                    COUNT(*) AS active_day_count
                FROM source
                GROUP BY customer_center_id, advertiser_id, ad_id, material_type, material_key
            ),
            filtered AS MATERIALIZED (
                SELECT
                    metrics.customer_center_id,
                    metrics.snapshot_time,
                    latest_row.advertiser_id,
                    COALESCE(NULLIF(latest_row.advertiser_name, ''), '') AS advertiser_name,
                    latest_row.ad_id,
                    COALESCE(NULLIF(latest_row.ad_name, ''), '') AS ad_name,
                    latest_row.material_type,
                    latest_row.material_key,
                    CONCAT_WS(':', metrics.customer_center_id, latest_row.advertiser_id::text, latest_row.ad_id::text, latest_row.material_type, latest_row.material_key) AS material_row_key,
                    COALESCE(NULLIF(mp.material_id, ''), NULLIF(latest_row.material_id, ''), '') AS material_id,
                    COALESCE(NULLIF(mp.material_name, ''), NULLIF(latest_row.material_name, ''), '未命名素材') AS material_name,
                    COALESCE(NULLIF(mp.create_time, ''), NULLIF(latest_row.create_time, ''), '') AS create_time,
                    COALESCE(NULLIF(mp.video_id, ''), NULLIF(latest_row.video_id, ''), '') AS video_id,
                    COALESCE(NULLIF(mp.cover_url, ''), NULLIF(latest_row.cover_url, ''), '') AS cover_url,
                    COALESCE(NULLIF(mp.aweme_item_id, ''), NULLIF(latest_row.aweme_item_id, ''), '') AS aweme_item_id,
                    COALESCE(NULLIF(mp.video_url, ''), NULLIF(latest_row.video_url, ''), '') AS video_url,
                    metrics.stat_cost,
                    metrics.pay_amount,
                    metrics.total_pay_amount,
                    metrics.settled_pay_amount,
                    metrics.order_count,
                    metrics.settled_order_count,
                    metrics.overall_show_count,
                    metrics.overall_click_count,
                    COALESCE(NULLIF(latest_row.product_info_text, ''), NULLIF(mp.product_info_text, ''), '') AS product_info_text,
                    COALESCE(NULLIF(latest_row.top_anchor_name, ''), NULLIF(mp.top_anchor_name, ''), '') AS top_anchor_name,
                    COALESCE(mre.first_seen_at, '') AS first_seen_at,
                    COALESCE(mre.last_seen_at, '') AS last_seen_at,
                    COALESCE(mre.last_snapshot_time, '') AS last_snapshot_time,
                    CAST(COALESCE(mre.seen_count, 0) AS INTEGER) AS seen_count,
                    CAST(COALESCE(mp.is_original, latest_row.is_original, 0) AS INTEGER) AS is_original,
                    CAST(metrics.active_day_count AS INTEGER) AS active_day_count,
                    CAST(
                        CASE
                            WHEN metrics.overall_show_count > 0
                            THEN ROUND(
                                (metrics.overall_click_count::numeric * 100.0::numeric)
                                / NULLIF(metrics.overall_show_count::numeric, 0),
                                2
                            )
                            ELSE 0.0
                        END AS DOUBLE PRECISION
                    ) AS overall_ctr,
                    CAST(
                        CASE
                            WHEN metrics.stat_cost > 0
                            THEN ROUND(
                                metrics.pay_amount::numeric / NULLIF(metrics.stat_cost::numeric, 0),
                                2
                            )
                            ELSE 0.0
                        END AS DOUBLE PRECISION
                    ) AS roi,
                    CAST(
                        CASE
                            WHEN metrics.stat_cost > 0
                            THEN ROUND(
                                metrics.settled_pay_amount::numeric / NULLIF(metrics.stat_cost::numeric, 0),
                                2
                            )
                            ELSE 0.0
                        END AS DOUBLE PRECISION
                    ) AS settled_roi,
                    CAST(
                        CASE
                            WHEN metrics.order_count > 0
                            THEN ROUND(
                                metrics.stat_cost::numeric / NULLIF(metrics.order_count::numeric, 0),
                                2
                            )
                            ELSE 0.0
                        END AS DOUBLE PRECISION
                    ) AS pay_order_cost,
                    CAST(
                        CASE
                            WHEN metrics.total_pay_amount > 0
                            THEN ROUND(
                                (metrics.settled_pay_amount::numeric * 100.0::numeric)
                                / NULLIF(metrics.total_pay_amount::numeric, 0),
                                2
                            )
                            ELSE 0.0
                        END AS DOUBLE PRECISION
                    ) AS settled_amount_rate
                FROM metrics
                INNER JOIN source AS latest_row
                  ON latest_row.customer_center_id = metrics.customer_center_id
                 AND latest_row.advertiser_id = metrics.advertiser_id
                 AND latest_row.ad_id = metrics.ad_id
                 AND latest_row.material_type = metrics.material_type
                 AND latest_row.material_key = metrics.material_key
                 AND latest_row.snapshot_time = metrics.snapshot_time
                LEFT JOIN material_profile mp
                  ON mp.customer_center_id = metrics.customer_center_id
                 AND mp.material_key = metrics.material_key
                LEFT JOIN material_relation_edges mre
                  ON mre.customer_center_id = metrics.customer_center_id
                 AND mre.material_key = metrics.material_key
                 AND mre.advertiser_id = metrics.advertiser_id
                 AND mre.ad_id = metrics.ad_id
                {search_clause}
            ),
            summary AS (
                SELECT
                    COUNT(*) AS total_count,
                    CAST(ROUND(COALESCE(SUM(stat_cost), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_stat_cost,
                    CAST(ROUND(COALESCE(SUM(pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_pay_amount,
                    CAST(ROUND(COALESCE(SUM(total_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_total_pay_amount,
                    CAST(ROUND(COALESCE(SUM(settled_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_settled_pay_amount,
                    CAST(COALESCE(SUM(order_count), 0) AS INTEGER) AS aggregate_order_count,
                    CAST(COALESCE(SUM(settled_order_count), 0) AS INTEGER) AS aggregate_settled_order_count,
                    CAST(COALESCE(SUM(overall_show_count), 0) AS INTEGER) AS aggregate_overall_show_count,
                    CAST(COALESCE(SUM(overall_click_count), 0) AS INTEGER) AS aggregate_overall_click_count,
                    COUNT(DISTINCT advertiser_id) AS aggregate_advertiser_count,
                    COUNT(DISTINCT ad_id) AS aggregate_plan_count,
                    COUNT(DISTINCT customer_center_id) AS aggregate_customer_center_count
                FROM filtered
            ),
            source_meta AS (
                SELECT
                    COALESCE(MAX(snapshot_time), '') AS latest_snapshot_time,
                    COUNT(DISTINCT source_day) AS snapshot_count,
                    COUNT(DISTINCT customer_center_id) AS customer_center_count
                FROM source
            ),
            paged AS (
                SELECT *
                FROM (
                    SELECT
                        filtered.*,
                        ROW_NUMBER() OVER (ORDER BY {sort_sql}) AS __page_order
                    FROM filtered
                ) ranked
                WHERE ranked.__page_order > ?
                  AND ranked.__page_order <= ?
            )
            SELECT
                source_meta.latest_snapshot_time,
                source_meta.snapshot_count,
                source_meta.customer_center_count,
                summary.total_count,
                summary.aggregate_stat_cost,
                summary.aggregate_pay_amount,
                summary.aggregate_total_pay_amount,
                summary.aggregate_settled_pay_amount,
                summary.aggregate_order_count,
                summary.aggregate_settled_order_count,
                summary.aggregate_overall_show_count,
                summary.aggregate_overall_click_count,
                summary.aggregate_advertiser_count,
                summary.aggregate_plan_count,
                summary.aggregate_customer_center_count,
                paged.*
            FROM summary
            LEFT JOIN source_meta ON TRUE
            LEFT JOIN paged ON TRUE
            ORDER BY paged.__page_order NULLS LAST
            """

            def run_relation_page(conn: Any, page_value: int) -> list[dict[str, Any]]:
                start_index = max(page_value - 1, 0) * normalized_page_size
                params = [
                    *source_params,
                    *search_params,
                    start_index,
                    start_index + normalized_page_size,
                ]
                return [dict(row) for row in conn.execute(relation_sql, params).fetchall()]

            with self.db() as conn:
                query_rows = run_relation_page(conn, normalized_page)
                summary_row = dict(query_rows[0] or {}) if query_rows else {}
                total_count = int(summary_row.get("total_count", 0) or 0)
                total_pages = max(1, (total_count + normalized_page_size - 1) // normalized_page_size)
                current_page = min(max(1, normalized_page), total_pages)
                if current_page != normalized_page:
                    query_rows = run_relation_page(conn, current_page)
                    summary_row = dict(query_rows[0] or {}) if query_rows else summary_row
                page_relation_rows = [
                    dict(row)
                    for row in query_rows
                    if str(row.get("material_key") or "").strip()
                ]
                latest_snapshot_time = str(summary_row.get("latest_snapshot_time") or "").strip()
                payload = self._build_material_relation_payload_from_rows(
                    conn,
                    page_relation_rows,
                    latest_snapshot_time=latest_snapshot_time,
                    all_customer_centers=all_customer_centers,
                )
                if page_relation_rows:
                    payload["items"] = self._sanitize_material_preview_fields_for_payload(
                        self._apply_latest_material_previews(
                            conn,
                            payload.get("items") or [],
                        )
                    )

            total_stat_cost = round(float(summary_row.get("aggregate_stat_cost", 0.0) or 0.0), 2)
            total_pay_amount = round(float(summary_row.get("aggregate_pay_amount", 0.0) or 0.0), 2)
            total_total_pay_amount = round(float(summary_row.get("aggregate_total_pay_amount", 0.0) or 0.0), 2)
            total_settled_pay_amount = round(float(summary_row.get("aggregate_settled_pay_amount", 0.0) or 0.0), 2)
            total_order_count = int(summary_row.get("aggregate_order_count", 0) or 0)
            total_settled_order_count = int(summary_row.get("aggregate_settled_order_count", 0) or 0)
            total_show_count = int(summary_row.get("aggregate_overall_show_count", 0) or 0)
            total_click_count = int(summary_row.get("aggregate_overall_click_count", 0) or 0)
            total_count = int(summary_row.get("total_count", 0) or 0)
            total_pages = max(1, (total_count + normalized_page_size - 1) // normalized_page_size)
            current_page = min(max(1, normalized_page), total_pages)
            start_index = (current_page - 1) * normalized_page_size
            page_items = list(payload.get("items") or [])
            snapshot_count = int(summary_row.get("snapshot_count", 0) or 0)
            source_customer_center_count = int(summary_row.get("customer_center_count", 0) or 0)

            payload["snapshot_time"] = str(summary_row.get("latest_snapshot_time") or "").strip()
            payload["snapshot_count"] = snapshot_count
            payload["meta"] = {
                "snapshot_time": payload.get("snapshot_time"),
                "status": "ok",
                "plan_count": 0,
                "detail_count": 0,
                "product_count": 0,
                "material_count": total_count,
                "relation_count": total_count,
                "video_count": 0,
                "error_count": 0,
                "snapshot_dates": [],
                "snapshot_fallback_used": False,
            }
            if all_customer_centers:
                payload["customer_center_count"] = source_customer_center_count
            payload["range_key"] = normalized
            payload["range_label"] = range_label
            payload["material_mode"] = MATERIAL_VIEW_RELATION
            payload["query_start_date"] = start_day
            payload["query_end_date"] = end_day
            payload["pagination"] = {
                "page": current_page,
                "page_size": normalized_page_size,
                "total_count": total_count,
                "total_pages": total_pages,
                "start_index": start_index + 1 if total_count > 0 else 0,
                "end_index": start_index + len(page_items),
                "sort_key": normalized_sort_key,
                "sort_dir": normalized_sort_dir,
                "search": str(search or "").strip(),
            }
            payload["materials_aggregate"] = {
                "material_mode": MATERIAL_VIEW_RELATION,
                "material_count": total_count,
                "stat_cost": total_stat_cost,
                "pay_amount": total_pay_amount,
                "total_pay_amount": total_total_pay_amount,
                "settled_pay_amount": total_settled_pay_amount,
                "order_count": total_order_count,
                "settled_order_count": total_settled_order_count,
                "overall_show_count": total_show_count,
                "overall_click_count": total_click_count,
                "overall_ctr": round(total_click_count / total_show_count * 100.0, 2) if total_show_count > 0 else 0.0,
                "roi": round(total_pay_amount / total_stat_cost, 2) if total_stat_cost > 0 else 0.0,
                "settled_roi": round(total_settled_pay_amount / total_stat_cost, 2) if total_stat_cost > 0 else 0.0,
                "plan_count": int(summary_row.get("aggregate_plan_count", 0) or 0),
                "advertiser_count": int(summary_row.get("aggregate_advertiser_count", 0) or 0),
                "summary_text": f"共 {total_count} 条关系行",
            }
            payload["metrics_semantics"] = {
                "money_scope": "material_relation_grain",
                "reconcilable_to_account_summary": True,
                "reconcile_requires_relation_grain": True,
                "notice": "当前按素材 x 账户 x 计划关系逐行展示，可用于核对账户或计划总额；如果再按素材去重汇总，结果会与账户总表不一致。",
            }
            payload["materialTodayStatus"] = self._material_today_hot_status(
                all_customer_centers=all_customer_centers,
            )
            payload.update(
                self._history_backfill_status_for_window(
                    start_dt,
                    end_dt,
                    tz_name=tz_name,
                    kind="material_relation",
                    all_customer_centers=all_customer_centers,
                )
            )
            payload.update(
                self._history_correction_status_for_window(
                    start_dt,
                    end_dt,
                    tz_name=tz_name,
                    kind="material_relation",
                    all_customer_centers=all_customer_centers,
                )
            )
            return self._attach_freshness(
                payload,
                data_time=payload.get("snapshot_time"),
                synced_at=payload.get("snapshot_time"),
                source="material_relation_current_daily",
                partial=False,
            )

        return self._read_payload_cache_swr(
            namespace=cache_namespace,
            cache_store=self._material_query_cache,
            cache_key=self._versioned_cache_key(cache_version, query_cache_key),
            raw_cache_key=query_cache_key,
            cache_version=cache_version,
            force_refresh=force_refresh,
            builder=build_payload,
            fresh_ttl_seconds=max(fresh_ttl, 300),
            stale_ttl_seconds=max(stale_ttl, 900),
        )

